window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["artifacts"]={"updatedAt":"2026-07-13","count":392,"artifacts":[{"id":"tuyet-hong-lang","name":"Tuyết Hồng Lăng","cn":null,"category":"phi-hanh","categoryLabel":"Pháp khí phi hành","phamCap":"Thượng phẩm pháp khí phi hành","soHuu":["Thanh Hư môn (sở hữu môn phái)"],"trangThai":"đang dùng","blurb":"Pháp khí phi hành của Thanh Hư môn. Khi triển khai hóa thành hồng kiều (cầu vồng đỏ) khảm đầy điểm ngân quang chói mắt, đủ chở cả đoàn hàng chục người bay trên không. Khi thu lại biến thành một món như bằng gấm nhỏ gọn cầm tay.","detail":"Xuất hiện c175: Phù Vân Tử và đoàn Thanh Hư môn đi trên Tuyết Hồng Lăng từ trên cao hạ xuống điểm hẹn cấm địa. Trông như điểm sáng, bên dưới ngân quang chớp động; hạ xuống thành hồng kiều khảm ngân quang. Phù Vân Tử phất tay thu lại thành vật như bằng gấm. Đoàn Hoàng Phong cốc kinh ngạc; quản sự nhắc nhở giải thích.","nguon":["c0175"]},{"id":"thien-nguyet-than-chu","name":"Thiên Nguyệt thần chu","cn":"天月神舟","category":"phi-hanh","categoryLabel":"Pháp khí phi hành","phamCap":"Thượng phẩm pháp khí phi hành","soHuu":["Yểm Nguyệt tông (sở hữu môn phái)"],"trangThai":"dang-co","blurb":"Thuyền phi hành của Yểm Nguyệt tông, dùng chở cả đoàn đệ tử. Chạm trổ vàng bạc tả long họa phượng tinh xảo, phát hào quang trắng; khi triệt tiêu hào quang thu lại gọn. Nguy nga lộng lẫy hơn hẳn Tuyết Hồng Lăng Thanh Hư môn.","detail":"Xuất hiện c178: Nghê Thường tiên tử và đoàn Yểm Nguyệt tông xuất hiện từ xa trên Thiên Nguyệt thần chu. Thuyền chạm trổ vàng bạc tả long họa phượng, hào quang trắng bao phủ. Sau khi hạ cánh, Nghê Thường triệt tiêu hào quang thuyền.","nguon":["c0178","@c0211"],"aliases":["Thiên Nguyệt Thần Châu"]},{"id":"noi-dan-huyet-tuyen-giao","name":"Nội đan Huyết Tuyến Giao","cn":null,"category":"dan-duoc","categoryLabel":"Nội đan linh thú","phamCap":"Nội đan quý hiếm (trợ đột phá)","soHuu":["Phù Vân Tử (mang theo làm vật cược)"],"trangThai":"vật cược ván ba bên","blurb":"Nội đan của yêu thú Huyết Tuyến Giao. Hình cầu trắng được bao phủ bởi những sợi tơ màu máu li ti. Công dụng giúp linh thú đột phá lên tầng mới — loại nguyên liệu quý Lý Sư Tổ từng mai phục hơn 30 năm tại Bàn Long giang vẫn không bắt được. Phù Vân Tử dùng làm vật cược khích tướng thành công.","detail":"Xuất hiện c176: Phù Vân Tử tung ra nội đan Huyết Tuyến Giao — viên cầu trắng phủ tơ máu đỏ — làm mồi nhử. Lý Sư Tổ lộ vẻ mắt sáng lên vì từng theo đuổi vật này hơn 30 năm không thành. Đây là vật cược của Phù Vân Tử cho ván cược ba bên về kết quả Huyết Cấm Thí Luyện.","nguon":["c0176"]},{"id":"vo-hinh-cham","name":"Vô hình châm","cn":null,"category":"phu-bao","categoryLabel":"Phù bảo — ẩn hình công kích","phamCap":"Phù bảo thượng phẩm","soHuu":["Khung tiền bối (tự luyện, dùng làm vật cược)"],"trangThai":"vật cược ván ba bên","blurb":"Ba khối phù bảo do Khung tiền bối tự luyện lúc nhàn rỗi từ Ngũ kim chi tinh, kết hợp độc pháp Vô hình độn pháp. Ẩn hình đả thương người hoàn toàn trong vô hình — ngay cả Nguyên Anh kỳ tu sĩ cũng đau đầu ứng phó. Khung tiền bối dùng làm vật cược vì không có hậu nhân để truyền thừa.","detail":"Xuất hiện c176: Khung tiền bối đề cập 3 phù bảo Vô hình châm tự luyện lúc nhàn rỗi. Vật cược trong ván ba bên (c177): nếu Yểm Nguyệt tông thắng, Lý sư tổ và Phù Vân Tử mỗi người được 1 châm, 1 châm còn lại Khung giữ. Chất liệu: Ngũ kim chi tinh; vận dụng pháp Vô hình độn pháp đặc trưng của Khung.","nguon":["c0176","c0177"]},{"id":"ngan-giap-giac-mang","name":"Ngân Giáp Giác Mãng","cn":null,"category":"linh-thu","categoryLabel":"Linh thú phi hành","phamCap":"Trúc Cơ trung kỳ (linh thú)","soHuu":["Lý Sư Tổ (linh thú)"],"trangThai":"đang dùng","blurb":"Linh thú rắn lớn của Lý Sư Tổ, thân dài hơn 20 trượng, vảy bạc sáng loáng, có sừng đen. Tu vi Trúc Cơ trung kỳ. Dùng làm phương tiện phi hành chở cả đoàn Hoàng Phong cốc từ tông môn tới điểm hẹn cấm địa — 2 ngày bay.","detail":"Xuất hiện c174: Lý Sư Tổ cưỡi Ngân Giáp Giác Mãng dẫn đoàn tới điểm hẹn Kiến Châu trong 2 ngày. Xác nhận c176: Phù Vân Tử đề cập nội đan Huyết Tuyến Giao có thể giúp linh thú đột phá; Lý sư tổ mắt sáng lên — hàm ý Ngân Giáp Giác Mãng là đối tượng muốn giúp đột phá.","nguon":["c0174","c0176"]},{"id":"tui-to-vang","name":"Túi trữ vật bằng tơ vàng","cn":null,"category":"tru-vat","categoryLabel":"Túi trữ vật đặc chế","phamCap":"Thượng phẩm (đặc chế)","soHuu":["Lý Sư Tổ (đặc chế, dùng một lần)"],"trangThai":"đã dùng @c174","blurb":"Túi trữ vật bằng tơ vàng đặc chế, không thể nhận thần thức hay linh lực thẩm tra từ bên ngoài. Mục đích: chứa thượng phẩm pháp khí để bốc thăm công bằng. Từng đệ tử chỉ được thò tay vào bốc, không thể biết trước hay can thiệp bằng thần thức.","detail":"Xuất hiện c174: Lý Sư Tổ rút túi tơ vàng ra bảo đệ tử bốc thăm pháp khí phân công cho chuyến thí luyện. Túi đặc chế ngăn thần thức và linh lực — đảm bảo công bằng tuyệt đối. Mỗi đệ tử thò tay vào bốc một pháp khí thượng phẩm.","nguon":["c0174"]},{"id":"gioi-thuoc","name":"Giới thước","cn":null,"category":"phap-bao-ban-menh","categoryLabel":"Pháp bảo bản mệnh","phamCap":"Pháp bảo bản mệnh Kết Đan kỳ","soHuu":["Lý Sư Tổ"],"trangThai":"đang dùng","blurb":"Pháp bảo bản mệnh của Lý Sư Tổ — hình dạng giới thước (thước kẻ dài), hào quang màu bạc trắng, như có linh tính. Dùng trong trận phá cấm chế Phong nhận đại trận trước cấm địa: đập nát vô số phong nhận liên tục, mở thông đường cho đệ tử vào cấm địa.","detail":"Xuất hiện c179: Lý Sư Tổ xuất pháp bảo bản mệnh cùng 6 tổ sư khác phá Phong nhận đại trận 3-4 canh giờ. Giới thước hào quang bạc như có linh tính, liên tục đập nát phong nhận cho tới khi đại trận phá thông.","nguon":["c0179"]},{"id":"thanh-quan-kiem","name":"Thanh Quân kiếm","cn":null,"category":"phi-kiem","categoryLabel":"Phi kiếm pháp bảo","phamCap":"Thượng phẩm pháp bảo phi kiếm","soHuu":["Phù Vân Tử"],"trangThai":"đang dùng","blurb":"Phi kiếm pháp bảo của Phù Vân Tử, Thanh Hư môn. Đã được luyện nhập khối thiết tinh của Lý Sư Tổ (kết quả ván cược cũ), làm uy lực tăng mạnh đáng kể. Trong trận phá cấm địa, Phù Vân Tử phun ra thanh quang hóa phi kiếm huyễn thành giao long dài vài chục trượng.","detail":"Đề cập c175: Lý sư tổ và Phù Vân Tử bàn về ván cược cũ — Lý sư tổ phải luyện nhập thiết tinh vào Thanh Quân kiếm của Phù Vân Tử, làm uy lực kiếm tăng mạnh. Dùng c179: Phù Vân Tử vỗ ót há miệng phun thanh quang hóa phi kiếm, huyễn thành giao long vài chục trượng tấn công Phong nhận đại trận.","nguon":["c0175","c0179"]},{"id":"han-yen-thao","name":"Hàn yên thảo","cn":null,"category":"linh-thao","categoryLabel":"Kỳ thảo cấm địa","phamCap":"Kỳ thảo quý hiếm (không phải Trúc Cơ đan chủ dược)","soHuu":["mọc tự nhiên tại Ô Long đàm (cấm địa)"],"trangThai":"mọc trong cấm địa","blurb":"Kỳ thảo hiếm trong cấm địa Huyết Cấm, mọc tự nhiên tại bờ Ô Long đàm. Năm lá trắng tuyền tỏa bạch khí, thân nhỏ. Mỗi khoảng hơn mười mấy năm mới xuất hiện một lần ở bờ đầm. Được trọng thưởng nếu mang về — nhưng không phải chủ dược Trúc Cơ đan.","detail":"Xuất hiện c180: Hàn Lập phát hiện Hàn yên thảo trên bờ Ô Long đàm trong cấm địa. Mô tả: 5 lá trắng tuyền tỏa bạch khí. Được nghe nhắc là loại kỳ thảo mỗi hơn mười mấy năm mới xuất hiện ở bờ đầm, giá trị cao, mang về được trọng thưởng. Hàn Lập nén hưng phấn, thầm ghi địa điểm.","nguon":["c0180"]},{"id":"khu-thu-phan","name":"Khu thú phấn","cn":null,"category":"doc-duoc","categoryLabel":"Bột độc — khống chế yêu thú","phamCap":"Đặc sản Linh Thú Sơn","soHuu":["Vu sư huynh và đồng bọn Linh Thú Sơn"],"trangThai":"đã dùng @c180","blurb":"Bột đặc chế của Linh Thú Sơn dùng để khống chế tạm thời yêu thú. Rải xuống nước hoặc môi trường sống của yêu thú, tạm thời vô hiệu hóa ý chí kháng cự. Vu sư huynh dùng Khu thú phấn khống chế đám Hàn băng thiềm tại Ô Long đàm trong kế giết người.","detail":"Xuất hiện c180: Vu sư huynh rải Khu thú phấn xuống Ô Long đàm, khống chế tạm thời đàn Hàn băng thiềm trong đó. Sau đó phối hợp Băng trùy thuật tấn công từ trước, Hàn băng thiềm tấn công từ sau lưng đệ tử Thiên Khuyết Bảo — giết hắn.","nguon":["c0180"]},{"id":"ti-tuyen","name":"Ti tuyến","cn":"","aliases":["Sợi tơ trong suốt"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"khac","blurb":"Sợi tơ kỳ quái trong suốt lấp lóe, dùng làm vũ khí đánh lén cắt đứt cổ đối phương.","detail":"Sợi ti tuyến trong suốt kỳ quái, lấp lóe dưới nắng, quấn trên ngón vô danh của một sư huynh Hoàng Phong cốc. Đây là pháp khí sát thương âm hiểm: vị sư huynh dùng nó đánh lén cắt đứt cổ đệ tử Cự kiếm môn có thực lực cao hơn, dù cuối cùng cả hai đồng quy vu tận.","nguon":["@c0181"]},{"id":"buom-buom-canh-gioi-linh-thu-son","name":"Bươm bướm cảnh giới Linh thú sơn","cn":"","aliases":["Bươm bướm nhiều màu"],"category":"linh-khi","categoryLabel":"Linh trùng khu sử","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Côn trùng biến màu ngụy trang, được thả thành lưới cảnh giới sống trăm trượng.","detail":"Loài bươm bướm nhiều màu có thể biến ảo màu sắc theo cảnh vật, được đệ tử Linh thú sơn bố trí dày đặc trong phạm vi trăm trượng làm lưới cảnh giới sống, phát hiện ngay khi có người tiếp cận. Chúng trời sinh sợ lạnh, gặp nhiệt độ thấp là đông cứng chết, nên không thả được quanh vùng nước lạnh dị chất như Ô long đàm.","nguon":["@c0181"]},{"id":"tui-da-do","name":"Túi da màu đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo chứa đồ","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Túi da màu đỏ hai đệ tử Linh thú sơn dùng thu chứa chiến lợi phẩm.","detail":"Túi da màu đỏ được hai đệ tử Linh thú sơn dùng để thu Hàn băng thiềm sau khi giết đệ tử Thiên khuyết bảo và cướp chiến lợi phẩm tại hiện trường.","nguon":["@c0181"]},{"id":"cu-kiem-cu-kiem-mon","name":"Cự kiếm (Cự kiếm môn)","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":[],"trangThai":"khac","blurb":"Thanh cự kiếm của đệ tử Cự kiếm môn, đâm xuyên đầu sư huynh Hoàng Phong cốc ghim xuống đất.","detail":"Thanh cự kiếm của đệ tử Cự kiếm môn áo đen. Trước khi chết vì bị ti tuyến cắt đứt cổ, người này còn thừa lực đâm một kiếm xuyên qua đầu sư huynh Hoàng Phong cốc, ghim thi thể xuống đất, tạo thành trận tử chiến không người thắng.","nguon":["@c0181"]},{"id":"mac-don-phu","name":"Mộc độn phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc thấp","soHuu":["Thiếu nữ áo trắng (Yểm Nguyệt tông)"],"trangThai":"da-dung","aliases":["Mộc độn thuật phù"],"blurb":"Phù lục Mộc độn thuật trung cấp bậc thấp, hiếm thấy trong tu tiên giới, là lợi khí chạy trốn tốt nhất lúc sinh tử.","detail":"Phù lục trung cấp bậc thấp cực hiếm, người thường coi là bảo vật gia truyền dùng lúc sinh tử. Thiếu nữ áo trắng Yểm Nguyệt tông dùng nó, cả người chìm trong màn lục quang chói mắt rồi biến mất khỏi cấm địa.","nguon":["@c0182"]},{"id":"thuy-trao-phong-ngu","name":"Thủy tráo phòng ngự","cn":"","category":"phap-bao","categoryLabel":"Pháp thuật phòng ngự","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp thuật phòng ngự dạng màn nước Hàn Lập tung ra đầu tiên khi bị phục kích để tự vệ.","detail":"Khi bị hai tu sĩ chặn tại Nhất tuyến thiên, Hàn Lập lập tức tung thủy tráo phòng ngự làm lớp bảo hộ trước khi bày các pháp bảo khác.","nguon":["@c0183"]},{"id":"phi-thien-thuan","name":"Phi thiên thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khiên bay Hàn Lập phóng ra làm lớp phòng ngự khi giao tranh.","detail":"Pháp bảo phòng ngự dạng khiên bay, được Hàn Lập triển khai trong trận một địch hai tại Nhất tuyến thiên.","nguon":["@c0183"]},{"id":"kim-phu-tu-mau-nhan","name":"Kim phù tử mẫu nhận","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí Hàn Lập cầm sẵn trong tay khi đối trận với hai kẻ phục kích.","detail":"Được Hàn Lập cầm sẵn cùng phù Thổ lao thuật khi bày thế phòng ngự tại Nhất tuyến thiên.","nguon":["@c0183"]},{"id":"tho-lao-thuat","name":"Thổ lao thuật","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Phù lục sơ cấp bậc cao","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Phù lục sơ cấp bậc cao; khi ném ra biến thành đạo hoàng quang bao lấy phòng ngự đối phương thành lớp vỏ vàng, giam giữ khiến không nhúc nhích được.","detail":"Hàn Lập bất ngờ ném Thổ lao thuật về phía gã râu quai nón; phù biến thành hoàng quang bao chặt lớp phòng ngự của gã, hình thành lớp vỏ vàng lớn hơn giam hắn không thể đi tới chút nào.","nguon":["@c0183"]},{"id":"dung-linh-phu","name":"Dung linh phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Phù lục bậc cao","soHuu":["Nghiêm (đệ tử Thiên khuyết bảo)","Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"da-dung","blurb":"Phù lục bậc cao dùng đồng thời bởi hai người một khắc trước khi vào cấm địa, tạm liên kết linh khí hai người để cấm chế truyền tới cùng một chỗ; tỉ lệ thành công năm-năm, giá cực đắt.","detail":"Công cụ giúp gã râu quai nón và đệ tử Thiên khuyết bảo tụ tập cùng điểm trong cấm địa để phục kích Hàn Lập. Hai người dùng đồng thời phù này ngay trước khi vào cấm địa; linh khí tạm thời liên kết nên cấm chế truyền hai người tới cùng chỗ, dù tỉ lệ thành công chỉ năm-năm và giá cực đắt.","nguon":["@c0183"]},{"id":"phu-luc-hao-quang-xanh-biec","name":"Phù lục phòng hộ hào quang xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Phù lục phòng ngự","phamCap":"Không rõ","soHuu":["Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"da-dung","blurb":"Phù lục phòng ngự gã râu quai nón dùng giữa đường tiến tới, dựng màn hào quang xanh biếc gia tăng phòng hộ.","detail":"Trên đường tiến tới hạ sát Hàn Lập, gã râu quai nón dùng phù lục này dựng màn hào quang xanh biếc bao quanh mình để tăng phòng hộ.","nguon":["@c0183"]},{"id":"tui-mau-xanh-ga-rau-quai-non","name":"Túi màu xanh","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Gã râu quai nón (tu sĩ Linh thú sơn)"],"trangThai":"dang-co","blurb":"Túi màu xanh gã râu quai nón hạ xuống trước khi ra tay đối phó Hàn Lập.","detail":"Trước khi tiến tới giao chiến, gã râu quai nón hạ túi màu xanh xuống rồi cười nanh ác tiến tới.","nguon":["@c0183"]},{"id":"kim-quang-chuyen","name":"Kim quang chuyên","aliases":["Kim chuyên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù bảo hình chữ nhật kim quang sáng rực, phát linh khí tận trời; khi khởi động hút ba phần pháp lực người dùng rồi phóng ra đè chết địch.","detail":"Vật thể hình chữ nhật kim quang sáng rực, mua từ Vạn bảo các. Khi khởi động, phù bảo liều mạng hút pháp lực trong cơ thể người dùng cuồn cuộn không dứt (bị ví “quỷ hút máu chết người”), sau khi hút ba phần mới dừng và trả quyền khống chế. Phóng ra đón gió lớn lên bằng gian phòng rồi như ngọn núi nhỏ vỗ thẳng xuống, đè thủng hố sâu cả trượng rộng vài chục trượng, phá nát mọi phòng hộ và thổ lao; đã đè chết tên râu quai nón tầng mười ba thành đám bùn.","nguon":["@c0184"]},{"id":"vong-bao-ho-moc-thuoc-tinh","name":"Vòng bảo hộ mộc thuộc tính","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tên râu quai nón (Linh thú sơn)"],"trangThai":"hong","blurb":"Pháp bảo phòng hộ mộc thuộc tính trên người tên râu quai nón, lực phòng hộ kinh người.","detail":"Vòng bảo hộ mộc thuộc tính khiến tên râu quai nón khinh thường màn tấn công của Hàn Lập, nhưng cuối cùng bị Kim quang chuyên phá nát cùng chủ nhân.","nguon":["@c0184"]},{"id":"doi-thiet-bong-den","name":"Đôi thiết bổng đen","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Tên râu quai nón (Linh thú sơn)"],"blurb":"Đôi thiết bổng màu đen tên râu quai nón dùng để công phá màn hào quang thổ lao.","detail":"Tên râu quai nón dùng đôi thiết bổng đen cùng linh thú công phá màn hào quang Thổ lao thuật vây khốn hắn.","nguon":["@c0184"]},{"id":"cu-kiem-mau-bac","name":"Cự kiếm màu bạc","aliases":["Cự kiếm bạc"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Đại hán cự kiếm bạc"],"trangThai":"dang-co","blurb":"Cự kiếm màu bạc của đại hán chân trần, chém thượng phẩm pháp khí và vòng bảo hộ như cắt giấy, chém đứt người thành hai nửa.","detail":"Là món pháp khí duy nhất đại hán chân trần sử dụng. Uy lực áp đảo: chém thượng phẩm pháp khí và vòng bảo hộ như cắt giấy, chém Tiêu Nhị thành hai đoạn. Đại hán không lấy pháp bảo nào khác vì cho rằng chúng làm hắn phân tâm, bất lợi cho tu hành.","nguon":["@c0185"]},{"id":"phi-dao-mau-do-han-thien-nhai","name":"Phi đao màu đỏ","aliases":["Phi đao hồng quang"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Thiên Nhai"],"trangThai":"dang-co","blurb":"Hai thanh phi đao hồng quang của Hàn Thiên Nhai, dùng giết nữ đệ tử Yểm nguyệt tông.","detail":"Hai thanh phi đao màu đỏ tỏa hồng quang, tốc độ nhanh như sấm sét; Hàn Thiên Nhai dùng chúng bất ngờ giết chết nữ đệ tử Yểm nguyệt tông sau khi giả vờ tha.","nguon":["@c0185"]},{"id":"phap-khi-nhu-manh-lua","name":"Pháp khí như mảnh lụa","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nữ đệ tử Yểm nguyệt tông"],"trangThai":"mat","blurb":"Pháp khí phòng ngự như mảnh lụa của nữ đệ tử Yểm nguyệt tông, dùng ngăn hai phi đao hồng quang nhưng dần thất thế.","detail":"Pháp khí phòng ngự có hình như mảnh lụa; nữ đệ tử Yểm nguyệt tông dùng chống hai phi đao hồng quang của Hàn Thiên Nhai nhưng sắp không chống nổi, sau khi nàng thu pháp khí để đổi lấy mạng thì bị giết.","nguon":["@c0185"]},{"id":"guong-nho-che-ngu-phap-khi","name":"Gương nhỏ chế ngự pháp khí (nữ áo trắng)","category":"phap-bao","categoryLabel":"Pháp khí cổ quái","phamCap":"Không rõ","soHuu":["Nữ tử áo trắng (hậu nhân Trưởng lão Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Gương nhỏ cổ quái phóng thanh quang bao lấy pháp khí và pháp thuật đối phương, khiến chúng lơ lửng quần đảo giữa không trung không thể hạ xuống, như bị cấm chế.","detail":"Pháp khí cổ quái của nữ áo trắng, một trong nhiều bảo vật truyền lại từ Trưởng lão Yểm Nguyệt tông. Khi lật ra, gương phóng thanh quang bao lấy sáu thanh kim nhận của Hàn Lập cùng hỏa xà của nữ áo vàng, khiến chúng lơ lửng quần đảo giữa không trung không hạ xuống được. Hạn chế: mỗi lần chỉ chế ngự một vùng, kéo dài nửa khắc rồi phải thu hồi.","nguon":["@c0186"]},{"id":"dai-hoa-cau-phu-luc","name":"Đại hỏa cầu phù lục","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Nữ tử áo trắng (hậu nhân Trưởng lão Yểm Nguyệt tông)"],"trangThai":"da-dung","blurb":"Phù lục hỏa hệ nữ áo trắng dùng đánh nổ tan nửa trên cây cổ thụ nơi Hàn Lập ẩn thân.","detail":"Nữ áo trắng đánh ra một quả Đại hỏa cầu từ phù lục, phá tan nửa trên cây cổ thụ trong nháy mắt thành tro bụi để buộc Hàn Lập lộ diện, nhưng hắn đã kịp né ra sau gốc cây.","nguon":["@c0186"]},{"id":"thanh-tac","name":"Thanh Tác","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thượng phẩm pháp khí của Hàn Lập, sợi roi màu xanh di chuyển như linh xà vô thanh vô tức.","detail":"Pháp khí hình sợi roi màu xanh của Hàn Lập, khi thi triển di chuyển như linh xà, vô thanh vô tức. Hàn Lập dùng nó trói chặt nữ tử áo trắng Yểm nguyệt tông cùng vòng bảo hộ thành một cái kén. Sau đó bị luồng hoàng quang từ phù bảo của Phong Nhạc bắn xuyên qua.","nguon":["@c0187"]},{"id":"ngan-cau-han-lap","name":"Ngân câu","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Pháp khí ngân quang lập lòe của Hàn Lập, bị dịch thể ăn mòn hư hỏng.","detail":"Pháp khí phát ánh ngân quang lập lòe của Hàn Lập. Trong trận đánh với nữ tử áo trắng, ngân câu bị dịch thể màu hồng phun ra từ thủy tinh cầu ăn mòn đến mức đổi màu thủng lỗ chỗ, linh khí không còn, hư hỏng không dùng được nữa.","nguon":["@c0187"]},{"id":"thuy-tinh-cau-mau-hong","name":"Thủy tinh cầu màu hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Nữ tử áo trắng (Yểm nguyệt tông)"],"trangThai":"mat","blurb":"Pháp bảo của nữ tử áo trắng, phun dịch thể màu hồng phấn ăn mòn pháp khí và tạo vòng bảo hộ.","detail":"Pháp bảo hình cầu thủy tinh màu hồng của nữ tử áo trắng Yểm nguyệt tông, lơ lửng trên đầu. Khi kích hoạt bằng thủ ấn, nó phun dịch thể màu hồng phấn tạo vòng bảo hộ rộng cỡ một trượng và ăn mòn pháp khí đối phương. Sau khi nữ tử chết, thủy tinh cầu rơi xuống đất; Hàn Lập phóng hỏa cầu ngăn không cho Phong Nhạc thu lấy.","nguon":["@c0187"]},{"id":"tam-guong-nho-nu-ao-trang","name":"Tấm gương nhỏ","cn":"","category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Nữ tử áo trắng (Yểm nguyệt tông)"],"trangThai":"mat","blurb":"Pháp khí phòng ngự của nữ tử áo trắng, ngăn được kim nhận của Hàn Lập.","detail":"Pháp khí tấm gương nhỏ của nữ tử áo trắng Yểm nguyệt tông, ngăn cản được kim nhận của Hàn Lập khiến nàng tự đắc. Sau khi nữ tử bị Phong Nhạc giết, tấm gương rơi xuống đất; Hàn Lập không cho Phong Nhạc thu lấy.","nguon":["@c0187"]},{"id":"tieu-dao-hoang-quang","name":"Tiểu đao hoàng quang","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo (uy năng pháp bảo)","soHuu":["Phong Nhạc"],"trangThai":"dang-co","blurb":"Phù bảo của Phong Nhạc, tiểu đao cổ quái tỏa hoàng quang, một đòn giết chết nữ tử áo trắng.","detail":"Phù bảo hình tiểu đao cổ quái của Phong Nhạc: chuôi dài cỡ một thước, lưỡi dài ba bốn tấc, thân trong suốt tỏa hoàng quang chói mắt. Khi thi triển, linh khí bạo phát kinh người; một luồng hoàng quang bắn xuyên Thanh Tác, vòng bảo hộ và cả nữ tử áo trắng, giết chết nàng ngay tại chỗ. Hàn Lập xác nhận nó là phù bảo có đầy đủ uy năng của một pháp bảo, giống Kim quang chuyên của hắn.","nguon":["@c0187"]},{"id":"kim-quang-chuyen-han-lap","name":"Kim quang chuyên","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo (uy lực cao)","soHuu":["Hàn Lập"],"trangThai":"Do Hàn Lập nắm giữ; chưa xuất ra trong trận đấu với Phong Nhạc","blurb":"Phù bảo của Hàn Lập với lực phá hoại kinh người nhưng chậm chạp, chỉ phát huy khi vây khốn được đối thủ.","detail":"Phù bảo do Hàn Lập nắm giữ, lực phá hoại vượt xa phi kiếm thông thường: người tu tiên cấp thấp một khi bị trúng thì dù có nhiều pháp khí bảo hộ cũng khó thoát chết. Tuy nhiên nó có nhược điểm rõ ràng — phải hấp thụ một lượng lớn pháp thuật của người sử dụng mới có thể khu sử được, đồng thời tốc độ và độ linh hoạt kém, khó đuổi kịp đối thủ thân pháp nhanh. Vì thế nó chỉ thật sự hữu dụng khi đã trói buộc hoặc vây khốn được địch nhân từ trước, tính chất tương tự Đại ấn của cao thủ Kết đan kỳ Thiên khuyết bảo — uy lực lớn nhưng nặng nề chậm rãi. Trong trận với Phong Nhạc, Hàn Lập từng định xuất nó ra nhưng nhận ra thân pháp đối phương quá nhanh khiến kế đánh lén khó thành."},{"id":"hoang-la-tan","name":"Hoàng La Tán","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Phòng ngự cực cao","soHuu":["Phong Nhạc"],"trangThai":"mat","blurb":"Pháp khí phòng ngự của Phong Nhạc, xuất vòng hào quang màu xanh bao quanh người, lực phòng ngự vượt Phi Thiên Thuẫn.","detail":"Xuất một vòng hào quang màu xanh bao quanh người, lực phòng ngự cực cao khiến kim nhận của Hàn Lập nổ bắn ngược lại; có thể dùng vô số lần nên Phong Nhạc coi trọng hơn cả phù bảo tiểu đao (phù bảo chỉ dùng vài lần thành phế thải). Từ khi được Hoàng La Tán, Phong Nhạc chưa từng bị tu tiên giả cấp thấp làm bị thương.","nguon":["@c0189"]},{"id":"hon-nguyen-chau","name":"Hỗn Nguyên Châu","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Trung phẩm","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Pháp khí tầm thường ai cũng biết, tiểu hồ lô đen phun bảy tám viên cầu đen; Hàn Lập dùng che giấu Thiên Lôi Tử.","detail":"Pháp khí tầm thường được ai cũng biết, chỉ miễn cưỡng xếp trung phẩm; xuất ra từ tiểu hồ lô màu đen, phun bảy tám viên cầu màu đen bay về đối phương. Hàn Lập dùng làm bình phong che giấu Thiên Lôi Tử màu lam.","nguon":["@c0189"]},{"id":"phu-bao-tieu-dao-hoang-mang-phong-nhac","name":"Phù bảo tiểu đao (hoàng mang)","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo","soHuu":["Phong Nhạc"],"trangThai":"mat","blurb":"Tiểu đao màu vàng của Phong Nhạc, nhanh như thiểm điện vây quanh tấn công tìm sơ hở.","detail":"Tiểu đao màu vàng phát hoàng mang, được Phong Nhạc toàn lực chỉ huy vây quanh Hàn Lập tấn công nhanh như thiểm điện; phù bảo chỉ dùng được vài lần rồi thành phế thải nên Phong Nhạc coi trọng kém hơn Hoàng La Tán.","nguon":["@c0189"]},{"id":"dap-van-ngoa","name":"Đạp vân ngoa","aliases":["Đôi giày pháp khí (Ô Ngoa)","Linh ngoa","Ô Ngoa"],"category":"linh-khi","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đôi giày da yêu thú màu đen, nhẹ mềm dẻo dai, mở khóa thân pháp cực tốc; vốn của Phong Nhạc, Hàn Lập chiếm được.","detail":"Giày da đen làm từ da yêu thú, nhẹ mềm dẻo dai, ẩn phát linh khí; sống sót nguyên vẹn dưới Hỏa đạn thuật mà không dấu cháy nên bị nhận ra là pháp khí. Cho phép người mang bước một bước nhỏ liền phiêu ra ngoài một trượng, nhanh hơn Ngự Phong quyết nhiều, tạo nhiều ảo ảnh; kết hợp La Yên bộ và Ngự Phong quyết giúp Hàn Lập hóa gió, thoát khỏi cả Thiên Nhãn thuật chỉ hiện như bóng nhàn nhạt. Đây chính là bí mật thân pháp quỷ dị nhanh như lôi điện của Phong Nhạc; tốc độ này chỉ duy trì thời gian ngắn do thân thể còn miễn cưỡng.","nguon":["@c0190"]},{"id":"phu-bao-tieu-dao-nu-ao-vang","name":"Phù bảo tiểu đao (nữ áo vàng)","aliases":["Phù bảo hình tiểu đao"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù lục của nữ tử áo vàng, sau khi chủ chết khôi phục thành phù bảo hình tiểu đao.","detail":"Vốn là phù lục của nữ tử áo vàng; do chủ đã chết nên khôi phục thành phù bảo hình tiểu đao. Hàn Lập nhặt được cùng gương nhỏ và Thủy tinh cầu.","nguon":["@c0190"]},{"id":"cu-kiem-mau-xanh-mong-de-tu","name":"Cự kiếm màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Mông đệ tử (Hắc y nhân)"],"trangThai":"dang-co","blurb":"Cự kiếm màu xanh của Mông đệ tử Cự Kiếm môn, dùng chống đỡ thế công hỏa lang rồi một kiếm chém chết yêu thú.","detail":"Trong trận diệt Hỏa lang ba mắt ở vùng phía tây khu trung tâm, Mông đệ tử dùng cự kiếm màu xanh gánh đại bộ phận thế công của yêu thú, sau đó một kiếm chém xuống đầu nó kết liễu.","nguon":["@c0191"]},{"id":"phu-luc-mau-lam-bang-truy","name":"Phù lục màu lam (phù Băng Trùy)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nữ đệ tử Yểm Nguyệt tông (Yểm Nguyệt song kiều)"],"trangThai":"da-dung","blurb":"Phù lục màu lam của nữ đệ tử Yểm Nguyệt tông, biến thành mây đen hơn mười trượng và phóng vô số băng trùy phủ dày một vùng cát.","detail":"Nữ đệ tử Yểm Nguyệt tông ném phù lục lam ra sau lưng; nó hóa thành đám mây đen hơn mười trượng, hạ nhiệt vùng trời rồi phóng vô số băng trùy lớn cắm dày đặc, khiến vùng cát trở nên trong suốt nhưng vẫn không lộ mục tiêu ẩn nấp.","nguon":["@c0191"]},{"id":"khan-lua-mau-vang-ham-van-chi","name":"Khăn lụa màu vàng (hoàng cân)","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hạm Vân Chi"],"trangThai":"dang-co","blurb":"Khăn lụa màu vàng có hào quang chớp động mà cô gái áo lục nắm chặt, tựa hồ không phải vật phàm.","detail":"Khi trồi lên khỏi cát với vết thương ở vai, cô gái áo lục Linh Thú sơn nắm chặt trong tay một khăn lụa màu vàng mặt trên hào quang chớp động, dường như là pháp bảo phi phàm nàng liều mạng giữ gìn — có thể là nguyên nhân nàng bị Yểm Nguyệt tông truy sát.","nguon":["@c0191"]},{"id":"hoa-long-thao","name":"Hỏa Long thảo","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":[],"trangThai":"dang-co","blurb":"Kỳ trân dị thảo màu đỏ mọc sau thi thể Hỏa lang ba mắt, mục tiêu ba tu sĩ hợp sức hái và chia đều.","detail":"Mấy gốc cây cỏ nhỏ màu đỏ mọc sau thi thể Hỏa lang ba mắt tại hố đất vùng phía tây khu trung tâm; ba tu sĩ Cự Kiếm môn, Hướng Chi Lễ và Lý đạo trưởng hợp sức diệt yêu để hái và dự định chia đều, dù Mông đệ tử ngầm định trở mặt độc chiếm.","nguon":["@c0191"]},{"id":"hoa-xa-thuat-phu-luc","name":"Hỏa xà thuật (phù lục)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phù lục hỏa hệ, kích phát tạo lửa thiêu đốt mục tiêu.","detail":"Phù lục hỏa hệ Hàn Lập rút ra định kích phát để thiêu chết hai con phi xà trong khu trung tâm thí luyện. Chưa kịp ném thì kẻ địch kêu dừng tay nên hắn chần chừ, một tay vẫn đặt cẩn thận tại túi trữ vật.","nguon":["@c0192"]},{"id":"dai-bang-truy","name":"Đại băng trùy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp bảo băng hệ hình trùy, đâm xuyên vật thể.","detail":"Vật dùng đâm xuyên tứ chi ba tử thi trên bức tường đá gần cửa đồng, đóng đinh họ xếp thành chữ đại như một đòn giết gà dọa khỉ lập uy.","nguon":["@c0192"]},{"id":"nguyet-duong-bao-chau","name":"Nguyệt dương bảo châu","cn":"月阳宝珠","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thất đại phái"],"trangThai":"dang-co","blurb":"Bảo châu do tu sĩ Yểm Nguyệt tông luyện chế, không thể tấn công cũng không phòng ngự, chỉ phóng kỳ quang khắc chế sương mù độc chướng để dễ tiến vào cấm địa.","detail":"Nhờ Nguyệt dương bảo châu khắc chế sương mù, Yểm Nguyệt tông từng độc chiếm thu hoạch cấm địa, luyện nhiều Trúc Cơ đan và vươn lên thành Việt quốc đệ nhất tu tiên phái. Sau khi lục đại phái tìm tới ép, bảo châu trở thành vật chung của thất đại phái, các phái thay phiên nắm giữ và giám sát lẫn nhau khi khu trừ sương mù.","nguon":["@c0194","@c0195"]},{"id":"binh-ngoc-phun-doc-vu","name":"Bình ngọc phun độc vụ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (phụ trợ)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thượng phẩm pháp khí phụ trợ phun ra độc vụ màu xanh biếc mênh mông; uy lực yếu vì người tu tiên có ngũ hành hộ tráo chống được, nhưng Hàn Lập chọn để che mắt địch nhân.","detail":"Một trong ba kiện thượng phẩm pháp khí Hàn Lập chọn ra từ chiến lợi phẩm. Bình ngọc phun ra độc vụ màu xanh biếc mênh mông làm nhiễu loạn và khiến người trúng độc, song thực chất uy lực yếu vì người tu tiên đều có ngũ hành hộ tráo chống lại được. Hàn Lập chọn nó vì độc vụ có thể tạm che mắt địch nhân, làm công cụ nghi binh.","nguon":["@c0195"]},{"id":"phi-dao-thuong-pham-han-lap","name":"Phi đao (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (tấn công)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba kiện thượng phẩm pháp khí tấn công có uy lực lớn nhất Hàn Lập chọn ra từ chiến lợi phẩm.","detail":"Thanh phi đao là một trong ba kiện Hàn Lập chọn từ 11 món thượng phẩm pháp khí thu được, có uy lực tấn công lớn nhất.","nguon":["@c0195"]},{"id":"kim-bat-thuong-pham-han-lap","name":"Kim bạt (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí (tấn công)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba kiện thượng phẩm pháp khí tấn công có uy lực lớn nhất Hàn Lập chọn ra từ chiến lợi phẩm.","detail":"Chiếc kim bạt là một trong ba kiện Hàn Lập chọn từ 11 món thượng phẩm pháp khí thu được, có uy lực tấn công lớn nhất.","nguon":["@c0195"]},{"id":"binh-nho-than-bi-han-lap","name":"Cái bình nhỏ thần bí","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật thần bí của Hàn Lập, ban đêm dùng nuôi dưỡng cây con linh dược giúp chúng trưởng thành nhanh nhiều lần.","detail":"Cái bình nhỏ thần bí là nền tảng cốt lõi trong kế hoạch hái dược của Hàn Lập. Hắn dự tính sau khi hái các cây con linh dược mà người khác coi vô dụng, sẽ dùng bình này ban đêm nuôi dưỡng cho chúng trưởng thành nhiều lần, biến cây con thành linh dược đủ tuổi để luyện Trúc Cơ đan.","nguon":["@c0196"]},{"id":"huyet-tuyen-giao-noi-dan","name":"Huyết Tuyến giao nội đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược / Vật phẩm","phamCap":"Không rõ","soHuu":["Phù Vân Tử"],"trangThai":"dang-co","blurb":"Viên nội đan mà đạo sĩ Thanh Hư Phù Vân Tử đặt cược, rất khó có được, gần như tiêu tốn toàn bộ tiền tài của hắn.","detail":"Viên nội đan của Huyết Tuyến giao được Phù Vân Tử đặt cược trong cuộc đấu thí luyện cấm địa. Loại nội đan này rất khó kiếm, khiến hắn tiêu tốn gần hết tiền tài mới có được, nên khi Khung lão quái nhúng tay đánh cược hắn càng lo lắng được mất.","nguon":["@c0196","@c0211"]},{"id":"tu-hau-hoa","name":"Tử Hầu hoa","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại linh dược sản sinh ở sơn động bí mật; trăm năm trước bị hái sạch, nay chỉ còn cây con — mục tiêu hái dược của Hàn Lập.","detail":"Tử Hầu hoa là thảo dược sinh trưởng ở một sơn động bí mật trong cấm địa núi lửa. Trăm năm trước nơi này đã bị hái, nay chỉ còn cây con chưa trưởng thành mà người khác coi là vô dụng. Hàn Lập nhắm vào những cây con này để nuôi dưỡng thành linh dược đủ tuổi.","nguon":["@c0196"]},{"id":"buom-vang-chung-ngo","name":"Bướm vàng truy tung","cn":"","category":"khac","categoryLabel":"Vật / Pháp khí truy tung","phamCap":"Không rõ","soHuu":["Chung Ngô"],"trangThai":"dang-co","blurb":"Mười mấy con bướm vàng Chung Ngô thả vào rừng núi cấm địa để truy tung Hàn Lập.","detail":"Sau khi Hàn Lập vào cấm địa, Chung Ngô thả ra mười mấy con bướm vàng bay vào rừng núi, dùng để truy tung theo dấu Hàn Lập trước khi thong thả đi theo với ý ám toán.","nguon":["@c0196"]},{"id":"nguyet-quang-thach","name":"Nguyệt Quang thạch","category":"khac","categoryLabel":"Vật chiếu sáng","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên đá to bằng quả trứng gà phát ánh sáng trắng hòa nhã, Hàn Lập dùng soi đường trong động tối.","detail":"Khi hiện ra, Nguyệt Quang thạch phát ánh sáng trắng hòa nhã chiếu rõ khu vực phụ cận. Hàn Lập lấy từ túi trữ vật để soi đường trong bí động tối. Vì ánh sáng biến hắn thành đích ngắm, hắn tạo vòng bảo hộ thổ thuộc tính rồi mới tiếp tục tiến sâu.","nguon":["@c0197"]},{"id":"phi-dao-mau-xanh-han-lap","name":"Phi đao màu xanh","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thanh phi đao xanh sáng chói Hàn Lập điều khiển cắt xúc tu con rết.","detail":"Cuối chương, Hàn Lập khoát tay xuất ra một thanh phi đao màu xanh sáng chói cùng đạo kim quang hình tròn, trực tiếp cắt về phía hai xúc tu thô dài của con rết.","nguon":["@c0197"]},{"id":"luoi-dao-bay-han-lap","name":"Lưỡi dao sắc bén (bẫy)","category":"phap-bao","categoryLabel":"Pháp khí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lưỡi dao cực kỳ sắc Hàn Lập bố trí ẩn trong thông đạo làm cạm bẫy xẻ bụng con rết.","detail":"Hàn Lập bố trí một lưỡi dao cực kỳ sắc bén trong thông đạo. Khi con rết đuổi theo hắn tới nơi, bụng (bộ phận yếu nhất) bị lưỡi dao bất tri bất giác xẻ banh ra, độc huyết đen tuôn ồ ạt, tạo cơ hội cho hắn phản kích.","nguon":["@c0197"]},{"id":"phi-xoa-xanh-chau-tu-vang","name":"Phi xoa xanh và châu tử vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp","soHuu":["Thanh niên áo lam (đệ tử Thiên Khuyết bảo)"],"trangThai":"dang-co","blurb":"Pháp khí đỉnh cấp của thanh niên áo lam Thiên Khuyết bảo, linh quang chói mắt.","detail":"Bộ pháp khí đỉnh cấp gồm phi xoa màu xanh và châu tử màu vàng của thanh niên áo lam, tỏa linh quang chói mắt, dùng để tranh giành linh dược.","nguon":["@c0198"]},{"id":"quai-truong-lao-gia-ao-xanh","name":"Quải trượng (lão giả áo xanh)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Lão giả áo xanh (cầm quải trượng)"],"trangThai":"dang-co","blurb":"Pháp khí của lão giả áo xanh, hóa thành thanh quang cực nhanh chặn đường.","detail":"Cây quải trượng của lão giả áo xanh, khi phóng ra hóa thành thanh quang cực nhanh chặn đường thanh niên áo lam định cướp linh dược.","nguon":["@c0198"]},{"id":"thien-linh-qua","name":"Thiên Linh quả","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại quả linh dược chưa thành thục Hàn Lập dự định tiếp tục hái.","detail":"Thiên Linh quả là loại linh quả chưa thành thục mà Hàn Lập tiếp tục sưu tập tại cấm địa.","nguon":["@c0198"]},{"id":"lac-tran-chau","name":"Lạc Trần châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập","Mã Vân Long"],"trangThai":"dang-co","blurb":"Pháp khí thành danh của Mã Vân Long, nay ở trong tay Hàn Lập. Là bằng chứng khiến đạo sĩ nhận ra và bảo vệ Hàn Lập khỏi bị lão giả họ Lý sát hại.","detail":"Pháp khí thành danh của Mã Vân Long — cường giả Thiên Khuyết bảo. Hiện Hàn Lập cầm giữ, vô tình khiến người khác nhầm hắn có quan hệ lớn với Mã Vân Long, nhờ đó lão giả họ Lý bỏ ý định cướp pháp khí và không dám động vào Hàn Lập.","nguon":["@c0199"]},{"id":"kim-thu-tran-dai-ca","name":"Kim thư","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần đại công tử"],"trangThai":"dang-co","blurb":"Quyển sách kim quang rực rỡ của Trần đại ca, kết hợp Ngân bút tạo uy lực lớn dọa lui đối thủ.","detail":"Pháp khí của Trần đại công tử, hình quyển sách phát ra kim quang rực rỡ. Phối hợp cùng Ngân bút thi triển ngân phù tạo uy lực lớn, khiến thanh niên Hóa Đao ổ chống không nổi phải nhận thua.","nguon":["@c0199"]},{"id":"ngan-but-tran-dai-ca","name":"Ngân bút","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần đại công tử"],"trangThai":"dang-co","blurb":"Cây bút lớn bằng gỗ ngân quang lập lòe của Trần đại ca, dùng thi triển ngân phù.","detail":"Pháp khí của Trần đại công tử, là cây bút lớn bằng gỗ tỏa ngân quang lập lòe. Dùng thi triển ngân phù tạo vô số điểm sáng như sao đầy trời, kết hợp Kim thư tạo uy lực lớn.","nguon":["@c0199"]},{"id":"thanh-giao-ky-luc-gia","name":"Thanh Giao kỳ (Lục gia)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí đỉnh cấp vốn của tiểu tử Lục gia, bị Hàn Lập đoạt. Trần đại ca dùng làm manh mối truy tìm người cứu thất muội.","detail":"Pháp khí đỉnh cấp từng thuộc về tiểu tử Lục gia, đã bị Hàn Lập đoạt. Trần đại công tử biết người cứu thất muội có Thanh Giao kỳ nên lấy đó làm manh mối truy tìm.","nguon":["@c0199"]},{"id":"phi-kiem-lam-vang-tran-thu-muoi","name":"Phi kiếm lam-vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Trần sư muội"],"trangThai":"dang-co","blurb":"Hai kiện phi kiếm một lam một vàng của Trần thất muội.","detail":"Hai kiện phi kiếm, một màu lam một màu vàng, là pháp khí của Trần thất muội — nữ tử thực lực yếu nhất trong phe họ Trần khi tranh linh thảo.","nguon":["@c0199"]},{"id":"phi-xa-mieng-tho-chung-ngo","name":"Phi xà miệng thô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chung Ngô"],"trangThai":"dang-co","blurb":"Phi xà miệng to như cái bát của Chung Ngô, đi kèm bầy ong vàng to lớn.","detail":"Pháp khí của Chung Ngô (Linh Thú sơn), là phi xà có miệng to như cái bát, chiến đấu cùng bầy ong vàng to lớn.","nguon":["@c0199"]},{"id":"trai-do-dai-thu-rung","name":"Trái đỏ trên đại thụ","cn":"","category":"khac","categoryLabel":"Linh quả","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cây đại thụ đỏ như lửa trong rừng rậm mang vài trái đỏ to bằng nắm đấm.","detail":"Trong rừng rậm có cây đại thụ đỏ như lửa, mang vài trái đỏ to bằng nắm đấm; cô gái áo lục điều khiển tiểu điêu trắng đấu quái xà hai đầu bảo vệ nơi này.","nguon":["@c0199"]},{"id":"tieu-dieu-trang-nu-ao-luc","name":"Tiểu điêu trắng","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Cô gái áo lục"],"trangThai":"dang-co","blurb":"Điểu nhỏ màu trắng cô gái áo lục điều khiển gian nan đấu quái xà hai đầu.","detail":"Tiểu điêu màu trắng của cô gái áo lục trong rừng rậm, được điều khiển gian nan đấu với con quái xà hai đầu cạnh cây đại thụ đỏ.","nguon":["@c0199"]},{"id":"vien-hoan-mau-phan-hong","name":"Viên hoàn màu phấn hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo cao cấp","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Viên hoàn to bằng ngón cái từ miệng cô gái áo trắng phun ra, đón gió phồng to bằng cái đầu, phát âm ông ông, chứa linh lực khổng lồ.","detail":"Pháp bảo của Sư tổ Yểm Nguyệt tông. Ban đầu chỉ to bằng ngón cái, khi phun ra đón gió phồng to bằng cái đầu, phát ra âm thanh ông ông, ẩn chứa linh lực khổng lồ. Dùng để dẫn dụ yêu thú đỉnh cấp Bích Thủy ngạc ra khỏi mặt nước, đồng thời ngăn được hơn phân nửa lực công kích của yêu thú, giúp diệt nó mà không tổn thương đệ tử nào.","nguon":["@c0200"]},{"id":"khan-lua-hoang-quang-ham-van-chi","name":"Khăn lụa hoàng quang","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí đỉnh cấp","soHuu":["Hạm Vân Chi"],"trangThai":"dang-co","blurb":"Thủ đoạn phòng hộ duy nhất của cô gái áo lục, lóe hoàng quang nhưng ảm đạm vô sắc, bị cự kiếm bạc áp đảo.","detail":"Pháp khí đỉnh cấp mà cô gái áo lục Linh Thú sơn dùng liều chết chống hán tử Cự Kiếm môn. Khi thi triển lóe hoàng quang song ảm đạm vô sắc, là thủ đoạn phòng hộ duy nhất của nàng, khó khăn chống đỡ cự kiếm màu bạc của đối thủ.","nguon":["@c0200"]},{"id":"liet-duong-hoa","name":"Liệt Dương hoa","cn":"","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Linh dược","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược bên trong thạch điện gần đỉnh núi mà cô gái áo lục đòi hán tử Cự Kiếm môn đưa cho vài hạt.","detail":"Linh dược quý mọc bên trong thạch điện nhỏ gần đỉnh núi trong cấm địa. Cô gái áo lục Linh Thú sơn quyết liều chết đòi hán tử Cự Kiếm môn cho vài hạt, chết cũng không tránh ra.","nguon":["@c0200","@c0203"]},{"id":"kim-nhan","name":"Kim nhận","aliases":["Kim tử nhận","Tử nhận","Mẫu nhận","Bảy tử nhận"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ phi nhận màu vàng của Hàn Lập gồm mẫu nhận điều khiển và bảy tử nhận; được Vũ Si đánh giá là một bộ đỉnh cấp pháp khí.","detail":"Một thanh phi nhận màu vàng bay ra ngăn ngân kiếm cách đầu cô gái áo lục một trượng mà không bị hủy, tạo màn kim quang bảo hộ. Khi giao đấu, Hàn Lập rung mẫu nhận, bảy thanh tử nhận còn lại từ túi trữ vật bay ra biến thành bảy đạo kim mang, quần với cự kiếm màu bạc như bảy con kim xà quấn lấy một con cự mãng. Vũ Si đoán đây là một bộ đỉnh cấp pháp khí và khiêu chiến để đoạt lấy.","nguon":["@c0201"]},{"id":"khan-lua-ham-van-chi","name":"Khăn lụa (pháp khí Hạm Vân Chi)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hạm Vân Chi"],"trangThai":"hong","blurb":"Pháp khí khăn lụa của cô gái áo lục, hóa thành bánh xe để đón kiếm, bị ngân kiếm chém nát thành mảnh nhỏ.","detail":"Khi bị Vũ Si tấn công, cô gái áo lục biến khăn lụa thành bánh xe để chống đỡ, nhưng lập tức bị cự kiếm màu bạc một kiếm chém nát thành những mảnh nhỏ.","nguon":["@c0201"]},{"id":"thanh-ngung-kinh","name":"Thanh Ngưng kính","cn":"","aliases":["Gương nhỏ (nữ nhân nhiều bảo vật)"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đỉnh cấp pháp khí (hộ thân)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thanh Ngưng Kính là pháp khí gương Hàn Lập dùng để cản Nguyệt Nha quang nhận. Nó làm chậm công kích trong khoảnh khắc nhưng bị đánh vỡ làm đôi. (+) Gương nhỏ hộ thân pháp khí của Yểm Nguyệt song kiều, rót linh lực chiếu ánh sáng xanh vây khốn pháp khí địch giữa không trung. [CAN-SOAT-GOP]","detail":"Cái gương nhỏ Hàn Lập đoạt được từ nữ nhân nhiều bảo vật (từ tay Phong Nhạc). Rót linh lực vào, gương chiếu ra ánh sáng xanh, vây khốn ngân kiếm cùng các kim nhận còn lại giữa không trung không thể nhúc nhích. Đại hán chân trần kinh hãi nhận ra đây là Thanh Ngưng kính — hộ thân pháp khí của Yểm Nguyệt song kiều, khiến việc sở hữu nó trở thành họa danh tính có thể chuốc truy sát của Trưởng lão Kết đan kỳ Yểm Nguyệt tông.","nguon":["@c0202","@c0270","@c0383"],"tabs":{}},{"id":"phi-dao-mau-lam-thuong-pham","name":"Phi đao màu lam (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Thượng phẩm pháp khí Hàn Lập bắn về phía đại hán, bị hút vào ngân kiếm nghiền nát.","detail":"Một trong hai thượng phẩm pháp khí Hàn Lập vỗ túi trữ vật lấy ra bắn về phía đại hán chân trần. Vừa tiến vào vùng sáng bạc đã bị cự kiếm màu bạc luân chuyển cuốn vào cơn lốc xoáy nghiền nát.","nguon":["@c0202"]},{"id":"phi-bat-mau-vang-thuong-pham","name":"Phi bạt màu vàng (thượng phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Thượng phẩm pháp khí bắn cùng phi đao, cũng bị lốc xoáy ngân kiếm nghiền nát.","detail":"Cùng phi đao màu lam, Hàn Lập bắn phi bạt màu vàng về phía đại hán. Cả hai kiện vừa tiến vào bên trong đã bị cự kiếm màu bạc cấp tốc luân chuyển cuốn vào cơn lốc xoáy nghiền nát.","nguon":["@c0202"]},{"id":"vong-tran-hoan","name":"Vong Trần hoàn","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Viên thuốc sắc đỏ như lửa Hàn Lập tiện tay tự chế, dùng kết hợp Vô ưu châm pháp để xóa trí nhớ hoàn mỹ.","detail":"Vong Trần hoàn là viên thuốc có sắc đỏ như lửa, trước đây Hàn Lập tiện tay luyện chế. Khi dùng, hắn nhét viên thuốc vào miệng đối phương rồi kết hợp Vô ưu châm pháp để xóa trí nhớ đạt mức hoàn mỹ; tuy có chút nguy hiểm nhưng không gây vấn đề lớn. Trong cấm địa Huyết sắc thí luyện, hắn dùng nó cùng Vô ưu châm pháp để xóa trí nhớ nửa ngày của Hạm Vân Chi.","nguon":["@c0203"]},{"id":"vo-uu-cham-bo-ngan-cham","name":"Vô ưu châm (bộ ngân châm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ ngân châm đựng trong hộp bạc lớn bằng bàn tay, vật Hàn Lập từng dùng châm cứu tại Thất huyền môn.","detail":"Bộ ngân châm được cất trong một hộp bạc lớn bằng bàn tay, là vật Hàn Lập từng dùng để châm cứu trong quãng thời gian ở Thất huyền môn. Đây là dụng cụ để hắn thi triển Vô ưu châm pháp; khi lấy ra, hắn hồi tưởng lại Mặc đại phu, Lịch Phi Vũ cùng cuộc sống quá khứ tại Thải hà sơn và Thần thủ cốc.","nguon":["@c0203"]},{"id":"hop-vang-kim-hap-dam-lay","name":"Hộp vàng (kim hạp)","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Phi phàm (không phải vật phàm)","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc hộp vàng dài chừng một hai trượng lơ lửng trên tiểu đình bạch ngọc giữa đầm lầy, đóng chặt, ngoài có kim quang lưu động — mục tiêu tranh đoạt.","detail":"Ở trung gian thế giới đầm lầy dưới địa đạo có một tiểu đình bạch ngọc, trên không lơ lửng một hộp vàng dài chừng một hai trượng, rộng cỡ nửa trượng, đang đóng chặt, bên ngoài có kim quang lưu động — rõ ràng không phải vật phàm. Nó trở thành tâm điểm tranh đoạt giữa Hàn Lập và đám Yểm Nguyệt tông tiến vào đầm lầy.","nguon":["@c0204"]},{"id":"chu-tuoc-hoan","name":"Chu tước hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Pháp bảo của Nam Cung Uyển, từng có ý dùng để nghiền xương cốt Hàn Lập trả thù sau vụ Huyết Sắc Thí Luyện nhưng cuối cùng buông tha. (+) Pháp bảo hình vòng tròn của cô gái sư tổ Yểm Nguyệt tông, biến lớn như căn phòng, luân chuyển thành lửa đỏ tụ mấy trăm hỏa cầu. [CAN-SOAT-GOP]","detail":"Chu tước hoàn là pháp bảo hình vòng tròn được cô gái sư tổ Yểm Nguyệt tông phun ra, bay lên không trung đầm lầy, biến lớn như căn phòng và luân chuyển thành ngọn lửa đỏ rực tụ thành mấy trăm hỏa cầu to bằng nắm tay, làm nhiệt độ tăng cao. Có thể biến mất rồi hiện thân, chụp giam thân yêu thú Mặc Giao trong lửa đỏ, kết hợp với Hồng viêm thuật để bùng nổ sức mạnh. Việc khu sử được pháp bảo này khiến Hàn Lập nghĩ cô gái phải là Kết đan kỳ.","nguon":["@c0205","@c0711"]},{"id":"cai-hop-vat-can-tim-yem-nguyet-tong","name":"Cái hộp (vật cần tìm)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Cô gái áo trắng (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Vật cô gái sư tổ Yểm Nguyệt tông lẩm bẩm rằng thứ thật sự cần tìm nằm bên trong “cái hộp này”, còn những thứ trước chỉ là rác rưởi.","detail":"Cô gái sư tổ Yểm Nguyệt tông lẩm bẩm rằng vật thật sự cần tìm nằm bên trong “cái hộp này”, còn những thứ trước đây chỉ là rác rưởi — gợi mở mục tiêu thật của Yểm Nguyệt tông tại cấm địa.","nguon":["@c0205"]},{"id":"chu-tuoc-hoan-nam-cung","name":"Chu tước hoàn (pháp bảo viên hoàn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Pháp bảo viên hoàn của Nam Cung sư tổ, có thể phun liệt hỏa, phóng lớn đỡ đòn và vây khốn yêu thú.","detail":"Pháp bảo viên hoàn hình dạng chu tước của Nam Cung sư tổ Yểm Nguyệt tông. Có thể phun liệt hỏa, phóng lớn để đỡ chất lỏng tím của Mặc Giao và vây khốn giữ chặt yêu thú. Là vũ khí duy nhất gây được chút thống khổ cho Mặc Giao sau khi nó tiến hóa bậc hai.","nguon":["@c0206"]},{"id":"kim-ti-phu","name":"Kim ti phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc trung","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Phù lục trung cấp bậc trung hóa thành kim quang rồi phân vô số sợi tơ vàng quấn chặt yêu thú một lúc.","detail":"Nam Cung sư tổ dùng Kim ti phù kích phát thành kim quang, phân ra vô số sợi tơ vàng quấn chặt Mặc Giao. Trong chốc lát đã trói được yêu thú, nhưng chỉ giữ được một lúc trước khi mất hiệu.","nguon":["@c0206"]},{"id":"tieu-ngu-hanh-phu","name":"Tiểu ngũ hành phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp bậc thấp","soHuu":["Triệu sư muội (nữ tử áo trắng)"],"trangThai":"da-dung","blurb":"Phù lục trung cấp bậc thấp dán ở lối vào, phát động Tiểu ngũ hành tu di cấm pháp phong bế thông đạo.","detail":"Triệu sư muội dán Tiểu ngũ hành phù ở lối vào định hại Mặc Giao, nhưng phù phát động cấm pháp phong bế khiến hai bên thông đạo đá ép sát kín mít, vô tình nhốt Nam Cung sư tổ và Hàn Lập bên trong.","nguon":["@c0206"]},{"id":"hoa-linh-thach-nam-cung","name":"Hỏa linh thạch (màu đỏ)","cn":"","category":"linh-khi","categoryLabel":"Linh thạch","phamCap":"Không rõ","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Linh thạch màu đỏ Nam Cung sư tổ dùng để hấp nạp linh khí phục hồi pháp lực.","detail":"Hỏa linh thạch màu đỏ được Nam Cung sư tổ dùng để hấp nạp linh khí phục hồi pháp lực trong lúc chiến đấu với Mặc Giao.","nguon":["@c0206"]},{"id":"cac-phu-luc-trung-cap-nam-cung","name":"Thổ độn phù / Thủy lao phù / Hỏa điểu phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Trung cấp","soHuu":["Nam Cung Uyển"],"trangThai":"da-dung","blurb":"Các phù lục trung cấp khó gặp Nam Cung sư tổ xuất ra tạo hiệu ứng đặc biệt chuyển nguy thành an.","detail":"Nam Cung sư tổ liên tiếp xuất ra nhiều phù lục trung cấp khó gặp gồm Thổ độn phù, Thủy lao phù, Hỏa điểu phù... tạo các hiệu ứng đặc biệt để đối phó Mặc Giao, khiến Hàn Lập âm thầm kiêng dè.","nguon":["@c0206"]},{"id":"hop-vang-lo-lung-bach-ngoc","name":"Hộp vàng (lơ lửng trên bạch ngọc)","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Cái hộp vàng lơ lửng trên bạch ngọc mà Nam Cung sư tổ tiếc nuối, dự định lấy sau.","detail":"Một cái hộp vàng lơ lửng trên khối bạch ngọc trong khu chiến đấu. Nam Cung sư tổ tiếc nuối nhìn nó nhưng đành để lại, dự định sau này hãy tính; báo hiệu bảo vật quan trọng chưa thu được.","nguon":["@c0206"]},{"id":"binh-thuy-tinh-thu-nguyen-than","name":"Bình thủy tinh thu nguyên thần","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cô gái (Sư tổ Yểm Nguyệt tông)"],"trangThai":"dang-co","blurb":"Bình nhỏ của cô gái bắn hắc khí kéo nguyên thần Mặc Giao ra và giam vào.","detail":"Cô gái lấy một bình thủy tinh nhỏ, niệm chú bắn ra mấy cổ hắc khí quấn thân Mặc Giao, kéo hình ảnh Mặc Giao nhỏ màu xanh (nguyên thần) thu vào bình. Cô mặt mày hớn hở cho thấy nguyên thần này rất giá trị.","nguon":["@c0207"]},{"id":"vien-chau-vang-co-gai","name":"Viên châu màu vàng (ám khí cô gái)","category":"khac","categoryLabel":"Ám khí","phamCap":"Không rõ","soHuu":["Cô gái (Sư tổ Yểm Nguyệt tông)"],"trangThai":"da-dung","blurb":"Viên châu vàng cô gái ném nổ thành khói vàng khống chế đầu Mặc Giao.","detail":"Cô gái ném một viên châu màu vàng, nổ tung thành khói vàng bao phủ đầu Mặc Giao, khiến nó ngừng phun dung dịch tím, tạo cơ hội cho kim chuyên hạ xuống.","nguon":["@c0207"]},{"id":"dung-dich-tim-mac-giao","name":"Dung dịch màu tím của Mặc Giao","category":"khac","categoryLabel":"Chất tiết yêu thú","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Độc dịch màu tím Mặc Giao phun ra chặn kim chuyên, Hàn Lập kiêng kị.","detail":"Mặc Giao phun dung dịch màu tím chặn kim quang chuyên khiến nó không hạ xuống được; đây là độc dịch Hàn Lập kiêng kị.","nguon":["@c0207"]},{"id":"vien-cau-do-nghi-giao-dan","name":"Viên cầu màu đỏ (nghi giao đan)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Cầu đỏ mềm nhũn lớn bằng nắm tay moi từ bụng Mặc Giao, tự nổ phun sương hồng.","detail":"Hàn Lập moi từ bụng Mặc Giao ra viên cầu màu đỏ lớn bằng nắm tay. Cô gái nghi không phải nội đan thật vì Mặc Giao mới tiến hóa bậc hai và thuộc tính thủy thì nội đan phải màu lam. Khi cô vuốt nhẹ vài cái, viên cầu tự nổ tung phun ra sương khói màu hồng bao trùm cả hai.","nguon":["@c0207"]},{"id":"tai-lieu-than-mac-giao","name":"Tài liệu thân Mặc Giao","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cao cấp","soHuu":[],"trangThai":"dang-co","blurb":"Toàn thân Mặc Giao là tài liệu trân quý: da, sừng-móng, đan dịch.","detail":"Cô gái giải thích Mặc Giao tuy mới tiến hóa bậc hai nhưng toàn thân là tài liệu quý: da có thể luyện hộ giáp, sừng-móng luyện đỉnh cấp pháp khí, đan dịch luyện đan dược. Đáng tiếc chưa tiến hóa bậc ba nên không có nội giao đan.","nguon":["@c0207"]},{"id":"tui-dam-nang-thoi-tinh-mac-giao","name":"Túi dâm nang (thôi tình khí của Mặc Giao)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Mặc Giao"],"trangThai":"da-dung","blurb":"Túi chứa thôi tình vụ khí của Mặc Giao, chạm vào lập tức nổ tung.","detail":"Túi dâm nang của Mặc Giao, con súc sinh này thực ra là Hùng Giao hiếm thấy. Túi chứa thôi tình vụ khí, giống cái tiếp xúc sẽ lập tức nổ tung; thành phần mê dược trong đó rất ít, gây hôn mê cỡ năm sáu canh giờ. Chính là viên cầu khiến Hàn Lập và nữ tử hợp hoan; nữ tử sơ sẩy chạm phải nên nổ tung.","nguon":["@c0208"]},{"id":"hop-vang-bach-ngoc-dinh","name":"Hộp vàng (bạch ngọc đình)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Nữ tử tuyệt sắc (nữ tu Kết đan kỳ)"],"trangThai":"dang-co","blurb":"Hộp vàng đặt phía trước bên bạch ngọc đình, nữ tử thu vào túi trữ vật.","detail":"Hộp vàng đặt phía trước bên bạch ngọc đình. Nữ tử đòi lấy, Hàn Lập không dám tranh; nàng thu hộp vàng vào túi trữ vật thuận lợi. Công dụng chưa rõ.","nguon":["@c0208"]},{"id":"tui-tru-vat-de-tu-linh-thu-son","name":"Túi trữ vật (của đệ tử Linh thú sơn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Túi trữ vật Hàn Lập đoạt được sau khi giết một đệ tử Linh thú sơn không đầu.","detail":"Sau khi giết một đệ tử Linh thú sơn ngoài cấm địa, Hàn Lập có thêm một túi trữ vật trong tay; hắn liếc qua rồi lắc đầu.","nguon":["@c0209"]},{"id":"huyet-lan-tram-nam","name":"Huyết lan trăm năm","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược trưởng thành trăm năm, đạo sĩ Thanh Hư môn ra ba gốc trong đổ cục.","detail":"Linh dược trưởng thành khoảng trăm năm, được vị trung niên đạo sĩ Thanh Hư môn bày ra ba gốc trong cuộc đổ cục hái thuốc ở cấm địa.","nguon":["@c0210"]},{"id":"thien-linh-qua-linh-duoc","name":"Thiên linh quả (300 năm)","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược ba trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Quả linh dược trưởng thành ba trăm năm, ra hai quả trong đổ cục.","detail":"Linh dược trưởng thành khoảng ba trăm năm, đạo sĩ Thanh Hư môn bày ra hai quả trong cuộc đổ cục.","nguon":["@c0210"]},{"id":"ngoc-tuy-chi","name":"Ngọc tủy chi","category":"dan-duoc","categoryLabel":"Đan dược / Linh dược","phamCap":"Linh dược bốn trăm năm","soHuu":[],"trangThai":"dang-co","blurb":"Loại linh dược trưởng thành bốn trăm năm, ra ba gốc trong đổ cục.","detail":"Linh dược trưởng thành khoảng bốn trăm năm, đạo sĩ Thanh Hư môn bày ra ba gốc trong cuộc đổ cục hái thuốc ở cấm địa.","nguon":["@c0210"]},{"id":"linh-thu-ngui-mui-do-cuc","name":"Linh thú ngửi mùi","category":"khac","categoryLabel":"Kỳ thú","phamCap":"Linh thú kiểm tra","soHuu":[],"trangThai":"dang-co","blurb":"Kỳ thú mỗi phái dẫn theo, trong phạm vi ba trượng ngửi ra bất kỳ linh dược trên trăm năm kể cả trong túi trữ vật.","detail":"Mỗi phái dẫn theo một hai con linh thú này để kiểm tra đệ tử ra khỏi cấm địa; trong phạm vi ba trượng có thể ngửi ra bất kỳ linh dược trên trăm năm dù được cất giấu trong túi trữ vật, khiến đệ tử không thể giấu thu hoạch.","nguon":["@c0210"]},{"id":"thiet-tinh","name":"Thiết tinh","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Lý Sư Tổ"],"trangThai":"dang-co","blurb":"Vật liệu quý mà Lý sư tổ hứa đưa hai khối cho Khung lão quái khi thua cuộc.","detail":"Vật đặt cược khi Lý sư tổ thua cược với Khung lão quái. Lý sư tổ chủ động đáp ứng trong vòng hai mươi năm sẽ cho người đem hai khối thiết tinh tới.","nguon":["@c0211"]},{"id":"ngan-kiem","name":"Ngân kiếm","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Thanh kiếm bạc của đệ tử Cự kiếm môn chân trần trong câu chuyện Hàn Lập bịa ra.","detail":"Xuất hiện trong câu chuyện trai cò tương tranh ngư ông đắc lợi mà Hàn Lập bịa để giải thích việc tìm được linh dược: một đệ tử Cự kiếm môn chân trần cầm ngân kiếm tranh đấu với người mặt đầy sẹo của Thiên khuyết bảo.","nguon":["@c0211"]},{"id":"bich-quang-dao","name":"Bích quang đao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thanh trường đao đỉnh cấp linh quang lấp lóe, Lý Hóa Nguyên tặng Hàn Lập làm lễ gặp mặt khi thu ký danh đệ tử.","detail":"Pháp khí trường đao chất lượng cao, linh quang lấp lóe, được Lý Hóa Nguyên trao cho Hàn Lập như lễ gặp mặt trong nghi thức bái ký danh sư phụ, xem như minh chứng cho danh phận mới của hắn trong Hoàng phong cốc.","nguon":["@c0212"]},{"id":"khoi-loi-cung-thu","name":"Khôi lỗi cung thủ","aliases":["con rối cung thủ"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng phẩm pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Con rối gỗ điêu khắc sống động, mặc thiết giáp cầm trường cung đồng phát ngân quang; cần bí thuật phân thần mới khu sử.","detail":"Con rối bằng gỗ điêu khắc sống động, khoác thiết giáp thiết khôi, tay cầm trường cung đồng phát ánh ngân quang — thuộc thượng phẩm pháp khí. Muốn khu sử phải dùng bí thuật phân thân, rót một tia thần thức vào rối, nên chỉ tu sĩ Trúc cơ kỳ trở lên mới dùng được; Hàn Lập lúc này chưa thử dùng.","nguon":["@c0213"]},{"id":"to-giay-mau-bac","name":"Tờ giấy màu bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiến lợi phẩm từ đại hán Cự kiếm môn; mặt lồi lõm nhiều hoa văn kỳ lạ thần bí, chưa giải được.","detail":"Vật lấy được từ đại hán chân trần của Cự kiếm môn trong cấm địa. Bề mặt lồi lõm với nhiều hoa văn kỳ lạ thần bí; Hàn Lập cân nhắc nửa ngày không hiểu công dụng, đành tạm cất và vừa nghiên cứu vừa chờ dịp giải mã.","nguon":["@c0213"]},{"id":"ngan-kiem-phe-vat","name":"Ngân kiếm phế vật","category":"phap-bao","categoryLabel":"Pháp khí (hỏng)","phamCap":"Phế vật","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Một thanh ngân kiếm phế vật trong số chiến lợi phẩm thu được ở cấm địa.","detail":"Thanh ngân kiếm đã hỏng, nằm trong số thu hoạch của Hàn Lập từ cấm địa cùng linh thạch và tài liệu các loại.","nguon":["@c0213"]},{"id":"chuong-linh-phap-khi","name":"Chuông linh","aliases":["pháp khí linh đang"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí phát tiếng chuông; Hàn Lập dùng để khua tỉnh đại hán ngốc nghếch ở Nhạc lộc điện.","detail":"Một kiện pháp khí dạng chuông linh của Hàn Lập, được hắn dùng để khua đánh thức đại hán đang ngủ gật trong thông đạo Nhạc lộc điện.","nguon":["@c0213"]},{"id":"truc-co-dan-thanh-pham","name":"Trúc cơ đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đan dược mục tiêu Hàn Lập chuẩn bị nhiều năm để luyện chế.","detail":"Đan dược Hàn Lập dồn công chuẩn bị mấy năm để tự luyện chế. Hắn tự nhận là tay mơ nên tính mỗi lần chỉ luyện một viên, chuẩn bị linh dược đủ luyện cả trăm lần để tích lũy kinh nghiệm, lường trước sẽ thất bại nhiều.","nguon":["@c0214"]},{"id":"lenh-tien-mau-tim","name":"Lệnh tiễn màu tím","cn":"","category":"khac","categoryLabel":"Lệnh phù","phamCap":"Không rõ","soHuu":["Đại hán ngốc nghếch (dẫn đường Địa Hỏa Chi Ốc)"],"trangThai":"dang-co","blurb":"Lệnh phù dùng mở cửa vào khu ổ thạch đạo của Địa Hỏa Chi Ốc.","detail":"Vật đại hán dùng bắn tia sáng vào cửa đá nhiều màu để kích hoạt, mở ra thông đạo ổ thạch đen ngòm cao hơn trượng dẫn vào Địa Hỏa Chi Ốc.","nguon":["@c0214"]},{"id":"ngoc-bai-mau-trang-gian-19","name":"Ngọc bài màu trắng (gian mười chín)","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chìa mở và phong bế cửa phòng luyện đan gian mười chín.","detail":"Ngọc bài trắng dùng mở và phong bế cửa đá trắng của phòng luyện đan gian mười chín; đại hán giao Hàn Lập tự giữ. Khi cửa đóng, phòng đoạn tuyệt liên hệ với ngoại giới trừ khi vài tu sĩ Kết đan kỳ hợp lực mới vào được.","nguon":["@c0214"]},{"id":"ho-lo-chua-hoa-tinh","name":"Hồ lô chứa hỏa tinh","cn":"","category":"khac","categoryLabel":"Vật phụ trợ luyện đan","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Hồ lô cỡ nắm tay chứa hỏa tinh, treo trên vách phòng luyện đan.","detail":"Các hồ lô cỡ nắm tay treo trên vách gian mười chín, chứa hỏa tinh dùng gia tăng uy lực địa hỏa khi nhiệt độ chưa đủ, nhưng hiệu lực chỉ kéo dài trong thời gian ngắn.","nguon":["@c0214"]},{"id":"linh-thach-bac-trung-hoa","name":"Linh thạch bậc trung (thuộc tính hỏa)","cn":"","category":"khac","categoryLabel":"Linh thạch","phamCap":"Bậc trung","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Linh thạch hỏa thuộc tính bậc trung, hấp nạp linh khí nhanh hơn nhiều linh thạch bậc thấp.","detail":"Khối linh thạch hỏa thuộc tính bậc trung Hàn Lập đưa cho đại hán để nhờ an bài phòng luyện đan. Theo quy ước một trăm linh thạch bậc thấp mới đổi được một khối bậc trung, nhưng hiếm ai chịu đổi vì bậc trung hấp nạp linh khí nhanh hơn nhiều.","nguon":["@c0214","@c0229"]},{"id":"ich-coc-dan","name":"Ích cốc đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Đan dược chống đói, ăn vào duy trì được khoảng một tháng không cần tiến thực.","detail":"Đan chống đói mà Hàn Lập đổi được một bình từ lão nhân nơi phòng địa hỏa, mượn cớ ra ngoài thu thập thảo dược trăm năm. Nhờ Ích cốc đan hắn duy trì thêm được một tháng để tiếp tục luyện chế Trúc cơ đan không gián đoạn.","nguon":["@c0215"]},{"id":"phe-dan-lam-nhat","name":"Phế đan (vụn màu lam nhạt)","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vụn đan màu lam nhạt còn sót lại từ những lần luyện Trúc cơ đan chưa ngưng thành công.","detail":"Trong những lần luyện đan thất bại, đỉnh còn lại vô số vụn bể nát màu lam nhạt là phế đan chưa ngưng đan. Hàn Lập không vứt bỏ mà cẩn thận thu vào hộp ngọc, dự phòng về sau còn có thể có công dụng khác.","nguon":["@c0215"]},{"id":"phap-khi-han-lap-gia-ngu","name":"Pháp khí (Hàn Lập giá ngự)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp khí bay Hàn Lập cưỡi khi rời Nhạc Lộc điện.","detail":"Pháp khí Hàn Lập giá ngự bay trên trời khi rời Nhạc Lộc điện sau khi trùng quan thành công vào Trúc cơ kỳ.","nguon":["@c0216"]},{"id":"me-tung-ky","name":"Mê tung kỳ","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lá cờ nhỏ cỡ bàn tay vẽ năm đỉnh núi bị sương mù che phủ, dùng để bày Mê tung pháp trận khai mở động phủ.","detail":"Trận kỳ nhỏ cỡ bàn tay, trên vẽ năm đỉnh núi bị sương mù che phủ, tỏa linh khí quỷ dị cổ quái. Chung Linh Đạo giao cho Hàn Lập cùng ngọc giản hướng dẫn để bày Mê tung pháp trận bảo vệ động phủ mới lập.","nguon":["@c0219"]},{"id":"ngoc-diep-trang-danh-sach","name":"Ngọc điệp trắng (danh sách động phủ)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Chung Linh Đạo"],"trangThai":"dang-co","blurb":"Ngọc điệp trắng ghi danh sách đệ tử; Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập để hắn có động phủ danh chính ngôn thuận.","detail":"Danh sách đệ tử được lưu trên ngọc điệp trắng. Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập vào phía dưới cùng để hắn được cấp động phủ một cách danh chính ngôn thuận.","nguon":["@c0219"]},{"id":"ngoc-gian-huong-dan-tran","name":"Ngọc giản hướng dẫn trận pháp","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản chứa thủ pháp bày và thao túng trận, điều chú ý sau Trúc Cơ, và tiến cử loài Song đồng thử.","detail":"Ngọc giản Chung Linh Đạo trao cho Hàn Lập, bên trong ghi thủ pháp bày và thao túng trận pháp, các điều cần chú ý sau khi Trúc Cơ, cùng tiến cử loài yêu thú Song đồng thử — thứ khiến Hàn Lập đổi hướng đến Kỳ lân các.","nguon":["@c0219"]},{"id":"qua-tho-le","name":"Quả thổ lê","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Loại quả vàng Song đồng thử thích ăn nhất, đựng trong túi trắng.","detail":"Quả thổ lê là loại quả màu vàng mà Song đồng thử thích ăn nhất, được nữ đệ tử Kỳ lân các đựng trong túi trắng giao cho Hàn Lập khi cho thuê con thú. Hàn Lập dùng thổ lê để dụ và điều khiển con thú lần theo tìm hang.","nguon":["@c0220"]},{"id":"linh-nhan-chi-vat","name":"Linh nhãn chi vật","aliases":["Linh nhãn chi tuyền","Linh nhãn chi thạch","Linh nhãn chi thụ"],"category":"khac","categoryLabel":"Bảo vật linh khí","phamCap":"Bảo vật quý (chia theo cấp)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật quý sản sinh nơi linh khí nồng đậm, khiến các môn phái tranh đoạt điên cuồng; gồm nhiều loại như thạch, thụ, tuyền.","detail":"Linh nhãn chi vật là bảo vật quý sinh ra ở nơi linh khí nồng đậm, mỗi lần xuất hiện đều gây gió tanh mưa máu vì các môn phái tranh đoạt điên cuồng. Chúng gồm nhiều loại: linh nhãn chi thạch, linh nhãn chi thụ, linh nhãn chi tuyền. Tại Việt quốc chúng sớm đã rơi vào tay thất đại phái; Hoàng Phong Cốc từng có hai khối linh nhãn chi thạch, ba khối linh nhãn chi thụ, bảy linh nhãn chi tuyền và hơn mười linh nhãn chi vật, bị các tu sĩ Kết đan kỳ và lão tổ Nguyên Anh kỳ chia hết. Hàn Lập tình cờ tìm được một linh nhãn chi tuyền nhất cấp nhỏ đến đáng thương ở phụ cận đỉnh núi và dùng nó làm động phủ, giúp tăng tốc tu luyện hơn nửa thành.","nguon":["@c0221"]},{"id":"tran-ky-tran-ban","name":"Trận kỳ / trận bàn","category":"phap-bao","categoryLabel":"Pháp khí bố trận","phamCap":"Pháp khí bố trận","soHuu":["Thiên Tinh Tông"],"trangThai":"dang-co","blurb":"Pháp khí dựa vào để bố trí trận pháp mà không cần tu luyện trận đạo, chỉ cần linh thạch là mua được.","detail":"Trận kỳ và trận bàn là loại pháp khí cho phép tu sĩ bố trí trận pháp mà không cần dành hàng chục năm tu luyện trận đạo. Dù không tạo được cấm pháp đại trận, chúng đủ dùng cho các trận phòng thủ tầm thường, lấy số lượng bù chất lượng. Thiên Tinh Tông của Nguyên Vũ Quốc nổi danh nhờ luyện chế và bày bán loại pháp khí này, chỉ cần có linh thạch là có thể mua được. Đây là mục tiêu chính khiến Hàn Lập lặn lội tới phường thị của tông môn.","nguon":["@c0221"]},{"id":"dinh-cap-phap-khi-tinh-pham","name":"Đỉnh cấp pháp khí (tinh phẩm)","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp","soHuu":[],"trangThai":"dang-co","blurb":"Loại pháp khí cao cấp, giá động đến vài trăm linh thạch bậc thấp; tinh phẩm là mức cao nhất trong đỉnh cấp.","detail":"Pháp khí đỉnh cấp có giá trị rất cao, chỉ động đến cũng phải vài trăm linh thạch bậc thấp, người tu tiên bình thường gom cả đời chưa chắc mua nổi một kiện. Luyện chế đỉnh cấp pháp khí cần hỏa lực mạnh như tiên thiên chân hỏa hoặc địa hỏa, tương tự khi luyện Trúc Cơ đan. Hàn Lập tới gian hàng luyện khí đòi xem tinh phẩm của đỉnh cấp pháp khí nhưng tiệm chỉ có loại bình thường, nên hắn giao tài liệu để Từ lão giả luyện chế.","nguon":["@c0222"]},{"id":"hoa-van-kiem","name":"Hỏa Vân Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":[],"trangThai":"dang-co","blurb":"Kiện pháp khí là vật phẩm đầu tiên do bản điếm chủ trì đưa ra đấu giá tại cạnh mại hội của bí điếm.","detail":"Hỏa Vân Kiếm được một trung niên nam tử cao gầy vẻ mặt khôn khéo bước ra giới thiệu, mở màn chuỗi đấu giá của cạnh mại hội ngầm mà Hàn Lập tham dự.","nguon":["@c0223"]},{"id":"khoi-loi-co-quan-thu","name":"Khôi lỗi cơ quan thú","cn":"","aliases":["đôi khôi lỗi thú","khôi lỗi thú"],"category":"phap-bao","categoryLabel":"Pháp bảo (thượng cấp)","phamCap":"Thượng cấp pháp khí (khôi lỗi thú cấp hai)","soHuu":[],"trangThai":"dang-co","blurb":"Một cặp khôi lỗi màu đen sáng bóng, kích cỡ bằng nắm tay, ngoại hình hao hao sư tử-hổ; thực lực ngang tu sĩ Luyện Khí kỳ tầng chín.","detail":"Cặp khôi lỗi cơ quan thú là thượng cấp pháp khí do khôi lỗi cơ quan thuật chế thành, xếp vào khôi lỗi thú cấp hai theo phân cấp chính thức. Thân màu đen sáng bóng, kích cỡ bằng nắm tay, hình dáng hao hao giữa sư tử và hổ nhưng không rõ nguyên hình quái thú. Thực lực ngang tu sĩ Luyện Khí kỳ tầng chín, tuyệt đối trung thành và hung dữ không sợ chết. Được rao bán tại phiên đấu giá bí điếm, bị hai quái nhân đẩy giá bất thường tới trên chín trăm linh thạch kèm bảo vật.","nguon":["@c0224"]},{"id":"hong-la-thien-lo","name":"Hồng La Thiên lô","cn":"","aliases":[],"category":"khac","categoryLabel":"Đan lô","phamCap":"Đan lô đỉnh cấp","soHuu":["Nữ tu sĩ Trúc Cơ kỳ (mua Hồng La Thiên lô)"],"trangThai":"dang-co","blurb":"Đan lô đỉnh cấp màu hỏa hồng được luyện khí sư yêu quí, từng truyền qua nhiều luyện khí đại sư.","detail":"Hồng La Thiên lô là đan lô đỉnh cấp màu hỏa hồng, được giới luyện khí sư trân quí nhất, từng qua tay nhiều luyện khí đại sư và luyện chế ra hàng loạt tinh phẩm pháp khí như Huyễn Âm kiếm, Thanh Giao kỳ, Hắc Viêm châu. Nghe nói lô này gia tăng thành công suất luyện chế. Tại phiên đấu giá bí điếm được bán với tám trăm năm mươi mốt linh thạch. Chi tiết Thanh Giao kỳ trong tay Hàn Lập cũng xuất từ đan lô này khiến hắn kinh ngạc.","nguon":["@c0224"]},{"id":"huyen-am-kiem","name":"Huyễn Âm kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí (tinh phẩm)","phamCap":"Tinh phẩm pháp khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tinh phẩm pháp khí được nêu là từng luyện chế bằng Hồng La Thiên lô.","detail":"Huyễn Âm kiếm được nhắc tên như một trong các tinh phẩm pháp khí từng ra đời từ đan lô Hồng La Thiên lô, dùng để minh chứng đẳng cấp và giá trị của đan lô này trong phiên đấu giá bí điếm.","nguon":["@c0224"]},{"id":"hac-viem-chau","name":"Hắc Viêm châu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí (tinh phẩm)","phamCap":"Tinh phẩm pháp khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tinh phẩm pháp khí được nêu là từng luyện chế bằng Hồng La Thiên lô.","detail":"Hắc Viêm châu được nhắc tên như một trong các tinh phẩm pháp khí từng luyện chế bằng đan lô Hồng La Thiên lô, dùng làm dẫn chứng cho giá trị đan lô trong phiên đấu giá bí điếm.","nguon":["@c0224"]},{"id":"do-vat-trao-doi-nguoi-khoi-ngo","name":"Đồ vật trao đổi của người khôi ngô","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm trao đổi","phamCap":"Trị giá mấy ngàn linh thạch","soHuu":["Người khôi ngô đội mũ xanh biếc"],"trangThai":"dang-co","blurb":"Món đồ được nói trị giá mấy ngàn linh thạch mà người khôi ngô dùng thêm vào giá để đổi cặp khôi lỗi thú.","detail":"Trong lúc quýnh lên giành cặp khôi lỗi cơ quan thú, người khôi ngô đội mũ xanh biếc lôi ra một món đồ được nói trị giá mấy ngàn linh thạch, cộng thêm chín trăm linh thạch để ép bí điếm giao khôi lỗi thú ngay. Bản chất và công năng cụ thể của món đồ chưa được tiết lộ.","nguon":["@c0224"]},{"id":"hoang-tinh-chi-ngan-nam","name":"Hoàng Tinh chi ngàn năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Linh dược đỉnh cấp","soHuu":["Hàn Lập","Vạn Bảo lâu"],"trangThai":"dang-co","blurb":"Gốc linh dược đỉnh cấp ngàn năm, gần trăm năm mới hiện thế vài lần, dùng luyện linh đan để đột phá cảnh giới. Một trong hai gốc do Hàn Lập tự nuôi dưỡng, từng bán cho Vạn Bảo lâu.","detail":"Gốc dược thảo ngàn năm quý hiếm, gần trăm năm mới hiện thế vài lần, được dùng để luyện linh đan phục vụ đột phá cảnh giới. Đựng trong hộp ngọc xanh biếc, khi mở ra tỏa dược hương nồng đậm tràn ngập đại sảnh. Tại buổi đấu giá bí điếm, nam tử cao gầy đưa ra làm vật cuối cùng với giá khởi điểm năm trăm linh thạch, các tu sĩ tranh nhau hô giá từ một ngàn vượt hai ngàn linh thạch. Hàn Lập nhận ra đây chính là một trong hai gốc do chính mình nuôi dưỡng và từng bán cho Vạn Bảo lâu.","nguon":["@c0225"]},{"id":"hop-ngoc-xanh-biec-dung-linh-duoc","name":"Hộp ngọc xanh biếc","cn":"","category":"khac","categoryLabel":"Hộp đựng","phamCap":"Không rõ","soHuu":["Nam tử cao gầy (chủ trì bí điếm)"],"trangThai":"dang-co","blurb":"Hộp ngọc màu xanh biếc dùng đựng gốc Hoàng Tinh chi ngàn năm tại buổi đấu giá bí điếm.","detail":"Hộp bằng ngọc xanh biếc có vỏ bọc rút ra được, dùng để đựng và bảo quản gốc Hoàng Tinh chi ngàn năm. Khi mở ra, dược hương của linh dược tràn ngập đại sảnh đấu giá.","nguon":["@c0225"]},{"id":"bo-bo-tran-phap-khi-dien-dao-ngu-hanh","name":"Bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận (tàn phẩm)","category":"khac","categoryLabel":"Khí cụ trận pháp","phamCap":"Tàn phẩm (một phần mười uy lực)","soHuu":["Tề Vân Tiêu"],"trangThai":"dang-co","blurb":"Bộ khí cụ pháp khí hóa của kỳ trận Điên Đảo Ngũ Hành Trận, hiện chưa thành công, chỉ phát huy một phần mười uy lực nguyên trận.","detail":"Là mục tiêu Hàn Lập muốn đổi lấy bằng thiên niên linh dược, dù chỉ còn một phần mười công hiệu vẫn đủ dùng cho động phủ đơn giản. Thanh niên hứa vài năm sẽ nâng lên tối thiểu nửa uy lực.","nguon":["@c0226"]},{"id":"thien-nien-tu-que-hoa","name":"Thiên niên Tử Quế Hoa","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Thiên niên linh dược","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Dược thảo trên nghìn năm giá trị không thấp hơn Hoàng Tinh Chi.","detail":"Hàn Lập lấy ra làm vật mặc cả với thanh niên trận pháp sư, không mở hộp ngay mà đòi đối phương nói rõ dùng vật gì trao đổi.","nguon":["@c0226"]},{"id":"huyen-nguyet-thach","name":"Huyễn Nguyệt Thạch","category":"nguyen-lieu","categoryLabel":"Khoáng thạch / linh vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Viên đá được tu sĩ Trúc Cơ kỳ dùng kèm hai ngàn linh thạch để đấu được thiên niên dược thảo.","detail":"Xuất hiện trong đấu giá mật điếm như vật thanh toán bổ sung cho thiên niên linh thảo.","nguon":["@c0226"]},{"id":"ngoc-gian-phuong-phap-bo-tran-dien-dao","name":"Ngọc Giản (phương pháp bố trận Điên Đảo Ngũ Hành Trận)","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc Giản ghi phương pháp bố trí bộ pháp khí Điên Đảo Ngũ Hành Trận.","detail":"Ngọc Giản ghi lại phương pháp bố trí bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận gồm trận bàn và trận kỳ, để đại trận phát sinh hiệu lực. Tề Vân Tiêu giao cho Hàn Lập cùng bộ pháp khí và quyển Vân Tiêu Tâm Thuật trong giao dịch đổi lấy thiên niên linh dược.","nguon":["@c0227"]},{"id":"thien-nien-linh-duoc-trong-hop","name":"Thiên niên linh dược (trong hộp)","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Linh dược ngàn năm trong hộp của Hàn Lập, dược hương đầy linh khí; dùng trao đổi lấy bộ pháp khí và Vân Tiêu Tâm Thuật.","detail":"Linh dược ngàn năm trong hộp của Hàn Lập, dược hương tỏa ra đầy linh khí. Hàn Lập mở hộp cho Tề Vân Tiêu ngửi nhưng giữ chặt không cho lấy, ám thị đòi giao hàng trước; cuối cùng dùng làm vật trao đổi lấy bộ bố trận pháp khí Điên Đảo Ngũ Hành Trận, Ngọc Giản và quyển Vân Tiêu Tâm Thuật.","nguon":["@c0227"]},{"id":"vo-cung-ngo-cong","name":"Vỏ cứng của ngô công","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vỏ ngoài của yêu thú loại độc trùng thượng cấp bậc một, hiếm; là tài liệu luyện khí rất tốt.","detail":"Vỏ cứng ngoài của một yêu thú thuộc loại độc trùng thượng cấp bậc một, rất hiếm. Lão giả tóc bạc chủ tiệm Luyện khí nhận định là tài liệu luyện khí thượng cấp thích hợp làm hộ giáp, thuẫn bài, có thể luyện thành đỉnh cấp pháp khí; ngay khi chưa chế luyện đã có thể ngạnh tiếp một kích của đỉnh giai pháp khí. Hàn Lập lấy ra bán cho lão nhưng chặn lại vì còn tài liệu khác chưa lấy ra.","nguon":["@c0227"]},{"id":"than-phong-chau","name":"Thần Phong Châu","cn":"","aliases":["Thần Phong chu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí phi hành cao cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thuyền nhỏ màu trắng luyện từ vẩy và da Mặc Giao, biến lớn thành thuyền độc mộc chở mấy người, tốc độ cực nhanh nhưng không có năng lực phòng vệ.","detail":"Pháp khí phi hành do Từ lão luyện từ vẩy và da giao long Mặc Giao. Khi Hàn Lập dùng pháp quyết màu xanh, thuyền trắng biến thành thuyền độc mộc như thật chở được mấy người, đưa hắn lên không trung; tốc độ hiếm có, chỉ dùng nửa tốc độ cũng về động phủ trong một thời thần. Nhược điểm là không chở được nhiều người và không có năng lực phòng vệ. Hàn Lập rất hài lòng, thay thế pháp khí hình chiếc lá chậm chạp cũ, và đánh giá so với Thiên Nguyệt Thần Châu của Yểm Nguyện Tông.","nguon":["@c0228"]},{"id":"hai-vien-cau-xanh-do-may-che-giau","name":"Hai viên cầu xanh-đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Cặp cầu xanh và đỏ của Hàn Lập, đập vào nhau tạo cụm mây xanh đỏ đường kính hơn mười trượng bao trùm và giấu kín thân ảnh.","detail":"Hai viên cầu — một xanh một đỏ — khi đập vào nhau đồng thời tuôn ra một cụm khói xanh đỏ đường kính hơn mười trượng, bao trùm và che giấu thân ảnh Hàn Lập khỏi tầm nhìn để hắn an toàn quan sát trận chiến dưới đất.","nguon":["@c0228"]},{"id":"tai-lieu-mac-giao","name":"Tài liệu Mặc Giao","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Nguyên liệu quý","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Da giao long, vẩy, sừng, răng nanh, nhãn châu, lợi trảo từ thân Mặc Giao — nguyên liệu quý dùng luyện chế pháp khí.","detail":"Bộ nguyên liệu luyện khí lấy từ thân con giao long Mặc Giao gồm da, vẩy, sừng, răng nanh, nhãn châu, lợi trảo. Vì giao long là thiên địa yêu thú đã biến mất từ lâu ở tu tiên giới nên tài liệu cực quý; Hàn Lập giao cho Từ lão luyện chế, trong đó vẩy và da dùng chế Thần Phong Châu.","nguon":["@c0228"]},{"id":"phap-khi-hinh-la-co-tron-chay","name":"Pháp khí hình lá cờ (tu sĩ bị vây)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí hình lá cờ một tu sĩ Trúc Cơ dùng để thoát ly hộ trạo bay ra ngoài định trốn chạy khỏi vòng vây khôi lỗi.","detail":"Pháp khí phòng ngự hình lá cờ mà một vị tu sĩ trong nhóm bị vây dùng để tăng phòng hộ và thoát ly hộ trạo hợp lực bay ra ngoài trốn chạy; nhưng vừa ra khỏi liền bị siêu cấp quang trụ bắn trúng.","nguon":["@c0228"]},{"id":"dao-thuong-khoi-loi-can-chien","name":"Đao thương khôi lỗi cận chiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí cấp thấp","soHuu":[],"trangThai":"dang-co","blurb":"Binh khí sáng lòa trong tay khôi lỗi cận chiến mang trọng khải, xác thực là pháp khí cấp thấp.","detail":"Đao thương do đám khôi lỗi cận chiến (người máy mang trọng khải) cầm khi vây công nhóm Trúc Cơ tu sĩ; binh khí sáng lòa, được Hàn Lập nhận ra là pháp khí cấp thấp.","nguon":["@c0228"]},{"id":"thanh-hoa-chuong","name":"Thanh Hỏa Chướng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Kỳ môn pháp khí","phamCap":"Đỉnh cấp pháp khí (đôi)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đôi đỉnh cấp pháp khí kỳ môn của Hàn Lập, luyện từ mắt giao long, hóa thành sương mù xanh đỏ vừa che dấu thân ảnh vừa mang độc.","detail":"Hai đỉnh cấp pháp khí luyện chế từ mắt giao long, hóa thành sương mù xanh đỏ che dấu thân ảnh khiến người khác không nắm chắc vị trí. Được nhúng máu còn sót của Mạc Giao nên có thể khiến kẻ tiếp xúc chóng mặt nhức đầu, từ từ trúng độc mà không hay biết. Hàn Lập dùng nó ẩn mình trên không, đưa toàn bộ vân chướng xuyên nhập tầng mây xám để giấu thân triệt để.","nguon":["@c0229","@c0348"],"tabs":{"tienTrinh":[{"chuong":"@c0348","loai":"dùng","importance":"normal","giaiDoan":"Chuẩn bị đánh lén kín đáo","text":"Hàn Lập dùng Thanh Hỏa chướng hình thành phòng hộ và che thân trước khi đội Hoàng Phong Cốc giao chiến.","anchor":"Hắn đã lợi dụng Thanh Hỏa chướng hình thành nên phòng hộ"}]},"congNang":["Tạo mây đỏ che kín thân hình Hàn Lập khi chuẩn bị phục kích @c0348","Dùng làm lớp phòng hộ trong tình thế nguy hiểm @c0348"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0348","denChuong":"","cachCoDuoc":"Đã sở hữu trước trận phục kích","trangThai":"dang-giu"}]},{"id":"cu-ho-khoi-loi-ho-khong-lo","name":"Cự Hổ (khôi lỗi hổ khổng lồ)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi cơ quan thú","phamCap":"Không rõ","soHuu":["Nam tử khôi vũ (Thiên Trúc Giáo)"],"trangThai":"dang-co","blurb":"Khôi lỗi hổ khổng lồ cao năm sáu trượng của nam tử khôi vũ, phun quang trụ bạch sắc siêu cấp uy lực cực lớn từ miệng.","detail":"Khôi lỗi hổ cao đến năm sáu trượng, phun quang trụ bạch sắc siêu cấp uy lực cực lớn từ hàm dưới sau khi ngưng tụ bạch quang. Trên đầu hổ có cửa bí mật để nạp linh thạch bậc trung thuộc tính hỏa làm nhiên liệu; một kích toàn lực tiêu hao trọn nguyên một khối linh thạch bậc trung. Nam tử khôi vũ ngồi trên đầu hổ điều khiển, dùng nó bắn chết đám tu sĩ Nguyên Vũ Quốc.","nguon":["@c0229"]},{"id":"khoi-loi-bo-ha-cu-ho","name":"Khôi lỗi bộ hạ (đám khôi lỗi máy)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi máy","phamCap":"Không rõ","soHuu":["Nam tử khôi vũ (Thiên Trúc Giáo)"],"trangThai":"dang-co","blurb":"Các khôi lỗi máy công kích hộ trạo đám tu sĩ, rút lui khi Cự Hổ khai hỏa.","detail":"Đám khôi lỗi máy do nam tử khôi vũ điều khiển, ban đầu công kích hộ trạo đám tu sĩ Nguyên Vũ Quốc; khi Cự Hổ chuẩn bị phun quang trụ thì được lệnh dừng tay rút lui.","nguon":["@c0229"]},{"id":"hac-ti-co","name":"Hắc Ti Cổ","category":"khac","categoryLabel":"Độc / cổ trùng","phamCap":"Kỳ độc","soHuu":["Hoàng Long"],"trangThai":"da-dung","blurb":"Kỳ độc Hoàng Long phải ngàn cay vạn đắng mới cầu được từ Cổ Độc Tông. Được gieo qua hai lỗ máu trên cổ tay Lâm sư huynh, khó thanh trừ, thiết kế để trói buộc đối phương chờ phát tác.","detail":"Hắc Ti Cổ là kỳ độc Hoàng Long cầu được từ Cổ Độc Tông với ngàn cay vạn đắng. Hắn cấy nó vào Lâm sư huynh qua cái bắt tay giả vui mừng, để lại hai lỗ máu sâu cỡ cây đũa trên cổ tay đối phương. Loại độc này khó thanh trừ, được dùng làm mắt xích then chốt trong bẫy của Kim Giáo Chủ nhằm trói buộc Lâm sư huynh chờ độc phát tác. Lâm sư huynh kịp bức máu độc rồi uống bột phấn vàng trong bình ngọc xanh lục để giải.","nguon":["@c0230"]},{"id":"binh-ngoc-xanh-luc-bot-phan-vang","name":"Bình ngọc màu xanh lục chứa bột phấn vàng","category":"dan-duoc","categoryLabel":"Đan dược / giải độc","phamCap":"Không rõ","soHuu":["Lâm sư huynh"],"trangThai":"da-dung","blurb":"Bình ngọc màu xanh lục đựng bột phấn vàng dùng để giải độc. Lâm sư huynh đổ toàn bộ bột vào miệng để giải Hắc Ti Cổ.","detail":"Bình ngọc màu xanh lục chứa bột phấn vàng, là vật giải độc của Lâm sư huynh. Khi trúng Hắc Ti Cổ, hắn bức máu độc ra rồi đổ toàn bộ bột phấn vàng trong bình vào miệng để hóa giải kỳ độc từ Cổ Độc Tông.","nguon":["@c0230"]},{"id":"chiec-binh-nho-than-bi","name":"Chiếc bình nhỏ thần bí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảo vật bí ẩn của Hàn Lập có khả năng thúc linh dược trưởng thành nhanh, giúp luyện đan bù đắp tư chất kém.","detail":"Được Hàn Lập xác định là lợi thế then chốt trên con đường tiến lên Kết Đan: nhờ khả năng thúc linh dược trưởng thành, hắn có thể luyện đan để bù cho tư chất tu luyện kém của mình. Hắn coi đây là chỗ dựa để mưu tính đường tu luyện lâu dài.","nguon":["@c0231"]},{"id":"truc-bai-xanh-biec","name":"Trúc bài xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng Long"],"trangThai":"dang-co","blurb":"Kiện trúc bài lớn màu xanh biếc nổi bồng bềnh trên không, chở nhóm sáu bảy người Thiên Trúc giáo tới tấn công động phủ Hàn Lập.","detail":"Pháp bảo bay của Thiên Trúc giáo: một trúc bài xanh biếc cỡ lớn lơ lửng giữa không trung, trên đó có Hoàng Long dẫn đầu cùng đôi nam nữ và bốn huynh đệ song sinh. Nó là bệ đứng cho nhóm công kích đại trận động phủ Hàn Lập.","nguon":["@c0231"]},{"id":"tui-tru-vat-lam-su-huynh","name":"Túi trữ vật (Lâm sư huynh)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lâm sư huynh"],"trangThai":"dang-co","blurb":"Túi trữ vật trên áo xác Lâm sư huynh mà Hàn Lập lục tìm, kỳ vọng chứa khôi lỗi.","detail":"Khi lật thi thể Lâm sư huynh, Hàn Lập lục túi trữ vật trên áo hắn với hy vọng tìm được khôi lỗi. Chính lúc đó thần hồn Lâm sư huynh hóa đoàn sáng màu lục từ áo bay ra định đoạt xá.","nguon":["@c0231"]},{"id":"hai-goc-duoc-tai-sau-bay-tram-nam","name":"Hai gốc dược tài sáu bảy trăm năm","category":"nguyen-lieu","categoryLabel":"Linh dược / Dược thảo","phamCap":"Sáu bảy trăm năm","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai gốc linh dược lâu năm Hàn Lập dùng làm mồi thu hút Lôi Vạn Hạc.","detail":"Hai gốc dược tài đã dùng khoảng sáu, bảy trăm năm, mua từ bên ngoài tốn không ít linh thạch, linh khí bức người. Hàn Lập lấy ra từ trữ tàng thất, nhờ Lôi Vạn Hạc xem giúp thật giả và tuổi linh dược, thực chất dùng làm mồi tạo quan hệ giao hảo với tu sĩ Kết Đan kỳ.","nguon":["@c0234"]},{"id":"phap-khi-hop-ngoc-dung-thuoc","name":"Pháp khí hộp ngọc (hộp đựng thuốc)","category":"phap-bao","categoryLabel":"Pháp khí cất chứa","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí cất chứa linh dược, chỉ giữ dược lực tạm thời.","detail":"Dùng cất chứa linh dược nhưng chỉ giữ tạm thời; để thời gian dài thì dược lực từ từ tiêu tán, nên động phủ tu tiên thường bố trí trữ tàng thất riêng để giữ dược tính vĩnh viễn.","nguon":["@c0234"]},{"id":"ngoc-gian-cam-doan-than-thuc","name":"Ngọc giản (ghi phương pháp cấm đoạn thần thức)","category":"khac","categoryLabel":"Vật phẩm ghi chép","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản ghi rõ đặc điểm biến hóa cấm đoạn thần thức của trận pháp.","detail":"Ghi rõ biến hóa cấm đoạn thần thức của Điên Đảo Ngũ Hành trận cực đơn giản dễ dàng, luyện chế pháp khí thì uy lực giống hoàn toàn chính bản — công hiệu duy nhất có thể sánh với chính bản.","nguon":["@c0234"]},{"id":"tang-nguyen-dan","name":"Tăng Nguyên đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Loại đan dược Lôi Vạn Hạc muốn khai lô luyện chế để phụ trợ đột phá bình cảnh.","detail":"Đan dược mà Lôi Vạn Hạc dự tính luyện chế nhằm hỗ trợ vượt qua bình cảnh Kết Đan kỳ. Đòi hỏi chủ dược là linh dược đã ngoài năm trăm năm; nếu dùng linh thảo không đủ năm tuổi thì công hiệu suy giảm đáng kể. Đây là lý do lão thèm khát hai gốc linh thảo sáu-bảy trăm năm của Hàn Lập.","nguon":["@c0235","@c0236"]},{"id":"hai-goc-linh-thao-sau-bay-tram-nam","name":"Hai gốc linh thảo (sáu-bảy trăm năm)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai gốc linh thảo trân phẩm của Hàn Lập, được phán đoán đủ sáu-bảy trăm năm.","detail":"Hai gốc dược tài quý mà Hàn Lập sở hữu; Lôi Vạn Hạc vừa nhìn đã đoán đủ sáu, bảy trăm năm tuổi, thuộc loại trân phẩm khó tìm. Là vật trục tâm điểm của cuộc mặc cả trong chương: Hàn Lập dùng chúng làm giá đổi lấy một phương pháp luyện đan thích hợp.","nguon":["@c0235"]},{"id":"linh-thao-ngan-nam-bi-diem","name":"Linh thảo ngàn năm (bí điếm)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"khac","blurb":"Gốc linh thảo ngàn năm Hàn Lập kể (nửa thật nửa giả) từng thấy ở bí điếm, dùng làm mồi kích Lôi Vạn Hạc.","detail":"Gốc linh thảo ngàn năm mà Hàn Lập kể mình từng thấy ở một bí điếm nhưng vô lực mua nổi, đành trơ mắt nhìn người khác mua đi. Câu chuyện nửa thật nửa giả này được Hàn Lập tung ra để kích động lòng tham và sự tiếc nuối của Lôi Vạn Hạc, dọn đường cho cuộc trao đổi.","nguon":["@c0235"]},{"id":"chu-linh-thao","name":"Chu Linh thảo","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Linh thảo","soHuu":["Hàn Lập","Lôi Vạn Hạc"],"trangThai":"dang-co","blurb":"Loại linh thảo Hàn Lập có hai cây, dùng làm vật trao đổi phương thuốc cổ với Lôi Vạn Hạc.","detail":"Hàn Lập sở hữu hai gốc Chu Linh thảo. Trong cuộc giao dịch với Lôi Vạn Hạc, hai bên chốt dùng một gốc Chu Linh thảo đổi một cách điều chế phương thuốc cổ. Lôi Vạn Hạc thu nhận linh thảo để về luyện chế Tăng Nguyên đan của mình.","nguon":["@c0236"]},{"id":"tu-linh-dan","name":"Tụ Linh đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong hai phương thuốc cổ Hàn Lập chọn được từ mục lục của Lôi Vạn Hạc.","detail":"Phương điều chế đan dược cổ mà Hàn Lập chọn từ ngọc giản mục lục phương thuốc do Lôi Vạn Hạc đưa. Cùng với Luyện Khí tán, đây là kết quả cuộc trao đổi đổi Chu Linh thảo lấy cách điều chế.","nguon":["@c0236"]},{"id":"luyen-khi-tan","name":"Luyện Khí tán","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ","soHuu":["Hàn Lập"],"trangThai":"Đang sưu tầm nguyên liệu","blurb":"Luyện khí tán là tán dược từng được Hàn Lập dùng nhiều. Đến chương này, nó được nêu là đã không còn tác dụng với hắn vì phục dụng quá nhiều. (+) Phương thuốc cổ thứ hai Hàn Lập chọn từ mục lục phương thuốc của Lôi Vạn Hạc. [CAN-SOAT-GOP]","detail":"Phương điều chế đan dược cổ Hàn Lập chọn từ ngọc giản mục lục do Lôi Vạn Hạc cung cấp, bên cạnh Tụ Linh đan. Lôi Vạn Hạc lôi ra ngọc giản riêng ghi phương này để giao cho Hàn Lập.","nguon":["@c0236","@c0242","@c0374"],"tabs":{}},{"id":"ngoc-gian-muc-luc-phuong-thuoc","name":"Ngọc giản mục lục phương thuốc","category":"khac","categoryLabel":"Khác","phamCap":"Ngọc giản","soHuu":["Lôi Vạn Hạc"],"trangThai":"dang-co","blurb":"Ngọc giản Lôi Vạn Hạc đưa Hàn Lập, chứa danh sách phương thuốc kèm tính năng và nguyên liệu cần dùng.","detail":"Lôi Vạn Hạc đưa cho Hàn Lập một ngọc giản ghi mục lục các phương thuốc cổ của mình, kèm mô tả tính năng đan dược và nguyên liệu cần dùng. Nhờ đó Hàn Lập chọn được Tụ Linh đan và Luyện Khí tán, đồng thời thắc mắc lão hoàn thành mục lục này lúc nào.","nguon":["@c0236"]},{"id":"truyen-am-phu","name":"Truyền Âm phù","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập","Nho sinh"],"trangThai":"Đã ném vào đại trận và được Hàn Lập thu về","blurb":"Tờ phù dùng để truyền tin. Hàn Lập thấp giọng nói vào rồi ném đi, phù hóa thành đạo hỏa quang vọt vào màn nước báo tin đến động phủ. (+) Phù lục truyền tin, Phạm phu nhân gửi tới báo tin cho Hàn Lập nửa tháng sau khi thỏa thuận. [CAN-SOAT-GOP] (+) Phù lục truyền tin từ xa, hóa hỏa quang bay đến. Ma quan pháp sĩ tiếp nhận, hồng quang bạo vỡ ra lộ hỏa diễm chứa thông tin, nội dung khiến hai pháp sĩ Mộ Lan kinh sợ rút lui. [CAN-SOAT-GOP]","detail":"Hàn Lập dùng khi tới trước động phủ Lý Hóa Nguyên: thấp giọng nói mấy câu vào tờ phù rồi ném ra, phù hóa thành một đạo hỏa quang vọt vào màn nước để báo tin. Sau một nén nhang thì Vu Khôn ra đón.","nguon":["@c0237","@c0242","@c0402","@c0693"],"tabs":{}},{"id":"linh-duoc-thien-dia","name":"Linh dược thiên địa","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập","Lý Hóa Nguyên"],"trangThai":"da-dung","blurb":"Số linh dược thiên địa Hàn Lập từng có, bị Lý Hóa Nguyên lấy đi một nửa lấy danh nghĩa thu đồ; phần còn lại được luyện đan cứu mạng phu nhân của lão.","detail":"Lý Hóa Nguyên thu Hàn Lập làm đồ đệ vì tham số linh dược thiên địa này, lấy đi một nửa (nếu không Hàn Lập đã nhận hai viên Trúc Cơ đan thay vì một). Về sau chính số linh dược đó được luyện đan trong mấy năm để cứu chữa phu nhân của lão bị tu luyện sai lầm suýt mất mạng.","nguon":["@c0238"]},{"id":"kho-cong-phap-tang-thu-that","name":"Kho công pháp Tàng thư thất","category":"khac","categoryLabel":"Kho công pháp","phamCap":"","soHuu":["Lý Hóa Nguyên"],"trangThai":"dang-co","blurb":"Năm sáu mươi kiện ngọc giản, sách, hộp nổi lơ lửng tản kỳ quang, là công pháp Lý Hóa Nguyên thu thập mấy trăm năm.","detail":"Bên trong Tàng thư thất có năm, sáu mươi kiện ngọc giản, sách, hộp và bộ sách nổi lơ lửng tản kỳ quang đủ màu, là công pháp Lý Hóa Nguyên thu thập trong mấy trăm năm. Mỗi món đều bị hạ cấm chế bảo vệ.","nguon":["@c0239"]},{"id":"quyen-sach-mau-bac","name":"Quyển sách màu bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách Hàn Lập đang giữ, bề mặt có hoa văn cổ quái; khi bị nung, bề mặt tan chảy để lộ một lớp sách màu vàng bên trong không sợ lửa.","detail":"Quyển sách màu bạc Hàn Lập đang giữ, tên gọi trước đây là Tờ giấy màu bạc, bề mặt có hoa văn cổ quái, nặng và dày hơn quyển sách màu vàng. Khi Hàn Lập dùng liệt hỏa đỏ hồng nung, bề mặt tan chảy để lộ ra quang mang màu vàng — một quyển sách màu vàng ẩn bên trong không sợ lửa đốt.","nguon":["@c0240"]},{"id":"quyen-sach-mau-vang-ngung-nguyen","name":"Quyển sách màu vàng (Ngưng Nguyên công)","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách màu vàng Hàn Lập chọn làm chủ công pháp, kích cỡ giống hệt sách bạc nhưng mỏng hơn, ghi Ngưng Nguyên công và Tụ Linh thuật.","detail":"Quyển sách màu vàng đựng trong hộp ngọc mà Hàn Lập chọn làm chủ công pháp ở Tàng thư thất. Hình dáng kích cỡ giống hệt quyển sách màu bạc hắn đang giữ, chỉ mỏng hơn và bề mặt phủ cổ văn dày đặc, ghi lại pháp quyết bình thường Ngưng Nguyên công cùng thần thông phụ trợ Tụ Linh thuật. Sự giống nhau về hình dáng khiến Hàn Lập nảy nghi hoặc.","nguon":["@c0240"]},{"id":"quyen-sach-mau-vang-an-trong-sach-bac","name":"Quyển sách màu vàng ẩn trong sách bạc","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách vàng lộ ra sau khi nung chảy bề mặt sách bạc, dạy phi kiếm và kiếm quang, không sợ lửa và nuốt trọn kiếm quang xanh của Hàn Lập.","detail":"Quyển sách màu vàng lộ ra sau khi Hàn Lập nung chảy bề mặt quyển sách màu bạc. Nội dung dạy điều khiển phi kiếm và Kiếm tu chi thuật tu luyện kiếm quang. Sách không sợ lửa đốt, không biến hóa; khi Hàn Lập quăng lên không và đánh một đạo kiếm quang xanh to như cái bát để tiêu hủy thì kiếm quang biến mất vô ảnh vô tung như bị sách nuốt, khiến hắn từ kinh hãi chuyển sang phấn chấn.","nguon":["@c0240"]},{"id":"thanh-truc-phong-van-kiem","name":"Thanh trúc phong vân kiếm","cn":"","aliases":["Thanh tú phong vân kiếm","Kim Lôi trúc phi kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo phi kiếm","phamCap":"Dành cho tu sĩ Kết Đan kỳ","soHuu":["Hàn Lập"],"trangThai":"phuong-phap-luyen-che","blurb":"Pháp bảo Hàn Lập muốn luyện chế, cần tài liệu chính là dị chủng thần trúc vài nghìn năm tuổi. Hiện chưa tìm được phẩm loại vừa ý nên tạm gác. (+) Phương pháp luyện chế một bộ phi kiếm pháp bảo thuộc tính mộc, thích hợp phối hợp với Thanh nguyên kiếm quyết. [CAN-SOAT-GOP] (+) Hai thanh kiếm của Hàn Lập, rơi xuống bãi đá khi hắn bị ném từ trên cao, mất hết linh khí. [CAN-SOAT-GOP] (+) Pháp bảo bổn mạng của Hàn Lập, hiện chưa có hồn khí. Ngân Nguyệt đề nghị làm hồn khí cho kiếm, Hàn Lập đã đồng ý. [CAN-SOAT-GOP]","detail":"Thanh trúc phong vân kiếm được ghi trong tờ giấy vàng thứ hai Hàn Lập lấy từ động phủ Lý Hóa Nguyên. Pháp bảo này dành cho tu sĩ Kết Đan kỳ, cần ít nhất mười hai thanh phi kiếm mộc tạo thành một bộ; nếu đủ tài liệu và chân nguyên có thể luyện ba mươi sáu hoặc bảy mươi hai thanh, khi phối hợp với Thanh nguyên kiếm quyết có thể tăng uy lực đáng kể.","nguon":["@c0241","@c0399","@c0411","@c0413","@c0426","@c0491","@c0517","@c0547","@c0576","@c0613"],"tabs":{}},{"id":"to-giay-vang","name":"Tờ giấy vàng","cn":"","aliases":["Hai tờ giấy vàng"],"category":"khac","categoryLabel":"Vật phẩm chứa công pháp","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-kich-hoat","blurb":"Hai tờ giấy màu vàng chứa truyền thừa công pháp, được Hàn Lập lấy từ động phủ của Lý Hóa Nguyên.","detail":"Tờ giấy vàng hấp thu Thanh nguyên kiếm quang rồi phát kim quang, hiện vô số chữ sáng nhỏ và truyền nội dung thẳng vào người chạm vào, gây đau đớn cực độ. Tờ thứ nhất truyền Thanh nguyên kiếm quyết đầy đủ cùng Tam chuyển trọng nguyên công; tờ thứ hai truyền phương pháp luyện Thanh trúc phong vân kiếm.","nguon":["@c0241"]},{"id":"binh-nho-than-bi","name":"Bình nhỏ thần bí","cn":"","aliases":["Chiếc bình nhỏ thần bí","Bình thần bí","Bình nhỏ"],"category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"Thần bí","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Dị bảo chứa chất dịch màu lục có thể thúc sinh linh thảo và nguyên liệu thực vật. Chất dịch này cũng có mặt nguy hiểm: động vật uống vào đều nổ tung dù đã pha loãng.","detail":"Hàn Lập dùng bình nhỏ thần bí để thúc giục linh thảo và nguyên liệu luyện đan sinh trưởng, đồng thời tận dụng khả năng này cho việc chế lá bùa trống. Qua nhiều lần thí nghiệm sau khi vào Hoàng Phong cốc, hắn phát hiện chất dịch màu lục không thể dùng trên cơ thể sống vì có thành phần bí ẩn ngoài linh lực khiến động vật nổ tung.","nguon":["@c0242"]},{"id":"co-nho-mau-vang","name":"Cờ nhỏ màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Cây cờ nhỏ Hàn Lập thả ra khi xử lý truyền âm phù. Nó biến thành luồng sáng vàng bay đi dẫn luồng lửa sáng trở về.","detail":"Sau khi ra khỏi bế quan thất, Hàn Lập thả cờ nhỏ màu vàng để dẫn truyền âm phù trong đại trận trở lại. Vật này phối hợp với vầng sáng xanh trên tay hắn để thu truyền âm phù tới trước mắt.","nguon":["@c0242"]},{"id":"van-go-mau-lam-hinh-thu-ky-la","name":"Ván gỗ màu lam hình thù kỳ lạ","cn":"","category":"khac","categoryLabel":"Vật phẩm ngự khí","phamCap":"Không rõ","soHuu":["Nho sinh"],"trangThai":"Nho sinh đang giữ","blurb":"Vật phẩm màu lam có hình thù kỳ lạ do nho sinh mang theo. Y ném nó lên không trung rồi ngự khí bay đi khỏi động phủ Hàn Lập.","detail":"Nho sinh xuất hiện trong lam quang, tay nâng miếng ván gỗ màu lam kỳ lạ. Sau khi ném truyền âm phù vào đại trận, y dùng vật này để rời khỏi nơi ở của Hàn Lập.","nguon":["@c0242"]},{"id":"tu-linh-don","name":"Tụ linh đơn","cn":"","category":"dan-duoc","categoryLabel":"Đan dược phương thuốc cổ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"chưa luyện thành","blurb":"Đan dược cổ mà Hàn Lập xem là hướng tăng pháp lực tiếp theo sau khi Luyện khí tán mất hiệu lực.","detail":"Hàn Lập còn thiếu nguyên liệu để luyện Tụ linh đơn. Sau khi Luyện khí tán vô dụng với hắn, loại đan dược này trở thành hy vọng giúp pháp lực tăng nhanh trở lại.","nguon":["@c0243"]},{"id":"than-phong-chu","name":"Thần phong chu","cn":"","category":"phap-bao","categoryLabel":"Phi hành pháp khí","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Thần Phong Chu là phi hành pháp khí màu trắng tinh được Hàn Lập sử dụng để di chuyển đường xa, có khả năng chở người và chuyển hướng nhanh chóng.","detail":"Thần Phong Chu là một chiếc thuyền bay màu trắng tinh thuộc loại phi hành pháp khí. Hàn Lập dùng nó trong nhiều dịp: mời Trần Xảo Thiến cùng ngồi lên để bay đến Bạch Cúc Sơn (@c0332), cũng như chở nữ tử che mặt và chuyển hướng nhanh để rời khỏi Đổng Huyên Nhi (@c0361). Ngoài ra, Hàn Lập còn đứng trên Thần Phong Chu khi rời động phủ theo lệnh triệu tập của Lý Hóa Nguyên.","nguon":["@c0243","@c0271","@c0306","@c0332","@c0361","@c0364"],"tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"dùng","importance":"normal","giaiDoan":"Đưa người đến Bạch Cúc Sơn","text":"Hàn Lập lấy Thần Phong Chu trắng tinh ra, mời Trần Xảo Thiến cùng ngồi để bay đến Bạch Cúc Sơn.","anchor":"Hàn Lập nói xong, liền đem ra Thần Phong Chu trắng tinh, mời Trần Xảo Thiến.","phamCap":"Pháp khí"},{"chuong":"@c0361","loai":"dùng","importance":"normal","giaiDoan":"Thoát khỏi truy chặn","text":"Hàn Lập dùng Thần Phong Chu chở nữ tử che mặt và đổi hướng nhanh để rời khỏi Đổng Huyên Nhi.","anchor":"Thần Phong Chu dưới chân Hàn Lập chợt lóe, liền mang theo người “vù” một tiếng"}]},"aliases":["Thần Phong chu"],"congNang":["Ngự khí phi hành và chở người di chuyển đường xa @c0332","Phi hành và chuyển hướng nhanh @c0361"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0332","denChuong":"","cachCoDuoc":"đã có và sử dụng để đào thoát","trangThai":"đang giữ"}],"dacDiem":"Thuyền bay màu trắng tinh"},{"id":"tui-tru-vat","name":"Túi trữ vật","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Vật chứa Hàn Lập dùng để phân loại phù lục và đồ đạc.","detail":"Trước khi đến Lục Ba động, Hàn Lập lấy hơn mười túi trữ vật trong rương gỗ dưới giường đá rồi phân loại phù lục theo chủng loại và cấp bậc.","nguon":["@c0243"]},{"id":"phu-luc-bac-cao-so-cap","name":"Phù lục bậc cao sơ cấp","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"bậc cao sơ cấp","soHuu":["Hàn Lập"],"trangThai":"có thể chế tạo","blurb":"Loại phù lục Hàn Lập đã miễn cưỡng chế được sau bốn năm luyện tập.","detail":"Nhờ luyện pháp thuật cấp thấp và tiêu hao nhiều tài liệu chế phù, Hàn Lập đã miễn cưỡng chế ra phù lục bậc cao sơ cấp, dù tỷ lệ thành công còn rất thấp.","nguon":["@c0243"]},{"id":"phu-luc-trung-cap","name":"Phù lục trung cấp","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"trung cấp","soHuu":["Hàn Lập"],"trangThai":"mục tiêu luyện chế","blurb":"Mục tiêu chế phù kế tiếp của Hàn Lập.","detail":"Sau khi đạt mức miễn cưỡng chế phù lục bậc cao sơ cấp, Hàn Lập định trong lần bế quan sau sẽ học pháp thuật trung cấp và thử luyện chế phù lục trung cấp.","nguon":["@c0243"]},{"id":"dinh-nhan-don","name":"Định nhan đơn","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã luyện chế","blurb":"Đan dược giữ nhan sắc mà Hàn Lập luyện được trong lúc bế quan.","detail":"Hàn Lập luyện được bảy tám viên Định nhan đơn trong lúc rảnh rỗi và uống thử một viên vì tò mò về công dụng giữ gìn dung mạo.","nguon":["@c0243"]},{"id":"can-khon-thap","name":"Càn khôn tháp","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo trong truyền thuyết","soHuu":["Yến gia"],"trangThai":"làm phần thưởng Đoạt bảo đại hội","blurb":"Phù bảo của Yến gia, được Bách Xảo Viện luyện chế bằng phương pháp hàng đầu, là nhất kiện đại danh khí pháp bảo đương thời Việt Quốc. (+) Phù bảo do Yến gia đưa ra làm phần thưởng cao nhất tại Đoạt bảo đại hội. Giá trị của nó đủ khiến cả tu sĩ Kết Đan kỳ cũng động tâm. [CAN-SOAT-GOP]","detail":"Càn khôn tháp là phần thưởng dành cho người đứng đầu Đoạt bảo đại hội của Yến gia. Việc Yến gia dùng phù bảo này để chiêu dụ đệ tử các cao thủ Kết Đan kỳ cho thấy đại hội vừa là nơi tranh bảo, vừa là dịp kết giao thế lực.","nguon":["@c0245","@c0596"],"tabs":{}},{"id":"thu-cung-sa","name":"Thủ cung sa","cn":"","aliases":[],"category":"khac","categoryLabel":"Dấu kiểm trinh","phamCap":"Không rõ","soHuu":["Đổng Huyên Nhi"],"trangThai":"dang-co","blurb":"Dấu trên tay Đổng Huyên Nhi dùng để chứng minh nàng vẫn giữ trinh bạch.","detail":"Hồng Phất kiểm tra thủ cung sa của Đổng Huyên Nhi trước mặt phu nhân Lý Hóa Nguyên. Kết quả dấu này vẫn còn nguyên vẹn, làm sáng tỏ một phần lời đồn thất tiết quanh nàng.","nguon":["@c0246"]},{"id":"thu-moi-doat-bao-dai-hoi","name":"Thư mời Đoạt bảo đại hội","cn":"","aliases":[],"category":"khac","categoryLabel":"Thư mời","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Tờ giấy nhỏ ghi địa điểm Đoạt bảo đại hội là Yến Linh bảo.","detail":"Hàn Lập cầm thư mời này khi cùng Đổng Huyên Nhi tới khu vực tiếp khách của Yến gia. Hắn kiểm tra nhiều lần để xác định mình không nhầm địa điểm trước khi bắn hỏa cầu báo hiệu.","nguon":["@c0246"]},{"id":"song-thu-vu","name":"Song thủ vụ","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"không rõ","soHuu":["Yến gia","Yến Vũ","Yến Linh"],"trangThai":"đang sử dụng","blurb":"Song thủ vụ là quái ưng hai đầu cỡ lớn được huynh muội Yến gia cưỡi tới đón Hàn Lập và Đổng Huyên Nhi. Hàn Lập từng gặp loại linh thú này ở Thái Nam hội.","detail":"Trong chương 247, hai con Song thủ vụ chở Yến Vũ và Yến Linh bay tới đỉnh núi nơi Hàn Lập cùng Đổng Huyên Nhi đang chờ. Chúng được dùng như linh thú phi hành của Yến gia để tiếp dẫn khách vào Yến Linh bảo.","nguon":["@c0247"]},{"id":"lenh-bai-mo-yen-linh-bao","name":"Lệnh bài mở Yến Linh bảo","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Yến Vũ","Yến gia"],"trangThai":"đang sử dụng","blurb":"Lệnh bài mở Yến Linh bảo là vật được Yến Vũ dùng để khai mở cấm chế che giấu cổ bảo. Khi rót linh lực, nó phát ra chùm sáng vàng làm hào quang ngũ sắc hiện ra.","detail":"Yến Vũ lấy vật giống lệnh bài, rót linh lực rồi phóng ánh sáng vàng vào khoảng không giữa hai ngọn núi nhỏ. Ánh sáng này kích hoạt cấm chế, khiến hào quang ngũ sắc tan đi và Yến Linh bảo hiện ra.","nguon":["@c0247"]},{"id":"phuon-mau-vang-hinh-tam-giac","name":"Phướn màu vàng hình tam giác","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Đường huynh của Yến Vũ"],"trangThai":"đang sử dụng @c0248","blurb":"Pháp khí phòng thủ của đường huynh Yến Vũ trong trận tỷ thí. Khi dựng trước người, nó gọi ra luồng gió vàng bao bọc hộ thân.","detail":"Đường huynh của Yến Vũ dùng phướn màu vàng hình tam giác trong lúc thi triển đạo thuật thổ thuộc tính. Pháp khí này triệu một luồng gió vàng bao quanh thân, giúp hắn vừa tấn công bằng cự thạch vừa duy trì phòng thủ vững chắc.","nguon":["@c0248"]},{"id":"sau-bay-dau-lau-kho-trang-on","name":"Sáu bảy đầu lâu khô trắng ởn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Người áo bào màu lục"],"trangThai":"đang sử dụng @c0248","blurb":"Các đầu lâu khô trắng lơ lửng quanh người áo bào màu lục. Chương này chưa cho thấy công dụng cụ thể của chúng.","detail":"Trong trận đấu với tinh anh Yến gia, quanh người áo lục có sáu bảy đầu lâu khô trắng ởn lơ lửng. Chúng được nêu như hậu thủ chưa thi triển rõ, trong khi hắn chủ yếu dùng hắc khí lưới đen để chống cự cự thạch.","nguon":["@c0248"]},{"id":"quat-giay-mau-vang","name":"Quạt giấy màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Đường huynh của Yến Vũ"],"trangThai":"đang sử dụng @c0248","blurb":"Pháp khí được tinh anh Yến gia đổi sang ở cuối chương. Mỗi lần quạt ra đều tiêu hao thể lực lớn, khiến người dùng mồ hôi đầy mặt.","detail":"Sau khi ngừng cự thạch thuật, đường huynh của Yến Vũ cầm quạt giấy màu vàng bằng cả hai tay để tiếp tục trận đấu. Dù bề ngoài là vật nhẹ, mỗi lần quạt lại khiến hắn tiêu hao thể lực rõ rệt, báo hiệu pháp khí này có uy lực hoặc tác dụng đặc biệt.","nguon":["@c0248"]},{"id":"hoa-cot-bao-phien","name":"Hóa cốt bảo phiến","cn":"","aliases":["Hóa cốt phiến"],"category":"phap-bao","categoryLabel":"pháp khí","phamCap":"đỉnh cấp pháp khí","soHuu":["Đường huynh của Yến Vũ","Yến gia"],"trangThai":"suy tổn @c0249","blurb":"Đỉnh cấp pháp khí nổi danh của Yến gia, có thể khu sử độc vụ làm da tiêu thịt rữa. Trong trận với lục bào quái nhân, phần lớn độc vụ bị khô lâu nuốt mất khiến uy lực giảm đi.","detail":"Hóa cốt bảo phiến được Đường huynh của Yến Vũ dùng trong tỷ thí, ban đầu tạo lục vụ vây ép hắc khí của đối thủ. Lục bào quái nhân sau đó dùng khô lâu hút hắc khí rồi nuốt ngược lục vụ, khiến Đường huynh chỉ kịp thu hồi một phần; mặt quạt ảm đạm và uy lực về sau giảm không ít.","nguon":["@c0249"]},{"id":"phong-loi-phien","name":"Phong Lôi phiến","cn":"","category":"phap-bao","categoryLabel":"pháp khí","phamCap":"không rõ","soHuu":[],"trangThai":"được nhắc @c0249","blurb":"Pháp khí nổi danh được Đổng Huyên Nhi đem ra hỏi để so với Hóa cốt phiến. Yến Vũ cho rằng khó phát huy vì cần phong hoặc lôi dị linh căn, còn Phong sư huynh khẳng định Hóa cốt phiến không thể sánh bằng nó.","detail":"Phong Lôi phiến xuất hiện trong lời so sánh giữa Đổng Huyên Nhi, Yến Vũ và Phong sư huynh. Vật này trở thành nguyên cớ khiến hai nam tu tranh cãi trước mặt Đổng Huyên Nhi về giá trị của Hóa cốt phiến và pháp khí Yến gia.","nguon":["@c0249"]},{"id":"tu-quang-bat","name":"Tử quang bạt","cn":"","category":"phap-bao","categoryLabel":"pháp khí","phamCap":"không rõ","soHuu":["Phong sư huynh"],"trangThai":"đang có @c0249","blurb":"Pháp khí của Phong sư huynh, được hắn nêu ra khi chê bai Hóa cốt phiến. Việc nhắc đến Tử quang bạt khiến Yến Vũ bị kích nộ trong cuộc tranh cãi trước Đổng Huyên Nhi.","detail":"Tử quang bạt được Phong sư huynh đem ra làm chuẩn so sánh, nói Hóa cốt phiến còn không bằng pháp khí trong tay mình. Nó không trực tiếp tham chiến trong chương này nhưng là mấu chốt châm ngòi mâu thuẫn giữa Phong sư huynh và Yến Vũ.","nguon":["@c0249"]},{"id":"kho-lau-cua-luc-bao-quai-nhan","name":"Khô lâu của lục bào quái nhân","cn":"","category":"phap-bao","categoryLabel":"pháp khí quỷ vật","phamCap":"không rõ","soHuu":["Quái nhân lục bào tóc vàng mắt xám"],"trangThai":"đang dùng @c0249","blurb":"Các khô lâu được lục bào quái nhân sử dụng trong trận tỷ thí với Đường huynh Yến gia. Chúng hút hắc khí, nuốt độc vụ của Hóa cốt phiến rồi phun luồng sáng đen hợp thành cột sáng hạ đối thủ.","detail":"Khô lâu của lục bào quái nhân ban đầu hút hắc khí quanh chủ nhân và phình lớn như bánh xe. Sau đó chúng nuốt ngược lục vụ của Hóa cốt phiến, làm pháp khí đối phương suy giảm uy lực, rồi cùng lúc phun ra các luồng sáng đen hợp lại thành cột sáng xuyên thủng hộ thân hoàng phong của Đường huynh.","nguon":["@c0249"]},{"id":"ngoc-gian-dia-do-yen-linh-bao","name":"Ngọc giản địa đồ Yến linh bảo","cn":"","category":"khac","categoryLabel":"Ngọc giản / địa đồ","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang do Hàn Lập giữ","blurb":"Ngọc giản chứa địa đồ và một số thông tin về Yến linh bảo. Yến Vũ đưa vật này cho Hàn Lập để hắn tự tìm đường trong bảo.","detail":"Ngọc giản địa đồ Yến linh bảo giúp Hàn Lập tiết kiệm nhiều thời gian khi đi lại trong bảo thành. Nhờ thông tin trong đó, hắn biết thêm về đường sá, cửa hàng, trà lâu và quy chế khép kín đối với người thường trong Yến linh bảo.","nguon":["@c0250"]},{"id":"binh-bac","name":"Bình bạc","cn":"","category":"khac","categoryLabel":"Vật chứa đan","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập lấy ra trước lúc chia tay Mặc Thải Hoàn","blurb":"Một chiếc bình bạc Hàn Lập dùng để chứa đan hoàn màu phấn hồng. Nó xuất hiện khi hắn chuẩn bị món quà chia tay dành cho Mặc Thải Hoàn.","detail":"Hàn Lập lấy bình bạc ra rồi lấy từ trong đó một viên đan hoàn màu phấn hồng. Vật này gắn với khoảnh khắc hắn giúp Mặc Thải Hoàn kéo dài tuổi thọ và giữ dung nhan trước khi rời đi.","nguon":["@c0252"]},{"id":"dan-hoan-mau-phan-hong","name":"Đan hoàn màu phấn hồng","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập","Mặc Thải Hoàn"],"trangThai":"Đã được Mặc Thải Hoàn uống","blurb":"Đan dược Hàn Lập cho Mặc Thải Hoàn uống trước lúc chia tay. Nó không thể giúp nàng tu tiên nhưng có thể kéo dài tuổi thọ thêm vài năm và giữ dung nhan không đổi.","detail":"Hàn Lập lấy viên đan màu phấn hồng từ bình bạc, nói rõ công dụng rồi bắn thẳng vào miệng Mặc Thải Hoàn. Viên đan trở thành món quà chia tay giữa tu sĩ Trúc Cơ và một phàm nữ không có linh căn.","nguon":["@c0252"]},{"id":"thien-nam-thu-trac","name":"Thiên nam thủ trác","cn":"","category":"khac","categoryLabel":"Điển tịch","phamCap":"Điển tịch ghi chép phong tục và thế lực Thiên Nam","soHuu":["Vô Du Tử"],"trangThai":"được viện dẫn","blurb":"Điển tịch được Vô Du Tử viện dẫn để xác nhận thông tin về Quỷ Linh Môn và năm ma tông khác.","detail":"Thiên nam thủ trác ghi thông tin về các đại phái, nhân tình phong tục và kỳ văn các quốc gia. Vô Du Tử nhắc tới quyển hai chương bốn của điển tịch này để chứng minh Quỷ Linh Môn là một trong sáu tông phái ma đạo của Thiên La quốc.","nguon":["@c0253"]},{"id":"thien-hoa-thach","name":"Thiên hoa thạch","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"không rõ","soHuu":["Nữ tử họ Phương"],"trangThai":"được đưa ra trao đổi","blurb":"Tài liệu luyện khí do nữ tử họ Phương của Thiên khuyết bảo đưa ra trong hội trao đổi. Nó được giới thiệu là vật tốt để luyện chế pháp khí thổ thuộc tính.","detail":"Thiên hoa thạch xuất hiện trong hội trao đổi nhỏ tại Yến linh bảo, do nữ tử họ Phương thuộc Thiên khuyết bảo mang ra. Đây là một trong các vật phẩm hiếm làm không khí trao đổi trở nên sôi nổi.","nguon":["@c0255"]},{"id":"trung-phong-khieu-ung","name":"Trứng Phong khiếu ưng","cn":"","category":"khac","categoryLabel":"Trứng linh thú","phamCap":"ma thú bậc một cấp cao","soHuu":["Tu sĩ Linh thú sơn người đưa trứng Phong khiếu ưng"],"trangThai":"được đưa ra trao đổi","blurb":"Trứng linh thú do một tu sĩ Linh thú sơn đưa ra trao đổi. Phong khiếu ưng khi nuôi lớn có thể hỗ trợ canh gác và tìm vật.","detail":"Trong hội trao đổi tại Yến linh bảo, một tu sĩ Linh thú sơn xuất ra trứng Phong khiếu ưng. Vật này đại diện cho nhóm linh thú có giá trị sử dụng thực tế nếu được nuôi dưỡng thành công.","nguon":["@c0255"]},{"id":"duoc-thao-luyen-tu-linh-dan","name":"Dược thảo luyện Tụ linh đan","cn":"","category":"nguyen-lieu","categoryLabel":"Dược thảo","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã được Hàn Lập đổi lấy","blurb":"Một loại dược thảo cần để luyện Tụ linh đan mà Hàn Lập đổi được trong hội nhỏ. Niên đại của nó chưa đủ nhưng phù hợp với khả năng mang về thúc đẩy thêm của Hàn Lập.","detail":"Hàn Lập tìm được loại dược thảo này trong số vật phẩm trao đổi tại Yến linh bảo. Dù năm thuốc chưa đạt yêu cầu luyện đan ngay, nó vẫn có giá trị với hắn vì có thể được bồi dưỡng thêm.","nguon":["@c0255"]},{"id":"luc-phu-so-cap-bac-cao","name":"Lục phù sơ cấp bậc cao","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"sơ cấp bậc cao","soHuu":["Hàn Lập"],"trangThai":"dùng để trao đổi","blurb":"Loại phù lục Hàn Lập dùng làm vật trao đổi chính trong hội nhỏ tại Yến linh bảo. Hắn dùng mười tấm để đổi cổ phương Tự Linh Hoàn từ Vô Du Tử.","detail":"Khi đến lượt mình, Hàn Lập rao đổi lục phù sơ cấp bậc cao lấy nguyên liệu luyện đan hoặc phương thuốc. Sau khi xem cổ phương Tự Linh Hoàn, hắn lấy ra mười phù lục để hoàn tất giao dịch.","nguon":["@c0255"]},{"id":"tu-linh-hoan","name":"Tự Linh Hoàn","cn":"","category":"dan-duoc","categoryLabel":"Đan phương/đan dược nuôi linh thú","phamCap":"cổ phương","soHuu":["Hàn Lập"],"trangThai":"được Hàn Lập đổi lấy phương thuốc","blurb":"Cổ phương chuyên dùng để nuôi dưỡng linh thú, được Hàn Lập đổi từ Vô Du Tử. Với tu sĩ thường, nó gần như phế vật vì nguyên liệu quá quý hiếm, nhưng với Hàn Lập lại có giá trị đặc biệt. (+) Đan dược Hàn Lập dự định luyện chế với số lượng lớn. Hắn tìm mua hạt giống dược tài cần thiết để dùng Tụ Linh Hoàn vào việc dạy dỗ hai con tri thù. [CAN-SOAT-GOP]","detail":"Tự Linh Hoàn là phương thuốc cổ dùng cho linh thú, được nói là yêu thú đa số thích ăn và dùng lâu có thể giúp tăng cấp. Do nguyên liệu luyện chế quá quý, nó khó được tu sĩ bình thường sử dụng, nhưng Hàn Lập nhận ra giá trị riêng nên dùng mười phù lục sơ cấp bậc cao để đổi lấy.","nguon":["@c0255","@c0377"],"tabs":{}},{"id":"ngoc-gian-mau-xanh","name":"Ngọc giản màu xanh","cn":"","category":"khac","categoryLabel":"Vật phẩm ghi chép","phamCap":"không rõ","soHuu":["Vô Du Tử","Hàn Lập"],"trangThai":"chứa cổ phương Tự Linh Hoàn","blurb":"Ngọc giản do Vô Du Tử ném cho Hàn Lập xem trong hội trao đổi. Bên trong chứa phương thuốc cổ Tự Linh Hoàn chuyên nuôi dưỡng linh thú.","detail":"Vô Du Tử dùng ngọc giản màu xanh làm vật ghi chép cổ phương Tự Linh Hoàn. Sau khi Hàn Lập xem nội dung và cân nhắc giá trị của phương thuốc, giao dịch giữa hai người được hoàn tất.","nguon":["@c0255"]},{"id":"tu-van-ky","name":"Tử vân kỳ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hộ thân","phamCap":"không rõ","soHuu":["Yến Như Yên"],"trangThai":"đang do Yến Như Yên nắm giữ","blurb":"Tử vân kỳ là pháp bảo hộ thân của Yến Như Yên. Nàng dựa vào vật này để tự tin có thể thoát thân nếu đàm phán với Quỷ linh môn xảy ra biến cố.","detail":"Khi được Yến gia lão tổ dặn cẩn thận và chuẩn bị tiếp ứng quanh phòng khách, Yến Như Yên nói mình có Tử vân kỳ hộ thân. Vật này khiến nàng nắm chắc khả năng đào thoát trong trường hợp người Quỷ linh môn trở mặt.","nguon":["@c0256"]},{"id":"phap-khi-mau-tim-hinh-chiec-bat","name":"Pháp khí màu tím hình chiếc bạt","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Phong sư huynh"],"trangThai":"dang-co","blurb":"Pháp khí của Phong sư huynh được lấy ra khi chuẩn bị đối phó nam tử diễm lệ. Nó đi cùng lời uy hiếp buộc đối phương giải mê thuật cho Đổng Huyên Nhi.","detail":"Sau khi nghe Hàn Lập vạch ra khả năng Đổng Huyên Nhi bị mê hoặc, Phong sư huynh lấy pháp khí màu tím hình chiếc bạt ra. Pháp khí này được dùng để tạo sức ép với nam tử diễm lệ trong tình thế sắp giao chiến.","nguon":["@c0258"]},{"id":"phap-khi-giong-doan-thuong","name":"Pháp khí giống đoản thương","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Yến Vũ"],"trangThai":"dang-co","blurb":"Pháp khí của Yến Vũ được lấy ra cùng lúc Phong sư huynh chuẩn bị ra tay. Nó thể hiện thái độ muốn giáo huấn nam tử diễm lệ sau khi biết Đổng Huyên Nhi bị mê hoặc.","detail":"Yến Vũ lấy pháp khí giống đoản thương khi nhận ra Đổng Huyên Nhi không vô cớ đi theo người lạ. Vật này xuất hiện trong thế đối đầu trực tiếp với nam tử diễm lệ tại thời điểm Đổng Huyên Nhi còn bị khống chế.","nguon":["@c0258"]},{"id":"cu-xoa-xanh-biec-toa-hac-khi","name":"Cự xoa xanh biếc tỏa hắc khí","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phi hành","phamCap":"không rõ","soHuu":["Vương Thiền"],"trangThai":"đang dùng @c0260","blurb":"Thanh cự xoa dài hơn một trượng, toàn thân xanh biếc và tỏa hắc khí. Vương Thiền đứng trên pháp khí này để xuất hiện trên không, chặn đường Hàn Lập khi hắn chuẩn bị dùng Thần Phong Chu thoát thân.","detail":"Cự xoa xanh biếc tỏa hắc khí là pháp khí Vương Thiền sử dụng trong màn truy chặn Hàn Lập tại khu đại hội đoạt bảo. Nó giúp hắn đột ngột hiện thân trên không và tạo áp lực trực tiếp trước khi chuyển sang thi triển Huyết Linh Đại pháp truy sát.","nguon":["@c0260"]},{"id":"khien-vay-ca-mau-trang","name":"Khiên vảy cá màu trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng @c0260","blurb":"Pháp khí phòng ngự Hàn Lập phóng ra trong lúc đối mặt Vương Thiền. Từ điểm bạch quang trong lòng bàn tay, nó hóa thành một tấm khiên hình vảy cá màu trắng chắn trước người.","detail":"Khi quyết định không giao chiến lâu với Vương Thiền mà chuẩn bị lên Thần Phong Chu bỏ chạy, Hàn Lập đồng thời dùng khiên vảy cá màu trắng để tăng phòng hộ. Vật này xuất hiện cùng hai tầng vòng phòng ngự đỏ và xanh, cho thấy hắn đề phòng đòn đánh bất ngờ trong lúc thoát thân.","nguon":["@c0260"]},{"id":"lien-chau-hoa-cau-phu","name":"Liên Châu Hỏa Cầu Phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng một phần","blurb":"Phù lục hỏa cầu liên hoàn được Hàn Lập dùng để cản Huyết Vân và Bích Âm Thoa.","detail":"Hàn Lập ném nhiều tờ Liên Châu Hỏa Cầu Phù về phía sau, khiến phần đầu Huyết Vân nổ tan một mảng và tạm lộ thân hình Vương Thiền. Khi Bích Âm Thoa lao tới, hắn chuyển số phù lục còn lại sang chặn pháp khí này thay vì tiếp tục phá Huyết Vân.","nguon":["@c0261"]},{"id":"bich-am-thoa","name":"Bích Âm Thoa","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Vương Thiền"],"trangThai":"đang sử dụng","blurb":"Phi thoa màu xanh lục của Vương Thiền, vừa là pháp khí phi hành vừa được phóng ra truy kích Hàn Lập.","detail":"Bích Âm Thoa ban đầu ở dưới chân Vương Thiền, sau đó được hắn phóng thành lục quang lao thẳng về phía Hàn Lập. Pháp khí này còn phóng Âm Ma Ti để quấn Ô Long Đoạt, nhưng bị hắc mang của Ô Long Đoạt phá vỡ.","nguon":["@c0261"]},{"id":"o-long-doat","name":"Ô Long Đoạt","cn":"","category":"phap-bao","categoryLabel":"Đỉnh giai pháp khí","phamCap":"Đỉnh giai pháp khí","soHuu":["Hàn Lập"],"trangThai":"nguyên vẹn","blurb":"Đôi pháp khí đen giống móng vuốt, luyện bằng máu giao long, được Hàn Lập dùng làm thủ đoạn chủ lực trong vòng vây Huyết Vân.","detail":"Ô Long Đoạt chặn Bích Âm Thoa, phá Âm Ma Ti và bóp nát nhiều Huyết Quỷ. Khi Hàn Lập đánh sâu vào Huyết Vân, pháp khí này suýt bị Linh Huyết làm mất khống chế, nhưng vẫn được hắn kịp thời thu hồi; khả năng không dễ bị ô nhiễm khiến Vương Thiền càng muốn đoạt lấy.","nguon":["@c0261","@c0306","@c0341"],"tabs":{"tienTrinh":[{"chuong":"@c0341","loai":"nhắc tới","importance":"normal","giaiDoan":"Sau khi nhiều pháp khí bị phá","text":"Ô Long đoạt vẫn hoàn hảo, không bị tổn hao khi nhiều pháp khí khác của Hàn Lập bị bọ ngựa yêu thú phá hỏng.","anchor":"Ô Long đoạt” lại hoàn hảo, không có tổn hao gì"}]},"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0341","denChuong":"","cachCoDuoc":"Đã sở hữu từ trước","trangThai":"nguyên vẹn"}]},{"id":"linh-huyet","name":"Linh Huyết","cn":"","category":"nguyen-lieu","categoryLabel":"Vật chất huyết pháp","phamCap":"Không rõ","soHuu":["Vương Thiền"],"trangThai":"ẩn trong Huyết Vân","blurb":"Thành phần trong Huyết Vân có khả năng làm ô nhiễm và ảnh hưởng quyền khống chế pháp khí.","detail":"Linh Huyết khiến Ô Long Đoạt của Hàn Lập đờ ra và lắc lư khi đánh vào trong Huyết Vân, làm hắn phải dốc sức thu hồi trước khi mất khống chế hoàn toàn. Việc Ô Long Đoạt không bị ô nhiễm dễ dàng khiến Vương Thiền đánh giá cao pháp khí này.","nguon":["@c0261"]},{"id":"hac-sac-kho-lau-dau","name":"Hắc sắc khô lâu đầu","cn":"","category":"khac","categoryLabel":"Vật ngự trong Huyết Vân","phamCap":"Không rõ","soHuu":["Vương Thiền"],"trangThai":"đang sử dụng","blurb":"Các đầu lâu màu đen lao ra từ Huyết Vân, phun hắc khí để chặn pháp thuật và phù lục.","detail":"Khi Hàn Lập tung sơ cấp phù lục và hỏa xà vào một phía Huyết Vân, hắc sắc khô lâu đầu lập tức lao ra, phun hắc khí ngăn cản những pháp thuật đến trước mặt. Nhờ vậy vòng vây Huyết Vân phía sau hầu như không bị phá.","nguon":["@c0261"]},{"id":"me-vu-xanh-do","name":"Mê vụ xanh đỏ","cn":"","category":"khac","categoryLabel":"Hiệu ứng chưa rõ","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang phát huy","blurb":"Làn sương xanh đỏ dày đặc đột ngột xuất hiện quanh Hàn Lập trong vòng vây Huyết Vân.","detail":"Mê vụ xanh đỏ che khuất thân hình Hàn Lập và cả Huyết Quỷ, khiến Vương Thiền không nhìn rõ hắn đang làm gì. Dù bị Huyết Vân không ngừng hấp nạp, lớp sương này trong thời gian ngắn vẫn không loãng đi rõ rệt.","nguon":["@c0261"]},{"id":"tieu-dao-phu-bao","name":"Tiểu đao Phù Bảo","cn":"","aliases":["vệt sáng màu vàng"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Tiểu đao Phù Bảo là phù bảo Hàn Lập bí mật khởi dụng trong mê vụ. Nó hóa thành vệt sáng màu vàng, phá Huyết Vân và giúp Hàn Lập thoát khỏi vòng vây của Vương Thiền.","detail":"Trong trận Huyết Vân, Hàn Lập dùng tiểu đao Phù Bảo phối hợp hơn mười hỏa long từ phù lục đánh nát các khô lâu cản đường và xé mở Huyết Vân. Sau đó hắn tiếp tục dùng vệt sáng vàng phản kích Vương Thiền, nhưng bị kim khô lâu đầu Phù Bảo của Vương Thiền ngoạm giữ trước khi Vương Thiền độc phát bỏ chạy.","nguon":["@c0262"]},{"id":"kim-kho-lau-dau-phu-bao","name":"Kim khô lâu đầu Phù Bảo","cn":"","aliases":["kim khô lâu đầu"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo","soHuu":["Hàn Lập","Vương Thiền"],"trangThai":"Đổi chủ sang Hàn Lập","blurb":"Kim khô lâu đầu Phù Bảo là phù bảo Vương Thiền dùng để giữ vệt sáng vàng của Hàn Lập. Khi Mạc Giao chi Độc phát tác, Vương Thiền bỏ lại vật này và Hàn Lập thu được.","detail":"Kim khô lâu đầu ngoạm giữ tiểu đao Phù Bảo của Hàn Lập trong lúc Vương Thiền định vây lại. Do độc phát quá gấp, Vương Thiền không màng đến nó và rút lui, khiến Hàn Lập thu được cả kim khô lâu lẫn phù bảo của mình; Vương Thiền phán đoán uy năng còn lại chỉ đủ dùng một hai lần.","nguon":["@c0262"]},{"id":"mac-giao-chi-doc","name":"Mạc Giao chi Độc","cn":"","aliases":["đan độc Hắc Giao"],"category":"khac","categoryLabel":"Độc","phamCap":"cực độc","soHuu":["Hàn Lập"],"trangThai":"Đã phát tác lên Vương Thiền","blurb":"Mạc Giao chi Độc là độc cực mạnh còn sót lại trong mê vụ của Thanh Hỏa Chướng. Độc theo Huyết Vân nhập vào người Vương Thiền khi hắn vận công, buộc hắn phải bỏ chạy.","detail":"Hàn Lập nhận ra Vương Thiền rút lui vì Huyết Vân đã hấp thu độc vụ do Thanh Hỏa Chướng từng phóng ra. Khi Vương Thiền dùng công pháp hút Huyết Vân vào thân, Mạc Giao chi Độc theo đó phát tác, khiến hắn sắc mặt xanh đen và phải nhờ hai trưởng lão họ Lý bức độc.","nguon":["@c0262"]},{"id":"trung-dieu-lenh","name":"Trưng Điệu Lệnh","cn":"","aliases":["Khả Trưng Điệu Du Lịch Đệ"],"category":"khac","categoryLabel":"Lệnh bài điều động","phamCap":"Không rõ","soHuu":["Tuyên Nhạc"],"trangThai":"đã sử dụng","blurb":"Văn thư điều động đệ tử đang du lịch do trưởng môn các phái ký.","detail":"Tuyên Nhạc dùng Trưng Điệu Lệnh để buộc Hàn Lập, một đệ tử Hoàng Phong Cốc đang ở ngoài, phải gia nhập đội chi viện linh khoáng. Hàn Lập kiểm tra và cho rằng lệnh này có vẻ là thật.","nguon":["@c0263"]},{"id":"co-quan-khoi-loi","name":"Cơ quan khôi lỗi","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi chiến đấu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Hơn mười khôi lỗi chiến đấu mà Hàn Lập đang sở hữu.","detail":"Hàn Lập xem số cơ quan khôi lỗi đã có là nền tảng để Đại Diễn Quyết nhanh chóng chuyển hóa thành sức tự bảo vệ trong chiến loạn, vì chỉ cần luyện thành một tầng cũng có thể điều khiển chúng hiệu quả hơn.","nguon":["@c0263"]},{"id":"binh-ngoc-nho-mau-vang-nhat","name":"Bình ngọc nhỏ màu vàng nhạt","cn":"","category":"khac","categoryLabel":"Vật chứa hồn phách","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Bình ngọc nhỏ Hàn Lập dùng để thu giữ hồn phách thằn lằn. Vật này chứa quang cầu màu xanh lục sau khi hắn thi triển Khiên Hồn Thuật.","detail":"Trong lần luyện thu hồn trên hoang nguyên, Hàn Lập lấy bình ngọc nhỏ màu vàng nhạt ra để hút quang cầu hồn phách màu xanh lục rút từ thi thể thằn lằn. Nó đóng vai trò vật chứa tạm cho hồn phách trước khi được xử lý trong quá trình luyện khôi lỗi.","nguon":["@c0264"]},{"id":"khoi-loi-cap-hai","name":"Khôi lỗi cấp hai","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"cấp hai","soHuu":["Hàn Lập"],"trangThai":"dự định luyện chế","blurb":"Cấp khôi lỗi Hàn Lập chuẩn bị thử luyện sau khi đã làm ra nhiều khôi lỗi sơ cấp. Loại này cần tài liệu ngang thượng giai pháp khí và hồn phách phù hợp hơn. (+) Hơn hai trăm con thú hình khôi lỗi cấp hai, luyện từ thiết mộc mấy trăm năm và hồn phách trong Tụ Hồn Bát, chuẩn bị cho việc săn yêu thú. [CAN-SOAT-GOP]","detail":"Sau vài chục lần luyện chế khôi lỗi sơ cấp, Hàn Lập quyết định thử chế luyện khôi lỗi cấp hai. Tài liệu chủ yếu được nhắc đến là thiết mộc mấy trăm năm, ngoài ra còn cần hồn phách đủ mạnh như hồn phách thằn lằn thay cho hồn phách sóc vàng quá yếu.","nguon":["@c0264","@c0392"],"tabs":{}},{"id":"cu-ho-khoi-loi","name":"Cự hổ khôi lỗi","cn":"","category":"khac","categoryLabel":"Khôi lỗi thú","phamCap":"ước đoán trên cấp ba","soHuu":["Hoàng Long"],"trangThai":"bị phá hủy","blurb":"Khôi lỗi thú uy lực lớn từng do Hoàng Long của Thiên Trúc Giáo cưỡi. Hàn Lập ước đoán nó trên cấp ba và tiếc vì đã bị Lôi sư bá đánh thành tro bụi.","detail":"Cự hổ khôi lỗi có uy lực lớn đến mức khi vận hành phải tiêu hao trung giai linh thạch, khác với cơ quan khôi lỗi cấp thấp chỉ dùng linh thạch cấp thấp. Nó từng là ấn tượng mạnh khiến Hàn Lập hứng thú với khôi lỗi cao cấp, nhưng đã bị Lôi sư bá dùng pháp bảo phá hủy.","nguon":["@c0264"]},{"id":"thiet-moc-may-tram-nam","name":"Thiết mộc mấy trăm năm","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khôi lỗi","phamCap":"ngang tài liệu thượng giai pháp khí","soHuu":["Hàn Lập"],"trangThai":"đang cần thu thập","blurb":"Nguyên liệu chủ yếu để Hàn Lập thử luyện khôi lỗi cấp hai. Do đang làm nhiệm vụ ở linh thạch khoáng, hắn phải nhờ người tại chợ xa thu thập thay vì tự trồng trong động phủ.","detail":"Thiết mộc mấy trăm năm được Hàn Lập xác định là tài liệu cần thiết cho khôi lỗi cấp hai. Nếu ở động phủ, hắn có thể tự trồng và thúc niên phận, nhưng hoàn cảnh hiện tại khiến hắn phải nhờ người tìm mua hoặc thu thập ở nơi xa.","nguon":["@c0264"]},{"id":"khoi-loi-thu-cap-hai-dau-tien-cua-han-lap","name":"Khôi lỗi thú cấp hai đầu tiên của Hàn Lập","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Cấp hai","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khôi lỗi thú cấp hai đầu tiên của Hàn Lập được luyện thành sau hơn mười lần thất bại. Dù còn thô lậu, nó đánh dấu việc Hàn Lập bắt đầu biến Khôi Lỗi Thuật thành thủ đoạn chiến đấu thực tế.","detail":"Trong thời gian trấn thủ linh khoáng, Hàn Lập vừa tu luyện Đại Diễn Quyết vừa thử luyện khôi lỗi. Sau hơn mười lần thất bại, hắn luyện thành con khôi lỗi thú cấp hai đầu tiên, tuy uy lực và độ tinh xảo kém khôi lỗi của Thiên Trúc Giáo nhưng mở ra khả năng chế tác số lượng lớn.","nguon":["@c0265"]},{"id":"khoi-loi-cap-hai-cua-thien-truc-giao","name":"Khôi lỗi cấp hai của Thiên Trúc Giáo","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Cấp hai","soHuu":["Thiên Trúc Giáo"],"trangThai":"không rõ","blurb":"Khôi lỗi cấp hai của Thiên Trúc Giáo được Hàn Lập dùng làm căn cứ đánh giá giới hạn Khôi Lỗi Thuật. Việc từng có mấy trăm con bị tu sĩ Kết Đan kỳ quét sạch khiến hắn hiểu khôi lỗi cấp thấp khó chống đại cảnh giới cao hơn.","detail":"Hàn Lập nhớ lại cảnh tu sĩ họ Lôi quét sạch mấy trăm khôi lỗi cấp hai của Thiên Trúc Giáo, từ đó suy đoán khôi lỗi cấp thấp dù số lượng lớn cũng chưa đủ uy hiếp Kết Đan kỳ.","nguon":["@c0265"]},{"id":"khoi-loi-cap-ba-tro-len","name":"Khôi lỗi cấp ba trở lên","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Cấp ba trở lên","soHuu":[],"trangThai":"suy đoán","blurb":"Khôi lỗi cấp ba trở lên là mức Hàn Lập suy đoán cần có nếu muốn dùng số lượng lớn để đối đầu tu sĩ Kết Đan kỳ. Chúng đòi hỏi tài liệu, hồn phách và công sức luyện chế vượt xa khôi lỗi cấp hai.","detail":"Khi đánh giá khả năng đối kháng Kết Đan kỳ bằng khôi lỗi, Hàn Lập cho rằng ít nhất phải có hàng trăm khôi lỗi cấp ba trở lên mới có hy vọng tạo sức ép. Điều này khiến Khôi Lỗi Thuật khó phổ biến vì chi phí quá cao.","nguon":["@c0265"]},{"id":"tai-lieu-thuong-giai-phap-khi","name":"Tài liệu thượng giai pháp khí","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"Thượng giai pháp khí","soHuu":[],"trangThai":"không rõ","blurb":"Tài liệu thượng giai pháp khí là loại vật liệu cần cho việc luyện khôi lỗi cấp hai. Việc khôi lỗi cấp hai đã đòi hỏi vật liệu ở mức này cho thấy chi phí luyện khôi lỗi rất lớn.","detail":"Hàn Lập suy xét rằng ngay cả luyện chế khôi lỗi cấp hai cũng cần tài liệu đạt mức thượng giai pháp khí. Đây là một nguyên nhân khiến Khôi Lỗi Thuật khó trở thành thủ đoạn phổ cập.","nguon":["@c0265"]},{"id":"tai-lieu-dinh-giai-phap-khi","name":"Tài liệu đỉnh giai pháp khí","cn":"","category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"Đỉnh giai pháp khí","soHuu":[],"trangThai":"suy đoán","blurb":"Tài liệu đỉnh giai pháp khí là mức vật liệu Hàn Lập suy đoán cần cho khôi lỗi cấp cao hơn cấp hai. Nhu cầu này khiến việc chế tạo đại lượng khôi lỗi mạnh trở nên cực khó.","detail":"Khi suy đoán về khôi lỗi cấp ba trở lên, Hàn Lập cho rằng tài liệu luyện chế tối thiểu phải đạt mức đỉnh giai pháp khí. Cùng với yêu cầu hồn phách, đây là rào cản lớn của Khôi Lỗi Thuật.","nguon":["@c0265"]},{"id":"dai-ky-do-ruc-kim-o-liet-duong","name":"Đại kỳ đỏ rực Kim ô liệt dương","cn":"","category":"phap-bao","categoryLabel":"Pháp khí/trận kỳ","phamCap":"không rõ","soHuu":["Hồng y nhân Ma Diễm môn / Cuồng diễm tu sĩ"],"trangThai":"đang sử dụng","blurb":"Đại kỳ đỏ rực Kim ô liệt dương là pháp khí/trận kỳ của đội Cuồng diễm tu sĩ Ma Diễm môn. Nó được dùng để thi triển Thanh dương ma hỏa trong trận công kích linh quáng.","detail":"Mỗi hồng y nhân Ma Diễm môn lấy ra một đại kỳ đỏ rực, trên mặt cờ có Kim ô liệt dương tỏa hồng quang. Khi nhóm này bày trận và niệm chú hoàn tất, ngọn lửa màu xanh trong đại kỳ hướng về phía Lữ Thiên Mông.","nguon":["@c0266"]},{"id":"vien-chau-mau-trang","name":"Viên châu màu trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Tu sĩ trung niên Thiên Sát tông"],"trangThai":"đang sử dụng","blurb":"Viên châu màu trắng là pháp khí của tu sĩ trung niên Thiên Sát tông. Khi được tung ra, nó đón gió lớn nhanh như căn phòng nhỏ và đánh xuống Hàn Lập.","detail":"Trong lúc giao thủ với Hàn Lập, tu sĩ trung niên Thiên Sát tông tức giận vì đối thủ phân tâm nên lấy viên châu trắng từ túi trữ vật ra. Pháp khí này nhanh chóng phóng lớn, tạo áp lực buộc Hàn Lập dùng kiếm quang và Ô long đoạt chống đỡ.","nguon":["@c0266"]},{"id":"tieu-kiem-bach-khiet-cua-tuyen-nhac","name":"Tiểu kiếm bạch khiết của Tuyên Nhạc","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Tuyên Nhạc"],"trangThai":"đang sử dụng","blurb":"Tiểu kiếm bạch khiết của Tuyên Nhạc là pháp khí trắng được dùng khi giữ tứ sát trận. Nó hóa thành cầu vồng để ngăn pháp khí Thiên Sát tông.","detail":"Khi Thiên Sát tông mở màn phá trận, Tuyên Nhạc vừa phân công lực lượng vừa tự mình xuất thủ. Tiểu kiếm trắng của y hóa cầu vồng, chặn một thanh phi đao và một pháp khí hình trái châu của địch.","nguon":["@c0266"]},{"id":"thanh-qua","name":"Thanh qua","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Tu sĩ trung niên Thiên Sát tông"],"trangThai":"đang sử dụng","blurb":"Thanh qua là pháp khí của tu sĩ trung niên Thiên Sát tông. Nó được dùng để giao đấu với Kim nhận của Hàn Lập trong trận giữ sát trận.","detail":"Tu sĩ trung niên Thiên Sát tông dùng Thanh qua đối đầu Kim nhận của Hàn Lập. Khi thế giao đấu không chiếm ưu thế, y mới tiếp tục tung viên châu màu trắng để tăng sức ép.","nguon":["@c0266"]},{"id":"phi-thien-ngo-cong","name":"Phi thiên ngô công","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"không rõ","soHuu":["Lữ Thiên Mông"],"trangThai":"bị chém nát","blurb":"Phi thiên ngô công là hai con rết bay của Lữ Thiên Mông, thân có sọc vàng đen và cánh xanh biếc. Chúng được thả ra để ngăn Ma Diễm môn thi pháp nhưng đều bị bóng trắng ẩn thân chém nát.","detail":"Khi nhận ra Cuồng diễm tu sĩ chuẩn bị phóng Thanh dương ma hỏa, Lữ Thiên Mông thả hai phi thiên ngô công lao vào nhóm hồng y nhân. Một con vừa phun độc vụ đã bị ngân sắc bí pháp cắt thành nhiều khối, con còn lại cũng chịu chung số phận.","nguon":["@c0266"]},{"id":"bach-lan-thuan","name":"Bạch lân thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Bị chém vỡ thành hai mảnh @c0340","blurb":"Bạch lân thuẫn là pháp khí phòng ngự từng được Hàn Lập sử dụng trong nhiều tình huống nguy cấp. Tại sơn động trong chương 340, nó đỡ đòn cho Hàn Lập nhưng bị quái vật chém nứt đôi, hư tổn hoàn toàn.","detail":"Bạch lân thuẫn là một pháp khí mang tính chất phòng ngự mà Hàn Lập từng xuất ra khi tiến vào những nơi nguy hiểm. Trong lần đối đầu với tu sĩ Thiên Sát Tông ngoài đại trận, Hàn Lập thu pháp khí khác lại, xuất Bạch lân thuẫn làm lá chắn và lợi dụng thế công của đối phương để bay ngược về phía Tứ sát trận, rút lui an toàn trước khi Thanh dương ma hỏa quét tới. Về sau, khi Hàn Lập mang nó vào sơn động, Bạch lân thuẫn đã đỡ đòn trước quái vật nhưng bị chém nứt đôi, rơi xuống thành hai mảnh, hư tổn không còn sử dụng được nữa.","nguon":["@c0267","@c0307","@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị quái vật phá hủy","text":"Bạch Lân thuẫn đỡ đòn trong sơn động nhưng bị quái vật chém nứt đôi và rơi xuống thành hai mảnh.","anchor":"Bạch Lân thuẫn che ở phía trước lại phát ra thêm một tiếng “Choang” nữa","phamCap":"Pháp khí"}]},"congNang":["Phòng ngự trước người khi Hàn Lập tiến vào nơi nguy hiểm @c0340"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0340","denChuong":"@c0340","cachCoDuoc":"Hàn Lập mang theo và thả ra phòng thân.","trangThai":"hỏng"}]},{"id":"khoi-loi-thu-than-lan","name":"Khôi lỗi thú thằn lằn","aliases":["Con rối hình dáng thằn lằn"],"cn":"","category":"phap-bao","categoryLabel":"Khôi lỗi","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Khôi lỗi hình thằn lằn được Hàn Lập dùng để dò đường sau vụ sập hầm. Nó chui ra trước, quan sát bốn phía rồi quay lại báo an toàn.","detail":"Sau khi đường hầm trong linh quáng sụp lở, con rối thằn lằn từ vách đá chui ra một hang động thiên nhiên, dò xét xung quanh rồi quay lại. Hàn Lập theo sau thoát ra, nhờ cách dùng khôi lỗi dò đường mà tránh tự mình lao vào nguy hiểm chưa rõ.","nguon":["@c0267"]},{"id":"ham-dia-phu","name":"Hám địa phù","cn":"","category":"khac","categoryLabel":"Trung cấp phù lục","phamCap":"trung cấp","soHuu":["Liên Phi Hoa","Hàn Lập"],"trangThai":"đã dùng","blurb":"Trung cấp phù lục hiếm được Liên Phi Hoa dùng trong cuộc phá hủy linh quáng. Việc sử dụng nó khiến Hoàng sam lão giả tiếc rẻ.","detail":"Liên Phi Hoa dùng Hám địa phù để gây sập phá, không muốn để người thất đại phái bình an thoát khỏi linh quáng. Hoàng sam lão giả cho rằng dùng trung cấp phù lục hiếm như vậy cho chuyện nhỏ là lãng phí, nhưng không dám can thiệp vì thân phận của nàng.","nguon":["@c0268","@c0361"],"tabs":{"tienTrinh":[{"chuong":"@c0361","loai":"dùng","importance":"normal","giaiDoan":"Ẩn dưới gò đất","text":"Hàn Lập dùng Hãm Địa Phù để ẩn dưới gò đất, chờ Đổng Huyên Nhi rời đi rồi mới hiện thân.","anchor":"chính mình chế tác một phù lục cấp thấp “Hãm Địa Phù” này lại có một ngày phải dùng đến"}]},"congNang":["Ẩn thân dưới đất @c0361"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0361","denChuong":"@c0361","cachCoDuoc":"tự chế tác và mang theo","trangThai":"đã dùng"}]},{"id":"dai-na-di-lenh","name":"Đại na di lệnh","cn":"","aliases":["Lệnh bài màu lam","Lệnh bài"],"category":"khac","categoryLabel":"Lệnh bài","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ @c0363","blurb":"Đại Na Di lệnh là lệnh bài màu lam phát ánh sáng nhàn nhạt, được tìm thấy trên tay năm hài cốt cạnh cổ truyền tống trận trong nhũ động. Hàn Lập sử dụng lệnh bài này để kích hoạt cổ truyền tống trận, đồng thời khiến phe ma đạo không thể truy đuổi do không sở hữu lệnh bài tương ứng.","detail":"Năm hài cốt ngồi cạnh lục giác truyền tống trận cổ đều cầm trên tay lệnh bài màu lam. Các lệnh bài này xuất hiện cùng truyền tống trận, quặng linh thạch và hài cốt tỏa ngũ sắc quang hoa, cho thấy mối liên hệ trực tiếp với bí mật của trận pháp cổ. Khi Hàn Lập sử dụng Đại Na Di lệnh để kích hoạt cổ truyền tống trận, lệnh bài đóng vai trò vừa là chìa khóa vận hành trận pháp, vừa là điều kiện ràng buộc khiến bất kỳ ai không sở hữu lệnh bài đều không thể dùng truyền tống trận để truy đuổi theo.","nguon":["@c0268","@c0363","@c0559"],"tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"dùng","importance":"major","giaiDoan":"Truyền tống thoát thân","text":"Hàn Lập dùng Đại Na Di lệnh khi kích hoạt cổ Truyền tống trận, khiến phe ma đạo không thể truy đuổi vì không có lệnh bài này.","anchor":"bất kỳ ai trong bọn chúng cũng không hề có ‘Đại na di’ lệnh nên không thể đuổi theo Hàn Lập được"}]},"congNang":["Hỗ trợ kích hoạt cổ truyền tống trận, là vật cần thiết để vận hành trận pháp @c0363","Là điều kiện ràng buộc của cổ truyền tống trận: người không sở hữu lệnh bài sẽ không thể sử dụng trận pháp để truy đuổi @c0363"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0363","denChuong":"","cachCoDuoc":"Đã có trong tay khi kích hoạt cổ Truyền tống trận","trangThai":"đang giữ"}],"dacDiem":"Lệnh bài màu lam, phát ánh sáng nhàn nhạt, được tìm thấy trên tay năm hài cốt cạnh cổ truyền tống trận trong nhũ động."},{"id":"tui-nhat-nguyet","name":"Túi nhật nguyệt","cn":"","category":"phap-bao","categoryLabel":"Pháp khí thu yêu thú","phamCap":"không rõ","soHuu":["Lữ Thiên Mông"],"trangThai":"hong","blurb":"Túi da màu xanh biếc của Lữ Thiên Mông, dùng để thu Bạch tri thù vào trong. Pháp khí không giữ nổi yêu thú và bị phá nổ từ bên trong.","detail":"Lữ Thiên Mông dùng Túi nhật nguyệt phóng ra ánh sáng mờ bao lấy Bạch tri thù rồi thu yêu thú vào túi, khiến nhóm tu sĩ tưởng đã khống chế được nó. Ngay sau đó, túi biến dạng dữ dội rồi nổ tung, để Bạch tri thù thoát ra trong trạng thái thân thể chuyển đỏ thành Huyết tri thù.","nguon":["@c0269"]},{"id":"gia-thien-chung","name":"Già thiên chung","cn":"","aliases":["Tiểu chung màu vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"luyện bằng đồng tinh","soHuu":["Tuyên Nhạc","Hàn Lập"],"trangThai":"dang-co","blurb":"Tiểu chung màu vàng của Tuyên Nhạc, có thể biến lớn để giam mục tiêu. Trong chương này nó từng nhốt Huyết tri thù nhưng không giữ được đến cuối.","detail":"Tuyên Nhạc tế Già thiên chung khi Huyết tri thù khựng lại trước thân pháp của Hàn Lập; chiếc chuông hóa lớn và úp yêu thú vào trong. Tuyên Nhạc tin chất liệu đồng tinh khiến yêu thú không thể thoát, song Huyết tri thù cuối chương vẫn phá khốn từ dưới đất sau lưng Lữ Thiên Mông.","nguon":["@c0269","@c0308"]},{"id":"phu-bao-tieu-thuoc-xanh","name":"Phù bảo tiểu thước xanh","cn":"","aliases":["Tiểu thước phù bảo"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo","soHuu":["Lữ Thiên Mông"],"trangThai":"không rõ","blurb":"Phù bảo lấp lóe thanh quang của Lữ Thiên Mông, hóa thành tiểu thước màu xanh. Hắn dùng nó trong màn phản bội Hàn Lập và Tuyên Nhạc.","detail":"Lữ Thiên Mông lấy cớ tế phù bảo để chuẩn bị đối phó Huyết tri thù, nhưng khi tiểu thước xanh thành hình và phân hóa thành hàng trăm tiểu thước, hắn quay sang định giết Hàn Lập và Tuyên Nhạc để độc chiếm bảo vật. Đòn đánh bị cắt ngang khi Huyết tri thù thoát khốn và chém đôi Lữ Thiên Mông.","nguon":["@c0269"]},{"id":"lua-mong-do","name":"Lụa mỏng đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phụ trợ","phamCap":"không rõ","soHuu":["Tuyên Nhạc"],"trangThai":"không rõ","blurb":"Lụa mỏng đỏ là pháp khí Tuyên Nhạc dùng để che giấu khí tức trong nhũ động.","detail":"Tuyên Nhạc khoác lụa mỏng đỏ lên người làm khí tức biến mất, khiến Huyết tri thù chuyển mục tiêu sang Hàn Lập trong lúc hắn đứng ngoài quan chiến.","nguon":["@c0270"]},{"id":"hoa-hong-ho-giap","name":"Hỏa hồng hộ giáp","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"đỉnh giai","soHuu":["Tuyên Nhạc"],"trangThai":"hong","blurb":"Hỏa hồng hộ giáp là pháp khí phòng ngự đỉnh giai của Tuyên Nhạc.","detail":"Tuyên Nhạc dồn linh lực vào hỏa hồng hộ giáp để chống Hàn Lập, nhưng hộ giáp bị pháp khí tự bạo luyện từ sừng Mặc giao phá thủng và thành phế phẩm.","nguon":["@c0270"]},{"id":"phap-khi-tu-bao-tu-sung-mac-giao","name":"Pháp khí tự bạo từ sừng Mặc giao","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm tiêu hao công kích","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Pháp khí tự bạo từ sừng Mặc giao là vật phẩm tiêu hao giúp Hàn Lập phá hủy phòng ngự của Tuyên Nhạc.","detail":"Hàn Lập phun pháp khí này ra trong khoảnh khắc áp sát, dùng sức tự bạo của nó phá thủng hỏa hồng hộ giáp, tạo thời cơ để thanh nguyên kiếm quang chém đầu Tuyên Nhạc.","nguon":["@c0270"]},{"id":"tui-tru-vat-cua-tuyen-nhac","name":"Túi trữ vật của Tuyên Nhạc","cn":"","category":"khac","categoryLabel":"Vật phẩm chứa đồ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Túi trữ vật của Tuyên Nhạc là chiến lợi phẩm Hàn Lập lấy sau khi giết Tuyên Nhạc.","detail":"Sau khi chém đầu Tuyên Nhạc, Hàn Lập thuận tay lấy túi trữ vật bên hông đối phương cùng các pháp khí liên quan.","nguon":["@c0270"]},{"id":"tui-tru-vat-cua-cac-thi-the","name":"Túi trữ vật của các thi thể","cn":"","category":"khac","categoryLabel":"Chiến lợi phẩm","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Túi trữ vật của các thi thể là số chiến lợi phẩm Hàn Lập thu trong nhũ động sau trận chiến.","detail":"Sau khi nghỉ lại, Hàn Lập lục lấy đồ trong các túi trữ vật trên những thi thể tu sĩ chết trong nhũ động trước khi tiến đến Truyền tống trận.","nguon":["@c0270"]},{"id":"ngoc-gian-sao-chep-co-tran","name":"Ngọc giản sao chép cổ trận","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm ghi chép","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản được Hàn Lập dùng để ghi lại dạng thức và hoa văn của Cổ Truyền tống trận. Nó phục vụ kế hoạch tìm người sửa chữa trận pháp bị hư hại.","detail":"Sau khi phát hiện một góc Truyền tống trận trong hang đã hư, Hàn Lập lấy ngọc giản sao chép lại dạng thức và hoa văn của trận. Việc này giúp hắn giữ tư liệu để sau này tìm người am hiểu trận pháp xem có thể sửa chữa hay không.","nguon":["@c0271"]},{"id":"trung-nhen-yeu-thu","name":"Trứng nhện yêu thú","cn":"","aliases":[],"category":"khac","categoryLabel":"Trứng linh thú/yêu thú","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai quả trứng trong suốt bằng nắm tay được Hàn Lập phát hiện trong hang. Hắn mang chúng về đặt vào Linh nhãn chi tuyền để linh khí nuôi dưỡng.","detail":"Hàn Lập tìm thấy hai quả trứng trong suốt sau một cột đá lớn, nhận ra chúng là trứng của nhện yêu thú từng rất lợi hại. Hắn dùng túi da lấy từ tu sĩ Linh Thú sơn để cất giữ, rồi đem về động phủ ngâm trong Linh nhãn chi tuyền nhằm chậm rãi ấp nở bằng linh khí.","nguon":["@c0271"]},{"id":"tui-da-linh-thu-son","name":"Túi da Linh Thú sơn","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa linh thú","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Túi da lấy từ túi trữ vật của một tu sĩ Linh Thú sơn. Hàn Lập dùng nó để chứa hai trứng nhện yêu thú.","detail":"Trong lúc thu giữ trứng nhện yêu thú, Hàn Lập dùng một túi da đẹp lấy từ túi trữ vật của tu sĩ Linh Thú sơn. Vật này được dùng như đồ chứa thích hợp để mang trứng yêu thú rời khỏi hang.","nguon":["@c0271"]},{"id":"hat-chau-nhieu-mau-tu-hai-cot-ngu-sac","name":"Hạt châu nhiều màu từ hài cốt ngũ sắc","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm lạ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bảy tám hạt châu nhiều màu xuất hiện sau khi Hàn Lập thiêu đốt hài cốt ngũ sắc. Công dụng của chúng trong chương này chưa rõ.","detail":"Khi Hàn Lập dùng hỏa cầu thiêu đốt hài cốt ngũ sắc trong hang, sau lửa lại ngưng kết ra bảy tám hạt châu nhiều màu. Hàn Lập kinh ngạc trước vật lạ này và thu giữ, nhưng chương này chưa giải thích công dụng cụ thể.","nguon":["@c0271"]},{"id":"linh-nhan-chi-tuyen","name":"Linh nhãn chi tuyền","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh vật/nguồn linh khí","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Con suối linh tuyền trong mật thất động phủ cũ của Hàn Lập tại Thái Nhạc Sơn Mạch, phát tán linh khí trắng kinh người. (+) Nguồn linh khí trong động phủ của Hàn Lập. Chương này được dùng để ngâm và nuôi dưỡng hai trứng nhện yêu thú. [CAN-SOAT-GOP]","detail":"Khi trở lại động phủ, Hàn Lập đem trứng nhện yêu thú nhúng chìm vào Linh nhãn chi tuyền. Linh khí từ nguồn này chậm rãi nuôi dưỡng trứng, tạo điều kiện cho chúng ấp nở về sau.","nguon":["@c0271","@c0655"],"tabs":{}},{"id":"tinh-huyet-cua-han-lap","name":"Tinh huyết của Hàn Lập","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu khống chế","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Tinh huyết được Hàn Lập nhỏ vào pháp trận khống thần. Hai trứng nhện hấp thu nó để phục vụ việc khống chế yêu thú non.","detail":"Trong động phủ, Hàn Lập dùng vài giọt tinh huyết kết hợp pháp trận khống thần rồi đặt hai trứng nhện vào trong trận, sau đó mới đưa chúng trở lại Linh nhãn chi tuyền.","nguon":["@c0272"]},{"id":"phu-truyen-am","name":"Phù truyền âm","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"không rõ","soHuu":["Hoàng Phong Cốc"],"trangThai":"đã dùng","blurb":"Phù lục truyền tin gọi Hàn Lập tới Nghị Sự điện. Nó báo hiệu nhiệm vụ chiến trường của hắn bắt đầu.","detail":"Ngay sau khi Hàn Lập hoàn tất việc khống chế trứng nhện, phù truyền âm đến yêu cầu hắn nhanh chóng tập hợp tại Nghị Sự điện, khiến hắn hiểu nhiệm vụ môn phái đã tới.","nguon":["@c0272"]},{"id":"hai-dao-hac-quang","name":"Hai đạo hắc quang","cn":"","category":"phap-bao","categoryLabel":"Pháp khí/đòn tấn công","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Hai đạo hắc quang được Hàn Lập điều khiển trong chiến đấu. Chúng phối hợp với kim nhận vây công đệ tử Trúc Cơ sơ kỳ Quỷ Linh môn.","detail":"Trên chiến trường Kim Cổ nguyên, Hàn Lập dùng hai đạo hắc quang biến hóa như ô long, kết hợp vài lưỡi kim nhận tấn công dồn dập để phá phòng thủ của đối thủ Quỷ Linh môn.","nguon":["@c0272"]},{"id":"long-ngam-thao","name":"Long Ngâm thảo","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"quý hiếm","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Linh thảo Hàn Lập đổi bằng năm trăm linh thạch từ Trần mập. Nó được đặt trong hộp ngọc và là một thu hoạch quý tại khu giao dịch doanh trại.","detail":"Sau khi bán chiến lợi phẩm để gom đủ linh thạch, Hàn Lập đến quầy của Trần mập và đổi lấy Long Ngâm thảo. Giao dịch này cho thấy khu chợ tiền tuyến có nhiều vật phẩm hiếm mà bình thường khó gặp.","nguon":["@c0272"]},{"id":"hop-ngoc","name":"Hộp ngọc","cn":"","category":"khac","categoryLabel":"Vật phẩm chứa linh thảo","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Vật chứa Long Ngâm thảo Trần mập giao cho Hàn Lập. Nó xuất hiện trong giao dịch năm trăm linh thạch tại doanh trại.","detail":"Trần mập lấy ra một hộp ngọc chứa Long Ngâm thảo và đưa cho Hàn Lập sau khi nhận đủ năm trăm linh thạch.","nguon":["@c0272"]},{"id":"phuong-thuoc-co","name":"Phương thuốc cổ","cn":"","aliases":["Hai phương thuốc cổ"],"category":"khac","categoryLabel":"Đan phương","phamCap":"cổ phương","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Hai đan phương cổ Hàn Lập từng mua từ Trần mập với giá gần ngàn linh thạch. Tuy bị xem gần như bỏ đi, chúng lại khiến Hàn Lập rất kinh hỉ.","detail":"Trong lúc tiếp tục tìm đan phương hữu dụng cho Trúc Cơ kỳ, Hàn Lập nhớ rằng mình từng mua được hai phương thuốc cổ hiếm từ Trần mập. Đây là một trong những thu hoạch khiến hắn đánh giá cao khu giao dịch doanh trại.","nguon":["@c0272"]},{"id":"phu-bao","name":"Phù bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phù lục","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Phù bảo là một trong các chỗ dựa chiến đấu quan trọng của Hàn Lập trong chiến trường Trúc Cơ. Kết hợp với Đại Diễn quyết, nó giúp hắn thoát thân trước đối thủ mạnh hơn và giết nhiều tu sĩ ma đạo yếu hơn.","detail":"Ở chương 273, Hàn Lập được nhắc có vài kiện phù bảo trong tay. Nhờ chúng cùng Đại Diễn quyết, hắn có thể bảo toàn khi gặp tu sĩ Trúc Cơ hậu kỳ và chiếm ưu thế lớn trước Trúc Cơ sơ kỳ, trung kỳ ma đạo.","nguon":["@c0273"]},{"id":"duoc-thao-bon-tram-nam","name":"Dược thảo bốn trăm năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"bốn trăm năm","soHuu":["Hàn Lập"],"trangThai":"đã dùng để trao đổi","blurb":"Hai gốc dược thảo bốn trăm năm được Hàn Lập mạo hiểm lấy ra để đổi tài nguyên. Chúng góp phần giúp hắn gom đủ nguyên liệu cho các phương thuốc cổ.","detail":"Trong quá trình thu thập nguyên liệu cổ phương, Hàn Lập không chỉ vét linh thạch mà còn xuất ra hai gốc dược thảo bốn trăm năm. Việc này được mô tả là mạo hiểm, nhưng đổi lại giúp hắn hoàn tất phần lớn nhu cầu nguyên liệu.","nguon":["@c0273"]},{"id":"ngoc-gian-tu-lieu-gia-dinh-hau-nhan-an-nhan","name":"Ngọc giản tư liệu gia đình hậu nhân ân nhân","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản do Lý Hóa Nguyên giao cho Hàn Lập trước khi hắn rời đi làm nhiệm vụ hộ vệ. Bên trong chứa tư liệu về gia đình phàm tục cần được bảo vệ.","detail":"Khi giao nhiệm vụ bảo vệ hậu nhân của ân nhân, Lý Hóa Nguyên đưa cho Hàn Lập ngọc giản chứa tư liệu về gia đình nọ. Vật này giúp Hàn Lập nắm tình hình trước khi tới Việt đô liên hệ gia chủ đương đại.","nguon":["@c0274"]},{"id":"bo-phap-khi-bo-tran-dien-dao-ngu-hanh-tran-cai-tien","name":"Bộ pháp khí bố trận Điên Đảo Ngũ Hành trận cải tiến","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bố trận","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập nhận từ Tề Vân Tiêu","blurb":"Bộ trận kỳ và trận bàn do Tề Vân Tiêu cải tiến từ Điên Đảo Ngũ Hành trận. Uy lực đạt khoảng một phần ba trận pháp nguyên bản, mạnh hơn bản trước nhiều.","detail":"Tề Vân Tiêu giao cho Hàn Lập một hộp gỗ chứa nhiều trận kỳ và trận bàn linh khí bức người, số lượng nhiều hơn bộ cũ và hoa văn cũng phức tạp hơn. Theo lời Tề Vân Tiêu, uy lực bộ cải tiến tuy không đạt một nửa trận pháp nguyên bản như dự tính, nhưng đã tăng tới một phần ba, khiến Hàn Lập rất hài lòng vì có thể dùng làm thủ đoạn phòng ngự quan trọng.","nguon":["@c0275"]},{"id":"ngoc-boi-xanh-trong-suot","name":"Ngọc bội xanh trong suốt","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng làm tín vật","blurb":"Ngọc bội xanh trong suốt Hàn Lập lấy ra tại trà quán. Vật này giúp chưởng quầy nhận ra hắn là Hàn tiền bối mà Tề Vân Tiêu đã dặn chờ.","detail":"Khi gặp chưởng quầy, Hàn Lập đặt ngọc bội xanh trong suốt lên mặt bàn. Chưởng quầy vừa thấy tín vật liền đổi thái độ, nhận ra thân phận Hàn tiền bối và dẫn hắn tới nơi ở của Tề Vân Tiêu.","nguon":["@c0275"]},{"id":"tra-linh-khi","name":"Trà linh khí","cn":"","category":"khac","categoryLabel":"Trà linh tính","phamCap":"không rõ","soHuu":["Tề Vân Tiêu","Người bạn tặng trà của Tề Vân Tiêu"],"trangThai":"được dùng đãi khách","blurb":"Loại trà xanh thơm có chứa linh khí, khiến Hàn Lập chú ý ngay từ trà quán. Lá trà do bạn tốt của Tề Vân Tiêu mất mười năm nghiên cứu ở thế gian rồi tặng lại.","detail":"Hương trà trong trà quán mang linh khí nhàn nhạt khiến Hàn Lập bước vào tìm hiểu. Về sau, chưởng quầy dâng hai chén trà xanh có hương thơm và linh khí đậm hơn; Hàn Lập khen kỳ diệu, còn Tề Vân Tiêu giải thích trà này không phải do hắn chế ra mà là quà của một người bạn.","nguon":["@c0275"]},{"id":"linh-thao-ngan-nam","name":"Linh thảo ngàn năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"Ngàn năm","soHuu":["Hàn Lập"],"trangThai":"Đã dùng làm thuốc dẫn","blurb":"Linh thảo ngàn năm của Hàn Lập từng được dùng làm thuốc dẫn để giữ mạng chí hữu của Tề Vân Tiêu.","detail":"Trong lời Tề Vân Tiêu, linh thảo ngàn năm mà Hàn Lập từng đưa ra đã giúp bảo vệ tính mạng của Tân Như Âm. Tuy vậy thương thế của nàng vẫn chưa khỏi hẳn, khiến Tề Vân Tiêu tiếp tục cầu thêm linh thảo lâu năm.","nguon":["@c0276"]},{"id":"linh-thao-lau-nam","name":"Linh thảo lâu năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"Lâu năm","soHuu":["Hàn Lập"],"trangThai":"Đang có","blurb":"Linh thảo lâu năm trong tay Hàn Lập là thứ Tề Vân Tiêu muốn đổi để chữa dứt thương thế cho chí hữu.","detail":"Hàn Lập nói trong tay còn một ít linh thảo vốn định dùng luyện đan. Tề Vân Tiêu vì muốn chữa thương cho Tân Như Âm nên khẩn cầu nhượng lại, thậm chí nguyện dùng các loại trận kỳ để trao đổi.","nguon":["@c0276"]},{"id":"tran-ky-cua-te-van-tieu","name":"Trận kỳ của Tề Vân Tiêu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí bố trận","phamCap":"Không rõ","soHuu":["Tề Vân Tiêu"],"trangThai":"Đang có","blurb":"Các loại trận kỳ mà Tề Vân Tiêu đề nghị đem ra trao đổi linh thảo lâu năm với Hàn Lập.","detail":"Tề Vân Tiêu sẵn sàng dùng nhiều loại trận kỳ đổi linh thảo để cứu chí hữu. Hàn Lập đánh giá nếu có được mấy bộ trận kỳ này, năng lực phòng hộ sẽ tăng mạnh, thậm chí có thể dùng trận pháp công kích để vây giết cường địch.","nguon":["@c0276"]},{"id":"tieu-chu","name":"Tiểu chu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phi hành","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Tiểu chu là pháp khí phi hành Hàn Lập dùng để chở cả nhóm rời khỏi hiện trường. Nó đưa Hàn Lập, Tân Như Âm, Tề Vân Tiêu và nha hoàn bay về hướng Tây Bắc đến chỗ ở của Tân Như Âm.","detail":"Sau khi xử lý hiện trường, Hàn Lập dùng tiểu chu đưa Tân Như Âm, Tề Vân Tiêu và nha hoàn rời đi, tránh nguy cơ trưởng bối của nhóm bị giết xuất hiện. Trên đường, tiểu chu đổi hướng Tây Bắc theo lời mời của Tân Như Âm để đến nơi nàng cư trú.","nguon":["@c0277"]},{"id":"tui-tru-vat-cua-nhom-da-chet","name":"Túi trữ vật của nhóm đã chết","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Nha hoàn xinh đẹp của Tân Như Âm"],"trangThai":"đã thu nhặt","blurb":"Các túi trữ vật còn lại sau khi Hàn Lập thiêu sạch thi thể nhóm truy đuổi Tân Như Âm. Hàn Lập để nha hoàn của Tân Như Âm nhặt lấy nhằm vừa tránh lộ dấu vết vừa cho nàng hưởng lợi.","detail":"Khi các thi thể bị hỏa cầu thiêu thành tro, những túi trữ vật vẫn còn sót lại trên mặt đất. Hàn Lập không tự lấy mà ra hiệu để nha hoàn xinh đẹp của Tân Như Âm thu nhặt, khiến nàng vui mừng vì đây là khoản thu bất ngờ.","nguon":["@c0277"]},{"id":"tran-ky-va-tran-ban-cua-te-van-tieu","name":"Trận kỳ và trận bàn của Tề Vân Tiêu","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm trận pháp","phamCap":"không rõ","soHuu":["Tề Vân Tiêu"],"trangThai":"đang có","blurb":"Các bộ trận kỳ và trận bàn do Tề Vân Tiêu từng luyện chế. Sau khi Hàn Lập cứu Tân Như Âm, Tề Vân Tiêu nhắc lại lời hứa để Hàn Lập có thể tự do chọn lấy.","detail":"Tề Vân Tiêu xem việc Hàn Lập cứu Tân Như Âm là đủ để thực hiện lời hứa trước đó. Hắn chủ động nói Hàn Lập có thể tùy ý chọn trong các trận kỳ và trận bàn mình đã luyện chế, nhưng Hàn Lập lại chuyển sang đề nghị nhờ Tân Như Âm giúp một việc khác.","nguon":["@c0277"]},{"id":"linh-thao-tam-tram-nam","name":"Linh thảo tám trăm năm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo luyện đan","phamCap":"tám trăm năm","soHuu":["Hàn Lập"],"trangThai":"được đưa làm điều kiện giao dịch","blurb":"Linh thảo tám trăm năm được Hàn Lập đưa ra làm thù lao để Tân Như Âm chữa bệnh. Đây là điều kiện khiến Tề Vân Tiêu đặc biệt kích động vì mở ra hy vọng chữa khỏi cho người hắn yêu.","detail":"Cuối chương, Hàn Lập không vội nhận trận kỳ, trận bàn mà nêu đề nghị khác: nếu Tân Như Âm giúp hắn giải quyết việc riêng, hắn sẽ đưa một gốc linh thảo tám trăm năm dùng luyện đan cho nàng chữa bệnh. Vật này trở thành mấu chốt giao dịch giữa Hàn Lập và Tân Như Âm.","nguon":["@c0277"]},{"id":"ngoc-gian-chua-ban-ve-co-truyen-tong-tran","name":"Ngọc giản chứa bản vẽ cổ truyền tống trận","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"được giao cho Tân Như Âm xem xét","blurb":"Ngọc giản chứa hình dạng phục chế của cổ truyền tống trận mà Hàn Lập không thể trực tiếp di chuyển.","detail":"Hàn Lập đưa ngọc giản này cho Tân Như Âm để nàng xem xét và phục hồi bản vẽ cổ truyền tống trận. Nó là căn cứ giúp Tân Như Âm nhận ra trận pháp cổ và đánh giá mức độ hư hại.","nguon":["@c0278"]},{"id":"linh-thao-chua-benh-cua-tan-nhu-am","name":"Linh thảo chữa bệnh của Tân Như Âm","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thảo","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"được hứa giao nếu phục hồi bản vẽ","blurb":"Linh thảo Hàn Lập dùng làm điều kiện để nhờ Tân Như Âm chữa trị bản vẽ trận pháp.","detail":"Hàn Lập hứa sẽ hai tay dâng linh thảo cho Tân Như Âm nếu nàng có thể phục hồi vật liên quan đến trận pháp. Vật này trực tiếp thúc đẩy thỏa thuận nửa năm giữa hai bên.","nguon":["@c0278"]},{"id":"phong-thu-gui-tan-ngon","name":"Phong thư gửi Tần Ngôn","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"Phàm vật","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Phong thư Hàn Lập mang tới Tần trạch để gặp Tần Ngôn. Nội dung và cách đề chữ trên bì thư khiến hạ nhân Tần gia không dám coi thường người cầm thư.","detail":"Phong thư nhăn nhúm ghi gửi Tần Ngôn với khẩu khí trưởng bối. Đây là căn cứ để Lý Hóa Nguyên sắp xếp cho Hàn Lập thân phận hậu nhân chi phụ Tần gia, đồng thời giúp Hàn Lập được đưa vào phủ chờ gia chủ xác minh.","nguon":["@c0279"]},{"id":"thiep-moi-cua-hinh-vuong","name":"Thiếp mời của Hinh Vương","cn":"","category":"khac","categoryLabel":"Vật phẩm xã giao","phamCap":"Phàm tục","soHuu":["Hinh Vương","Tần Ngôn"],"trangThai":"đã gửi tới Tần gia","blurb":"Thiếp mời dự tiệc do Hinh Vương gửi tới Tần gia. Thiếp liên quan đến đại tiệc mừng ái phi khỏi bệnh và chỉ danh một số hậu bối Tần gia cùng đi.","detail":"Hinh Vương gửi thiếp mời Tần Ngôn dự tiệc mừng ái phi khỏi bệnh, đồng thời có lời mời vài công tử giao du rộng và vài tài nữ Tần gia. Vì vậy Tần Ngôn dù đang cấm túc hậu bối do lo nguy cơ Ma Đạo vẫn phải cho họ đi cùng.","nguon":["@c0285"]},{"id":"ho-tam-hoan","name":"Hộ Tâm Hòan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"thuốc quý phàm tục","soHuu":["Hàn Lập"],"trangThai":"đang do Hàn Lập giữ","blurb":"Hộ Tâm Hòan là bình thuốc do Hoa lão ca cẩn thận điều chế và tặng Hàn Lập làm vật phòng thân. Thuốc có danh tiếng không nhỏ trong giới phàm tục Việt Kinh.","detail":"Hoa lão ca giới thiệu Hộ Tâm Hòan có thể trị bệnh hoặc vết thương bình thường. Khi lão tặng bình thuốc này cho Hàn Lập, phản ứng chú ý, hâm mộ và giật mình của người quanh đó cho thấy danh tiếng của thuốc rất lớn.","nguon":["@c0286"]},{"id":"dao-thu","name":"Đạo thư","cn":"","category":"khac","categoryLabel":"Sách đạo pháp","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Không được chọn","blurb":"Một trong các lựa chọn trao đổi mà Hàn Lập đưa ra cho lão đạo đầu bạc khi nhận Lộng Diễm quyết. Lão đạo không chọn đạo thư mà chọn đan dược phá bình cảnh.","detail":"Đạo thư được Hàn Lập nêu như phần thưởng có thể dùng để đổi lấy Lộng Diễm quyết. Việc đặt đạo thư ngang với pháp khí và đan dược cho thấy Hàn Lập muốn trao đổi sòng phẳng, nhưng lão đạo ưu tiên thứ có thể giúp vượt bình cảnh Luyện Khí.","nguon":["@c0294"]},{"id":"phap-khi-cac-cap","name":"Pháp khí các cấp","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Nhiều cấp","soHuu":["Hàn Lập"],"trangThai":"Không được chọn","blurb":"Nhóm pháp khí mà Hàn Lập đưa ra làm lựa chọn trao đổi cho lão đạo đầu bạc. Lão đạo không chọn pháp khí vì muốn đan dược phá bình cảnh hơn.","detail":"Pháp khí các cấp được Hàn Lập đề nghị như một trong ba loại vật có thể đổi lấy Lộng Diễm quyết. Lựa chọn này cho thấy Hàn Lập có sẵn vật dụng thích hợp cho tu sĩ Luyện Khí, nhưng nhu cầu cấp thiết của lão đạo là đan dược hỗ trợ tu luyện.","nguon":["@c0294"]},{"id":"quyen-sach-da-mau-vang-da-den","name":"Quyển sách da màu vàng đã đen","cn":"","aliases":["Quyển sách vô danh không đầy đủ","Quyển sách thâm ảo của ông cháu họ Tiêu"],"category":"khac","categoryLabel":"Sách cổ","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập thu lấy","blurb":"Sách cổ bằng chất liệu bền chắc giống da yêu thú đặc chế. Phần đầu chứa thượng cổ văn tự Hàn Lập chưa hiểu, hai trang cuối có khẩu quyết vô danh thu liễm hơi thở.","detail":"Quyển sách vốn do Tiêu Chấn cất trong hộp gỗ cũ và giao cho Hàn Lập để xoa dịu tình thế. Hàn Lập đọc được phần khẩu quyết ở cuối, đánh giá có ích, rồi cất sách vào hộp ngọc trong túi trữ vật.","nguon":["@c0296"]},{"id":"ngoc-bai","name":"Ngọc bài","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Thiếu nữ họ Tiêu"],"trangThai":"đang lưu giữ","blurb":"Tín vật Hàn Lập giao cùng Truyền Âm phù cho cô gái họ Tiêu. Vật này dùng để nàng đến Bách Dược viên Hoàng Phong cốc tìm Mã sư huynh.","detail":"Hàn Lập đưa ngọc bài kèm Truyền Âm phù sau khi từ chối nhận cô gái họ Tiêu làm đồ đệ. Nó là vật giới thiệu giúp nàng có cơ hội bái nhập môn hạ vị tiền bối họ Mã, còn thành bại tùy vào đối phương có hài lòng với nàng hay không.","nguon":["@c0297"]},{"id":"dai-lua-theu-kim-tuyen","name":"Dải lụa thêu kim tuyến","cn":"","category":"phap-bao","categoryLabel":"Thượng cấp pháp khí","phamCap":"Thượng cấp pháp khí","soHuu":["Thiếu nữ họ Tiêu"],"trangThai":"đang lưu giữ","blurb":"Một trong hai thượng cấp pháp khí Hàn Lập tặng cho hai ông cháu họ Tiêu. Tiêu Chấn sau đó giao dải lụa này cho cháu gái.","detail":"Dải lụa thêu kim tuyến được Hàn Lập lấy ra để bồi thường vì việc giới thiệu bái sư chưa chắc thành công. Sau khi Hàn Lập rời đi, lão giả họ Tiêu chia dải lụa cho cháu gái sử dụng.","nguon":["@c0297"]},{"id":"tieu-kiem-mau-lam","name":"Tiểu kiếm màu lam","cn":"","category":"phap-bao","categoryLabel":"Thượng cấp pháp khí","phamCap":"Thượng cấp pháp khí","soHuu":["Tiêu Chấn"],"trangThai":"đang lưu giữ","blurb":"Một trong hai thượng cấp pháp khí Hàn Lập tặng cho hai ông cháu họ Tiêu. Tiêu Chấn giữ lại tiểu kiếm này sau khi chia dải lụa cho cháu gái.","detail":"Tiểu kiếm màu lam được Hàn Lập tặng cùng dải lụa thêu kim tuyến. Đây là phần pháp khí Tiêu Chấn giữ lại khi chuẩn bị đưa cháu gái đến Hoàng Phong cốc tìm cơ hội bái sư.","nguon":["@c0297"]},{"id":"phi-dao-mau-lam","name":"Phi đao màu lam","cn":"","category":"phap-bao","categoryLabel":"Thượng cấp pháp khí","phamCap":"thượng cấp pháp khí","soHuu":["Nữ tử bịt mặt"],"trangThai":"bị buông bỏ khi chủ nhân bị bắt","blurb":"Phi đao màu lam là thượng cấp pháp khí quý giá của nữ tử bịt mặt. Nàng dùng nó đối phó con rối cầm trường đao nhưng nhiều lần bị đánh bật.","detail":"Nữ tử bịt mặt cho rằng phi đao màu lam là pháp khí quý giá đổi bằng toàn bộ tích cóp của mình. Trong trận bị khôi lỗi chặn đường, phi đao liên tục chém về phía con rối cầm đao nhưng đều bị trường đao ánh vàng đánh bật, cuối cùng nàng buông pháp khí khi thấy đồng bọn đã bị khống chế.","nguon":["@c0298"]},{"id":"con-roi-binh-linh-cam-cung","name":"Con rối binh lính cầm cung","cn":"","category":"khac","categoryLabel":"Khôi lỗi chiến đấu","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Con rối binh lính cầm cung là khôi lỗi Hàn Lập dùng để chặn nữ tử bịt mặt. Nó bắn mũi tên ánh sáng đỏ và phối hợp với con rối cầm trường đao.","detail":"Con rối mặc giáp như binh lính, cầm cung lớn và bắn mũi tên ánh sáng đỏ khiến nữ tử bịt mặt buộc phải phòng thủ. Nó giữ vai trò tấn công tầm xa trong thế phối hợp xa gần của Hàn Lập, ép đối thủ quay lại vị trí cũ.","nguon":["@c0298"]},{"id":"con-roi-binh-linh-cam-truong-dao","name":"Con rối binh lính cầm trường đao","cn":"","category":"khac","categoryLabel":"Khôi lỗi chiến đấu","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Con rối binh lính cầm trường đao là khôi lỗi cận chiến của Hàn Lập. Nó áp sát nữ tử bịt mặt và đánh bật phi đao màu lam nhiều lần.","detail":"Con rối này mặc giáp, cầm trường đao ánh vàng và phối hợp cùng con rối cầm cung. Khi nữ tử bịt mặt dùng phi đao màu lam công kích, nó nhiều lần xuất đao đánh bay pháp khí, khiến nàng không thể thoát khỏi vòng vây.","nguon":["@c0298"]},{"id":"hai-binh-dan-duoc-trang-va-xanh","name":"Hai bình đan dược trắng và xanh","cn":"","category":"dan-duoc","categoryLabel":"Đan dược giải độc","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng một phần","blurb":"Hai bình đan dược trắng và xanh được Hàn Lập lấy ra để giải phần lớn độc tính cho bốn thành viên Mông Sơn ngũ hữu. Mỗi người uống một viên từ mỗi bình rồi tự vận công bức tàn độc về sau.","detail":"Khi phát hiện ngoài huyết chú còn có kịch độc trong người Mông Sơn ngũ hữu, Hàn Lập lấy hai bình đan dược từ túi trữ vật giao cho lão giả mặt đen. Thuốc khiến bốn người đau bụng dữ dội và bài tiết độc vật, nhưng có thể xua đại bộ phận độc tính trước khi xử lý huyết chú.","nguon":["@c0301"]},{"id":"khoi-loi-binh-si","name":"Khôi lỗi binh sĩ","cn":"","category":"phap-bao","categoryLabel":"Khôi lỗi cảnh giới","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Khôi lỗi binh sĩ là nhóm khôi lỗi kích thước như người thật do Hàn Lập thả ra trước khi giải huyết chú. Chúng cầm binh khí và tự công kích bất cứ ai tiến vào phạm vi mười trượng quanh hắn.","detail":"Trước lúc thử giải huyết chú cho lão giả mặt đen, Hàn Lập gọi ra sáu bảy khôi lỗi binh sĩ để cảnh giới. Việc bố trí này cho thấy hắn vẫn đề phòng Mông Sơn ngũ hữu dù đã buộc họ tạm thời nghe lệnh.","nguon":["@c0301"]},{"id":"hop-nho-cua-ngu-muoi","name":"Hộp nhỏ của ngũ muội","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm nghi vấn","phamCap":"không rõ","soHuu":["Ngũ muội"],"trangThai":"đang bị yêu cầu giao cho Hàn Lập","blurb":"Chiếc hộp nhỏ Ngũ muội lén lấy ra trong đêm tại Thanh Âm viện. Vật này khiến Hàn Lập và lão giả mặt đen cùng chú ý.","detail":"Ngũ muội giấu hộp nhỏ trong áo, lén ra góc tường định mở sau khi trời tối hẳn. Hàn Lập xuất hiện phía sau, lão giả mặt đen cùng những người khác cũng cầm Nguyệt Quang thạch đi ra, khiến nàng bị phát hiện và bị buộc giao hộp cho Hàn Lập.","nguon":["@c0303"]},{"id":"an-nac-phu","name":"Ẩn Nặc phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập","Ngũ muội"],"trangThai":"đã dùng","blurb":"Phù lục Hàn Lập đưa cho Ngũ muội khi thả nàng, giúp nàng tạm ẩn nấp trong lúc bỏ trốn.","detail":"Ngũ muội dùng Ẩn Nặc phù để tránh Lão Nhị truy đuổi sau khi rời Tần trạch. Vật này cũng nằm trong bố cục của Hàn Lập, vì việc nàng bỏ trốn khiến hậu thủ Vô Thường đan phát tác.","nguon":["@c0305"]},{"id":"vo-thuong-dan","name":"Vô Thường đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Đan dược vừa có thể giải độc vừa có thể qua thủ pháp đặc thù chuyển thành kịch độc.","detail":"Hai bình Vô Thường đan vốn được dùng như thánh dược giải độc cho Mông Sơn ngũ hữu. Hàn Lập âm thầm đặt cấm chế khi giải huyết chú cho Ngũ muội, sau đó kích phát để dược lực còn sót lại chuyển thành kịch độc, khiến nàng chết trên đường tới cứ điểm Hắc Sát giáo.","nguon":["@c0305"]},{"id":"khoi-loi-to-lon-cua-han-lap","name":"Khôi lỗi to lớn của Hàn Lập","cn":"","category":"khac","categoryLabel":"Khôi lỗi chiến đấu","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Bốn khôi lỗi lớn được Hàn Lập điều ra để công phá trận pháp quanh miếu hoang.","detail":"Các khôi lỗi bắn ra cột sáng to như miệng bát vào màn hào quang của Lạc Thạch trận, phối hợp với Ô long đoạt để phá vỡ lớp phòng hộ.","nguon":["@c0306"]},{"id":"co-lon-mau-den-hac-phong-tran","name":"Cờ lớn màu đen Hắc Phong trận","aliases":["Cờ đen Hắc Phong trận"],"cn":"","category":"phap-bao","categoryLabel":"Trận kỳ","phamCap":"Không rõ","soHuu":["Hắc y nhân Hắc Sát giáo"],"trangThai":"đang sử dụng","blurb":"Cờ lớn màu đen là trận kỳ được Hắc y nhân dùng để triển khai Hắc Phong trận.","detail":"Theo lệnh Tiểu vương gia, Hắc y nhân rút cờ lớn màu đen ra để bày trận. Khi múa cờ, trận kỳ phát tiếng như quỷ khóc và tạo mây mù đen cuồn cuộn quanh chiến trường.","nguon":["@c0307"]},{"id":"tam-lang-thu","name":"Tam Lăng thứ","aliases":["Lục mang thứ"],"cn":"","category":"phap-bao","categoryLabel":"Pháp khí công kích","phamCap":"Thượng giai cực phẩm","soHuu":["Lão Nhị cao gầy"],"trangThai":"hỏng","blurb":"Tam Lăng thứ là pháp khí công kích màu xanh biếc của Lão Nhị cao gầy.","detail":"Lão Nhị cao gầy dùng Tam Lăng thứ đánh vào Huyết Thị và tự tin đây là cực phẩm trong thượng giai pháp khí. Pháp khí bị huyết quang cuốn chặt rồi bị Huyết Thị bóp mất linh khí, trở thành phế liệu.","nguon":["@c0307"]},{"id":"hai-dao-o-quang-va-sau-dao-kim-quang","name":"Hai đạo ô quang và sáu đạo kim quang","cn":"","category":"phap-bao","categoryLabel":"Đỉnh cấp pháp khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Hai đạo ô quang và sáu đạo kim quang là nhóm pháp khí Hàn Lập phóng ra để vây đánh Huyết Thị.","detail":"Hàn Lập lấy hai đạo ô quang và sáu đạo kim quang từ túi trữ vật, tạo thế công lớn nhằm vây công Huyết Thị. Tuy vậy, Huyết Thị hóa thành khối huyết quang cao hai ba trượng khiến các pháp khí không thể tiến sâu.","nguon":["@c0307"]},{"id":"hoa-diem-lien-hoan-phi-xoa","name":"Hỏa diễm liên hoàn phi xoa","cn":"","category":"phap-bao","categoryLabel":"Pháp khí thành bộ","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ ba tiểu xoa màu đỏ được Hàn Lập dùng trong trận đánh nhóm áo đen.","detail":"Hàn Lập lấy Hỏa diễm liên hoàn phi xoa từ chiến lợi phẩm khi đánh Huyết Tri chu. Trong chương này, bộ pháp khí hóa thành ba đạo hồng quang, chém gãy cờ đen của hắc y tu sĩ rồi đốt chết đối phương.","nguon":["@c0308"]},{"id":"mai-rua-den","name":"Mai rùa đen","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vật phòng ngự được Hàn Lập dùng như thuẫn bài trước đòn phản kích của tiểu vương gia.","detail":"Khi tiểu vương gia bắn mười tia đen, Hàn Lập dùng mai rùa đen đỡ toàn bộ công kích. Mai rùa không phát sáng, khiến tiểu vương gia đoán vật này chưa được chuyên môn tế luyện.","nguon":["@c0308"]},{"id":"phu-luc-mau-xanh-mo-mo","name":"Phù lục màu xanh mờ mờ","cn":"","category":"phap-bao","categoryLabel":"Phù lục/phù bảo","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Phù lục màu xanh được Hàn Lập lấy ra để đối phó đại hán yêu hóa.","detail":"Hàn Lập lấy phù lục này từ túi trữ vật, trịnh trọng cầm bằng hai tay và vận công thi triển trong lúc Mông Sơn tứ hữu cùng khôi lỗi thú cầm chân đối thủ.","nguon":["@c0309"]},{"id":"khoi-loi-thu","name":"Khôi lỗi thú","cn":"","category":"phap-bao","categoryLabel":"Khôi lỗi","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Nhóm khôi lỗi thú được Hàn Lập bố trí để hỗ trợ phòng tuyến.","detail":"Hàn Lập tung thêm bảy, tám con, hợp với bốn con trước đó thành mười khôi lỗi thú. Chúng đồng loạt bắn cột sáng, đánh ngã hoặc đẩy lùi đại hán yêu hóa để kéo dài thời gian.","nguon":["@c0309"]},{"id":"phap-khi-cua-mong-son-tu-huu","name":"Pháp khí của Mông Sơn tứ hữu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Mông Sơn tứ hữu"],"trangThai":"bị phá nát","blurb":"Các pháp khí Mông Sơn tứ hữu tung ra trong lúc vây công đại hán yêu hóa.","detail":"Nhóm pháp khí này được dùng để công kích khi đại hán yêu hóa bị khôi lỗi thú đánh ngã, nhưng không gây thương tổn đáng kể và bị mười ngón tay của hắn cắt nát thành sắt vụn.","nguon":["@c0309"]},{"id":"phu-bao-thuoc-ngoc-mau-xanh","name":"Phù bảo thước ngọc màu xanh","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo","soHuu":["Hàn Lập"],"trangThai":"còn ít uy lực @c0310","blurb":"Phù lục xanh trên tay Hàn Lập hóa thành thước ngọc, rồi phân hóa thành hàng trăm thước nhỏ để công kích.","detail":"Trong trận tại miếu hoang, Hàn Lập kích hoạt phù bảo này nhanh hơn nhờ tu vi Trúc Cơ trung kỳ. Thước ngọc phân hóa thành nhiều thước nhỏ, khiến đại hán đầu bóng lưỡng yêu hóa sợ hãi bỏ chạy; Hàn Lập không truy đuổi vì uy lực phù bảo còn lại không nhiều.","nguon":["@c0310"]},{"id":"doan-hon-dan","name":"Đoạn hồn đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược độc sát","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng với Tiểu vương gia @c0310","blurb":"Độc đan được Hàn Lập dùng để xử tử Tiểu vương gia sau khi thẩm vấn.","detail":"Sau khi dùng dược vật và Mê hồn Huyễn sắc nhãn khiến Tiểu vương gia khai hết bí mật, Hàn Lập nhét Đoạn hồn đan vào miệng hắn. Đan này khiến người uống chết vô thanh vô tức.","nguon":["@c0310"]},{"id":"bach-luan-thuan","name":"Bạch Luân Thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng ngự","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Khiên phòng ngự được Hàn Lập triệu ra trước mặt lúc tưởng địch tập kích. Nó được dùng trong tư thế phòng bị khẩn cấp trước nhóm tu sĩ Trúc Cơ Kỳ ngoài cửa.","detail":"Bạch Luân Thuẫn xuất hiện khi Hàn Lập cảm ứng có ba bốn tu sĩ Trúc Cơ Kỳ ẩn khí tức bên ngoài. Vì tưởng Tứ đại huyết thị của Hắc Sát giáo kéo đến, hắn lập tức gọi khiên ra che trước người để chuẩn bị ứng chiến hoặc đào tẩu.","nguon":["@c0312"]},{"id":"hoa-van-phu","name":"Hỏa Vân phù","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Phù bảo Hàn Lập cầm trong tay khi tưởng có địch tập kích. Nó thể hiện trạng thái như lâm đại địch của hắn trước khi nhận ra viện binh đồng môn. (+) Phù lục bị chưởng quỹ tiệm tạp hóa bán lừa là hàng cao cấp, thực chất chỉ là hàng bình thường không phải do đại sư chế tạo. [CAN-SOAT-GOP]","detail":"Hỏa Vân phù được Hàn Lập nắm sẵn trong tay cùng lúc triệu Bạch Luân Thuẫn. Sau đó hắn mới nhận ra nhóm ngoài cửa là Tống Mông và các đồng môn đến chi viện, không phải Hắc Sát giáo.","nguon":["@c0312","@c0680"]},{"id":"don-sat-thu-cua-han-lap","name":"Đòn sát thủ của Hàn Lập","cn":"","aliases":[],"category":"khac","categoryLabel":"Hậu thủ","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hậu thủ bảo mệnh Hàn Lập đã chuẩn bị trước khi đột nhập hang ổ Hắc Sát giáo. Chương này chưa nói rõ đó là pháp bảo, phù lục hay thủ đoạn khác.","detail":"Hàn Lập không chỉ dựa vào lòng can đảm khi nhận lời tham gia. Hắn tự xét rằng mình đã chuẩn bị một đòn sát thủ để trong trường hợp tình thế bất lợi vẫn có cơ hội toàn thân lui ra khỏi nơi nguy hiểm.","nguon":["@c0314"]},{"id":"buc-thu-gui-ly-hoa-nguyen","name":"Bức thư gửi Lý Hóa Nguyên","cn":"","aliases":[],"category":"khac","categoryLabel":"Thư tín","phamCap":"Không áp dụng","soHuu":["Vũ Huyễn"],"trangThai":"khong-ro","blurb":"Bức thư Vũ Huyễn viết cho Lý Hóa Nguyên sau khi rời Tần phủ. Nội dung thư chưa được tiết lộ.","detail":"Sau khi từ chối tham gia hành động, Vũ Huyễn ở khách điếm Việt Kinh và nghe nói đã viết thư cho Lý Hóa Nguyên, nhằm báo lại toàn bộ sự việc liên quan nhóm đồng môn và kế hoạch đối phó Hắc Sát giáo.","nguon":["@c0314"]},{"id":"bi-mat-tu-tieu-vuong-gia","name":"Bí mật từ Tiểu Vương gia","cn":"","aliases":[],"category":"khac","categoryLabel":"Tin tức cơ duyên","phamCap":"Không áp dụng","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Thông tin Hàn Lập biết được từ Tiểu Vương gia và cho là có thể giúp ích lớn cho việc Kết Đan. Đây là động cơ thật khiến hắn chấp nhận mạo hiểm vào Hoàng cung.","detail":"Hàn Lập tự biết linh căn của mình kém nên đặc biệt coi trọng mọi cơ hội tăng khả năng Kết Đan. Vì bí mật nghe được từ Tiểu Vương gia có thể có tác dụng lớn với đại cảnh giới sau này, hắn mới nhận lời tham gia hành động nguy hiểm này.","nguon":["@c0314"]},{"id":"tran-ky-va-tran-ban-cua-dien-dao-ngu-hanh-tran","name":"Trận kỳ và trận bàn của Điên đảo ngũ hành trận","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí trận pháp","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bộ trận cụ của Điên đảo ngũ hành trận đã cải biến, do Tề Vân Tiêu tặng Hàn Lập.","detail":"Hàn Lập lấy trận kỳ và trận bàn từ túi trữ vật tại rừng trúc trong Ngự hoa viên để bí mật bố trí Điên đảo ngũ hành trận. Bộ trận cụ này trở thành hậu thủ hắn chuẩn bị trước trận chiến với giáo chủ Hắc Sát giáo.","nguon":["@c0315"]},{"id":"thuong-giai-phap-khi","name":"Thượng giai pháp khí","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng giai","soHuu":["Mông Sơn tứ hữu"],"trangThai":"đã được Hàn Lập tặng cho Mông Sơn tứ hữu","blurb":"Vài món pháp khí tinh xảo được Hàn Lập đem tặng Mông Sơn tứ hữu trước trận đánh Hắc Sát giáo. Giá trị đủ lớn với tán tu Luyện Khí kỳ nhưng không đến mức gây họa như đỉnh giai pháp khí.","detail":"Trước khi để Mông Sơn tứ hữu rời Việt Kinh, Hàn Lập lấy ra vài món pháp khí thượng giai lấp lánh hào quang và bảo mỗi người chọn một món. Hắn cố ý không tặng đỉnh giai pháp khí vì lo món quá quý sẽ kích phát lòng tham hoặc đem lại rắc rối cho nhóm tán tu Luyện Khí kỳ.","nguon":["@c0316"]},{"id":"khan-tay-bang-to-tam-cua-luu-tinh","name":"Khăn tay bằng tơ tằm của Lưu Tĩnh","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"không rõ","soHuu":["Lưu Tĩnh"],"trangThai":"đang sử dụng","blurb":"Pháp khí phòng ngự dạng khăn tay tơ tằm của Lưu Tĩnh. Khi được vung ra, nó hóa thành lá chắn lớn để chặn công kích pháp thuật và pháp khí.","detail":"Trong trận đánh Lãnh cung, Lưu Tĩnh dùng khăn tay này tạo thành lá chắn khổng lồ bảo vệ đồng môn trước đòn phản kích của đệ tử Hắc Sát giáo. Lá chắn còn bắn ngược một phần pháp thuật trở lại đối phương.","nguon":["@c0317"]},{"id":"lam-ti-kiem","name":"Lam Ti kiếm","cn":"","category":"phap-bao","categoryLabel":"Đỉnh giai pháp khí","phamCap":"đỉnh giai pháp khí","soHuu":["Tống Mông"],"trangThai":"đang sử dụng","blurb":"Cự kiếm màu lam Tống Mông yêu thích sử dụng. Nó được dùng để thi triển Vạn Ti thiên hạ trong trận đánh Lãnh cung.","detail":"Lam Ti kiếm phát huy uy lực diện rộng khi Tống Mông khiến thân kiếm quay như bánh xe ánh sáng rồi bắn ra vô số tia lam. Đòn này áp đảo phần lớn đệ tử Hắc Sát giáo phòng thủ Lãnh cung.","nguon":["@c0317"]},{"id":"nam-phap-khi-mau-xanh-hinh-tron","name":"Năm pháp khí màu xanh hình tròn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Thanh Văn đạo sĩ"],"trangThai":"đang sử dụng","blurb":"Bộ năm pháp khí màu xanh của Thanh Văn đạo sĩ, xếp quanh thân thành hình ngũ giác.","detail":"Thanh Văn phóng năm pháp khí màu xanh hình tròn khi bị Hàn Lập và Vương sư huynh vây công. Chúng hợp thành vòng bảo hộ Thanh Mộc chân tráo, chặn loạt công kích bằng kim xoa và kim nhận của Hàn Lập.","nguon":["@c0318"]},{"id":"toa-kim-hoan","name":"Tỏa Kim hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Thanh Văn đạo sĩ"],"trangThai":"bị đánh nát @c0319","blurb":"Hai viên hoàn tỏa hàn khí của Thanh Văn đạo sĩ, dùng để đánh úp Hàn Lập trong lúc hắn chuẩn bị thi pháp.","detail":"Thanh Văn đạo sĩ phóng Tỏa Kim hoàn hóa thành hai đạo kim quang nhằm đánh úp Hàn Lập. Đòn này bị ba đạo lục mang của Vương sư huynh chặn lại, sau đó hai Kim hoàn bị Vương sư huynh đánh nát.","nguon":["@c0319"]},{"id":"kim-phu-cua-luu-tinh","name":"Kim phù của Lưu Tĩnh","cn":"","aliases":[],"category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Lưu Tĩnh"],"trangThai":"Đã sử dụng trong trận phá quang kén","blurb":"Phù lục màu vàng do Lưu Tĩnh lấy ra khi yêu cầu đồng môn dùng tuyệt chiêu. Vật này cần chú ngữ kích phát để thi triển Thiên Nhận thuật.","detail":"Kim phù hóa thành kim quang rồi sinh ra vô số tiểu kiếm vàng của Thiên Nhận thuật. Trong trận tại hoàng cung Việt quốc, nó là thủ đoạn then chốt khiến huyết quang quang kén Huyết thị bắt đầu biến hóa và suy yếu.","nguon":["@c0320"]},{"id":"phu-bao-mau-xam-cua-tong-mong","name":"Phù bảo màu xám của Tống Mông","cn":"","aliases":["Trường thương màu xám","Phù bảo Trường thương"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Tống Mông"],"trangThai":"Đang dùng","blurb":"Phù bảo màu xám của Tống Mông, khi kích phát hiện thành một thanh trường thương màu xám dài vài thước. Nó tản ra khí tức quỷ dị và phát tiếng kêu thê lương khi công kích.","detail":"Trong trận phá quang kén, Tống Mông dùng trường thương phù bảo này phối hợp với Thiên Nhận thuật và các pháp khí khác. Đòn công kích của nó xuyên thủng lớp huyết quang còn lại, góp phần buộc Băng Yêu xuất hiện khi yêu hóa chưa hoàn tất.","nguon":["@c0320"]},{"id":"phu-bao-mau-lam-cua-su-ty-tran-xao-thien","name":"Phù bảo màu lam của sư tỷ Trần Xảo Thiến","cn":"","aliases":["Phù bảo màu lam của Tuyết Hồng sư tỷ"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Tuyết Hồng sư tỷ"],"trangThai":"Không rõ sau khi chủ nhân tử trận","blurb":"Phù bảo do sư tỷ của Trần Xảo Thiến lấy ra trong trận phá quang kén Huyết thị. Việc nàng sở hữu phù bảo cho thấy đây là vật đáng chú ý trong nhóm đồng môn.","detail":"Tuyết Hồng sư tỷ khởi động phù bảo màu lam cùng lúc Tống Mông khởi động phù bảo màu xám. Khi nàng đang ngồi dưới đất khống chế phù bảo, Băng Yêu ẩn thân đánh lén xuyên ngực khiến nàng tử trận.","nguon":["@c0320"]},{"id":"phu-bao-cua-tuyet-hong","name":"Phù bảo của Tuyết Hồng","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo","soHuu":["Tuyết Hồng sư tỷ"],"trangThai":"Không rõ","blurb":"Phù bảo Tuyết Hồng đang kích phát vào thời khắc bị Băng Yêu đánh lén chí mạng.","detail":"Vì muốn nhanh kích phát phù bảo và tiết kiệm pháp lực, Tuyết Hồng thu pháp khí phòng ngự. Sơ hở này khiến nàng bị Băng Yêu ẩn hình đánh lén trong thời khắc cuối cùng khi không thể dừng lại.","nguon":["@c0321"]},{"id":"thanh-dong-tieu-thuan","name":"Thanh Đồng tiểu thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"Không rõ","soHuu":["Vương hộ pháp"],"trangThai":"Bị băng phong, tạm mất linh tính","blurb":"Pháp khí hộ thân của Vương sư huynh, tự động đỡ một trảo của Băng Yêu.","detail":"Khi Băng Yêu tập kích Vương sư huynh, Thanh Đồng tiểu thuẫn tự động hộ chủ và chặn được đòn đầu. Sau đó nó bị băng sương dày đóng kết, rơi xuống và tạm thời mất linh tính, khiến Vương sư huynh suýt trúng đòn thứ hai.","nguon":["@c0321"]},{"id":"hop-ngoc-mau-do-lua","name":"Hộp ngọc màu đỏ lửa","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Lưu Tĩnh"],"trangThai":"đã vỡ","blurb":"Vật chứa được Lưu Tĩnh lấy từ túi trữ vật trước khi thi triển Chân bảo hỏa điểu. Khi bị vỗ vỡ, hộp để lộ phù lục hỏa điểu tỏa nhiệt khí mạnh bên trong.","detail":"Trong lúc quyết định tự mình xử lý ba Huyết thị còn lại, Lưu Tĩnh lấy ra một hộp ngọc đỏ lửa rồi phá hộp để lộ phù lục có đồ án chim lửa. Hộp là vật chứa bảo vệ Chân bảo, không được nêu phẩm cấp riêng.","nguon":["@c0322"]},{"id":"phap-bao-ban-the-cua-chan-bao","name":"Pháp bảo bản thể của Chân bảo","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo nguồn","phamCap":"Không rõ","soHuu":[],"trangThai":"tổn thất vĩnh viễn khi luyện Chân bảo","blurb":"Pháp bảo nguồn dùng để luyện ra Chân bảo, truyền một phần uy lực vào phù lục đặc biệt cho hậu nhân huyết mạch trực hệ sử dụng. Quá trình luyện chế khiến bản thể pháp bảo chịu hao tổn vĩnh viễn.","detail":"Chương giải thích Chân bảo là loại phù bảo đặc biệt có thể chứa tới một phần ba uy lực của pháp bảo bản thể. Để luyện thành, pháp bảo gốc phải chịu tổn thất vĩnh viễn và Chân bảo chỉ có thể dùng một lần bởi hậu nhân trực hệ huyết mạch của chủ nhân pháp bảo.","nguon":["@c0322"]},{"id":"hoa-dieu-chan-bao","name":"Hỏa điểu Chân bảo","cn":"","aliases":["Chân bảo hỏa điểu","Hỏa điểu Chân bảo","Phù lục hỏa điểu"],"category":"phap-bao","categoryLabel":"Chân bảo","phamCap":"Chân bảo","soHuu":["Lưu Tĩnh"],"trangThai":"đang sử dụng","blurb":"Chân bảo dạng phù lục của Lưu Tĩnh, khi kích phát hóa thành chim lửa đỏ.","detail":"Lưu Tĩnh rót pháp lực vào phù lục để kích phát Hỏa điểu Chân bảo. Khi thành công, chim lửa màu đỏ xuất hiện trong tay hắn, sau đó hóa thành hỏa diễm cự điểu lao về phía yêu nhân mang khuôn mặt Thanh Văn đạo sĩ.","nguon":["@c0323"]},{"id":"vien-hoan-mau-vang","name":"Viên hoàn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp khí hộ thân","phamCap":"không rõ","soHuu":["Lưu Tĩnh"],"trangThai":"đang sử dụng","blurb":"Pháp khí viên hoàn màu vàng được Lưu Tĩnh dùng để hộ thân khi kích phát Chân bảo.","detail":"Trong lúc ngồi xuống rót pháp lực vào Hỏa điểu Chân bảo, Lưu Tĩnh phóng viên hoàn màu vàng bay quanh thân để bảo vệ bản thân trước nguy hiểm từ chiến trường.","nguon":["@c0323"]},{"id":"hat-chau-mau-xanh","name":"Hạt châu màu xanh","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Vương sư huynh","Hắc Sát giáo chủ"],"trangThai":"Bị Hắc Sát giáo chủ nhặt lại","blurb":"Hạt châu màu xanh lớn cỡ ngón tay cái từng nằm trên tay Vương sư huynh. Hắc Sát giáo chủ giết hắn trước tiên để lấy lại vật này.","detail":"Sau khi rút cánh tay đỏ máu khỏi ngực Vương sư huynh, Hắc Sát giáo chủ nói hắn không nên lấy thứ không thuộc về mình rồi nhặt hạt châu màu xanh từ tay thi thể. Vật này rõ ràng có liên quan quan trọng đến Hắc Sát giáo chủ hoặc bí mật dưới mặt đất.","nguon":["@c0324"]},{"id":"hai-thanh-ngan-cau-va-vien-hoan-cua-luu-tinh","name":"Hai thanh ngân câu và viên hoàn của Lưu Tĩnh","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Chưa rõ","soHuu":["Lưu Tĩnh"],"trangThai":"Chưa kịp sử dụng khi chủ nhân bị giết","blurb":"Bộ pháp khí Lưu Tĩnh lấy ra khi chuẩn bị đối phó Hắc Sát giáo chủ. Hắn chưa kịp phát động thì bị đánh lén xuyên ngực.","detail":"Trước lúc giao chiến với Hắc Sát giáo chủ, Lưu Tĩnh lật tay lấy ra hai thanh ngân câu và viên hoàn. Biến cố xảy ra ngay sau đó khi kẻ đánh lén từ phía phe tu sĩ ra tay, khiến pháp khí không kịp phát huy tác dụng.","nguon":["@c0324"]},{"id":"quy-xac-phap-khi","name":"Quy xác pháp khí","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Pháp khí hình quy xác được Hàn Lập phóng ra để tăng phòng ngự khi đối diện Việt hoàng và Lam bào nhân.","detail":"Trong lúc nhận ra đối thủ che giấu tu vi và sát ý đã lộ rõ, Hàn Lập phóng Quy xác pháp khí cùng Bạch Lân thuẫn để bảo vệ toàn thân trước Việt hoàng Trúc Cơ hậu kỳ.","nguon":["@c0325"]},{"id":"vien-chau-mau-lam","name":"Viên châu màu lam","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Vật phẩm nghi Ngũ hành huyết ngưng đan","phamCap":"Chưa rõ","soHuu":["Hắc Sát giáo chủ"],"trangThai":"bị lấy từ thi thể Băng Yêu","blurb":"Viên châu màu lam bay ra từ thi thể Băng Yêu, được Hắc Sát giáo chủ lấy đi.","detail":"Lam bào nhân lấy viên châu màu lam từ thi thể Băng Yêu bị Hàn Lập chém nát. Hàn Lập liên hệ viên châu này với hệ Ngũ hành huyết ngưng đan liên quan Kết đan.","nguon":["@c0325"]},{"id":"vien-chau-mau-kim","name":"Viên châu màu kim","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Vật phẩm nghi Ngũ hành huyết ngưng đan","phamCap":"Chưa rõ","soHuu":["Việt hoàng"],"trangThai":"bị lấy từ nơi Huyết thị chết","blurb":"Viên châu màu kim được Việt hoàng lấy từ nơi hai Huyết thị bị hỏa điểu chân bảo luyện hóa.","detail":"Việt hoàng vỗ xuống mặt đất tại nơi hai Huyết thị chết, khiến viên châu màu kim bắn lên cùng viên châu màu hoàng. Hàn Lập đoán chúng thuộc hệ Ngũ hành huyết ngưng đan.","nguon":["@c0325"]},{"id":"vien-chau-mau-hoang","name":"Viên châu màu hoàng","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Vật phẩm nghi Ngũ hành huyết ngưng đan","phamCap":"Chưa rõ","soHuu":["Việt hoàng"],"trangThai":"bị lấy từ nơi Huyết thị chết","blurb":"Viên châu màu hoàng được Việt hoàng lấy cùng viên châu màu kim từ nơi hai Huyết thị chết.","detail":"Viên châu màu hoàng bắn lên từ dưới đất sau khi Việt hoàng vỗ xuống nơi hai Huyết thị bị luyện hóa. Hàn Lập xem nó là một trong những viên châu thuộc hệ Ngũ hành huyết ngưng đan.","nguon":["@c0325"]},{"id":"kim-thuoc","name":"Kim thước","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nhóm Tống Mông"],"trangThai":"bị huyết quang khống chế @c0326","blurb":"Một pháp khí của nhóm Tống Mông bị giữ trong huyết quang của Việt Hoàng. Nó trở nên bất động như mất linh tính.","detail":"Kim thước xuất hiện trong số pháp khí của nhóm Tống Mông đang trôi nổi trong huyết quang quanh Việt Hoàng. Tình trạng này khiến Hàn Lập nhận định ma quang hộ thể của đối phương có thể ăn mòn hoặc khắc chế pháp khí thông thường.","nguon":["@c0326"]},{"id":"doi-quai-nhan-mau-tim","name":"Đôi quái nhận màu tím","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nhóm Tống Mông"],"trangThai":"bị huyết quang khống chế @c0326","blurb":"Một đôi pháp khí của nhóm Tống Mông bị huyết quang của Việt Hoàng vây giữ. Chúng được nêu đối lập với Ô Long đoạt vốn không sợ tà công này.","detail":"Đôi quái nhận màu tím cùng kim thước và trường kiếm màu xanh lam bị giữ trong huyết quang, không thể cử động như đã mất linh tính. Chi tiết này làm nhóm Tống Mông không dám tiếp tục dùng pháp khí, chuyển sang phù lục để công kích.","nguon":["@c0326"]},{"id":"truong-kiem-mau-xanh-lam","name":"Trường kiếm màu xanh lam","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nhóm Tống Mông"],"trangThai":"bị huyết quang khống chế @c0326","blurb":"Pháp khí kiếm của nhóm Tống Mông bị giữ lại trong huyết quang. Nó mất linh tính trong lúc đối đầu ma quang hộ thể của Việt Hoàng.","detail":"Trường kiếm màu xanh lam nằm trong số pháp khí bị huyết quang quanh Việt Hoàng khống chế. Việc nó bất động góp phần xác nhận nguy cơ pháp khí thông thường bị tà công của Việt Hoàng ăn mòn.","nguon":["@c0326"]},{"id":"tu-tuy-dan","name":"Tu tủy đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Ma đạo cứu mạng","soHuu":["Việt hoàng"],"trangThai":"đã dùng @c0326","blurb":"Viên đan màu hồng đầy mùi huyết tinh do người luyện ma công đặc biệt tự hao tổn tu vi luyện thành. Việt Hoàng nuốt nó để phục hồi gần như hoàn toàn sau thương thế do Thiên Lôi tử gây ra.","detail":"Tu tủy đan được Việt Hoàng lấy từ bình nhỏ màu xanh thẫm trong lúc bị khôi lỗi và phù lục vây công. Chung Vệ Nương giải thích đan này chỉ người tự luyện mới dùng được, nhằm cứu mạng khi tu luyện ma công đặc biệt, và hiệu quả của nó khiến Hàn Lập cùng Tống Mông chấn kinh.","nguon":["@c0326"]},{"id":"vien-chau-do-ruc","name":"Viên châu đỏ rực","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Việt hoàng"],"trangThai":"được Việt Hoàng thu lấy @c0326","blurb":"Viên châu đỏ rực được Việt Hoàng chụp lấy sau khi phục hồi nhờ Tu tủy đan. Hàn Lập liên hệ nó với gã áo lam đã chết và việc gom đủ Ngũ hành huyết ngưng đan.","detail":"Sau khi thu lại quang thuẫn và mở rộng huyết quang hộ thể, Việt Hoàng chụp lấy viên châu đỏ rực. Hành động này khiến Hàn Lập nghĩ rằng Ngũ hành huyết ngưng đan đã thu thập đủ, chỉ cần giết Việt Hoàng là có thể đoạt bảo vật hữu ích cho Kết đan.","nguon":["@c0326"]},{"id":"tran-ky-mau-tim","name":"Trận kỳ màu tím","cn":"","category":"phap-bao","categoryLabel":"Trận kỳ","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Trận kỳ Hàn Lập lấy ra để kích hoạt bố trí thật sự trong rừng trúc.","detail":"Vật này có phù văn dày đặc, được Hàn Lập lấy từ túi trữ vật và cắm xuống để phối hợp các trận kỳ khác, làm Điên Đảo Ngũ Hành trận chuyển từ phòng hộ ban đầu sang màn sáng năm màu vững chắc.","nguon":["@c0327"]},{"id":"tran-ban-mau-vang","name":"Trận bàn màu vàng","cn":"","category":"phap-bao","categoryLabel":"Trận bàn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Trận bàn trung tâm Hàn Lập dùng để phát động Điên Đảo Ngũ Hành trận.","detail":"Hàn Lập trịnh trọng giơ trận bàn màu vàng, khiến một cột sáng màu vàng phóng lên và phối hợp bốn cột sáng từ trận kỳ, cuối cùng nhập vào màn phòng hộ để hình thành màn sáng năm màu của đại trận.","nguon":["@c0327"]},{"id":"hac-huyet-dao","name":"Hắc huyết đao","cn":"","aliases":["Hắc huyết yêu đao"],"category":"phap-bao","categoryLabel":"Pháp bảo/vũ khí","phamCap":"không rõ","soHuu":["Việt Hoàng"],"trangThai":"đang sử dụng","blurb":"Pháp bảo do Việt Hoàng luyện thành từ chuôi đao đen bằng máu, tinh huyết và huyết quang.","detail":"Hắc Huyết Đao ban đầu là chuôi đao đen nhỏ, sau khi hấp thu tơ máu, tinh huyết và huyết quang của Việt Hoàng thì hóa thành trường đao tỏa huyết khí. Thanh đao có thể cắn nuốt thần thức của Hàn Lập và chém rách tầng phòng hộ ngũ sắc đầu tiên của Điên Đảo Ngũ Hành Trận.","nguon":["@c0328"]},{"id":"phu-luc-mau-xanh-cua-han-lap","name":"Phù lục màu xanh của Hàn Lập","cn":"","category":"phap-bao","categoryLabel":"Phù lục/phù bảo chưa xác định","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang khởi phát","blurb":"Phù lục màu xanh được Hàn Lập lấy ra khi chuẩn bị đối địch Việt Hoàng trong trận.","detail":"Hàn Lập khởi phát phù lục màu xanh trong lúc dùng thần thức quan sát Việt Hoàng. Vật này là thủ đoạn hắn chuẩn bị cùng các phù bảo của đồng môn trước khi Việt Hoàng phá tầng phòng hộ đầu tiên.","nguon":["@c0328"]},{"id":"phu-bao-mau-do-cua-tran-xao-thien","name":"Phù bảo màu đỏ của Trần Xảo Thiến","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"không rõ","soHuu":["Trần Xảo Thiến"],"trangThai":"đang khởi động","blurb":"Phù bảo màu đỏ được Trần Xảo Thiến lấy ra để chuẩn bị công kích Việt Hoàng.","detail":"Trần Xảo Thiến lấy phù bảo màu đỏ từ túi trữ vật rồi khoanh chân khởi động cùng Chung Vệ Nương, phối hợp với Hàn Lập trong thế trận vây Việt Hoàng.","nguon":["@c0328"]},{"id":"phu-bao-mau-vang-cua-chung-ve-nuong","name":"Phù bảo màu vàng của Chung Vệ Nương","cn":"","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"không rõ","soHuu":["Chung Vệ Nương"],"trangThai":"đang khởi động","blurb":"Phù bảo màu vàng được Chung Vệ Nương lấy ra trong lúc nhóm Hoàng Phong Cốc chuẩn bị đối phó Việt Hoàng.","detail":"Chung Vệ Nương lấy phù bảo màu vàng từ túi trữ vật và khoanh chân khởi động cùng Trần Xảo Thiến, chờ thời cơ công kích đối thủ đang bị trận pháp ngăn giữ.","nguon":["@c0328"]},{"id":"huyet-ngung-ngu-hanh-dan","name":"Huyết ngưng ngũ hành đan","aliases":["Ngũ hành huyết ngưng đan"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Việt hoàng"],"trangThai":"dang-co","blurb":"Đan dược then chốt giúp Khúc Hồn tu Huyết Luyện Thần Quang đi theo hướng kết Sát Đan. Nhờ nó, Khúc Hồn có thể trực tiếp luyện hóa đan lực thay vì ngưng kim đan theo công pháp chính thống. (+) Đan dược trên người Việt hoàng mà Hàn Lập nhắm tới sau khi diệt địch. [CAN-SOAT-GOP]","detail":"Vật Hàn Lập đặt tâm tư ngay sau khi giết Việt hoàng, khiến hắn thả hai Khôi Lỗi thú đi lục soát thi thể để tìm kiếm.","nguon":["@c0329","@c0386"],"tabs":{}},{"id":"ngoc-gian-mau-trang-xam","name":"Ngọc giản màu trắng xám","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản quỷ dị ghi lại các công pháp và bí thuật của Hắc Sát giáo, thu được từ Việt hoàng.","detail":"Vật phẩm chứa các công pháp, bí thuật Hắc Sát giáo gồm Hắc Sát Tu La công, Sát Yêu quyết, Huyết Luyện thần quang, Sát Đan thuật, Thân ngoại hóa thân cùng phương pháp ngưng luyện Huyết Linh Toản, đồng thời nhiều lần nhắc tới Huyền Âm Kinh. Hàn Lập phải dùng thanh quang bảo hộ hai tay đề phòng cấm chế hoặc nguyền rủa trước khi đưa thần thức vào đọc.","nguon":["@c0330"]},{"id":"nguy-kim-dan","name":"Ngụy kim đan","aliases":["Sát Đan"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cận kim đan","soHuu":[],"trangThai":"khong-ro","blurb":"Kim đan nhân tạo do Sát Đan thuật tạo ra, uy lực gần kim đan thật và tăng thọ nhưng không thể tăng tiến, dần ăn mòn thần trí.","detail":"Loại kim đan giả kết thành khi tu sĩ Trúc Cơ hậu kỳ dùng Sát Đan thuật ăn Huyết ngưng ngũ hành đan (một phần ba cơ hội thành công). Ngụy kim đan có uy lực gần với kim đan của tu sĩ Kết Đan kỳ và giúp tăng tuổi thọ, nhưng chỉ duy trì được cảnh giới Kết Đan sơ kỳ, không thể tăng tiến, đồng thời phóng thích sát yêu chi khí ăn mòn thần trí người dùng.","nguon":["@c0330"]},{"id":"tu-hon-bat","name":"Tụ Hồn Bát","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang do Hàn Lập nắm giữ","blurb":"Cái bát đen nhánh hiếm thấy chuyên dung nạp hồn phách nguyên thần tu sĩ, âm hàn tà dị.","detail":"Pháp khí hiếm thấy dùng để chứa và dần tiêu diệt linh tính hồn phách nguyên thần của tu sĩ, để tà tu dùng tế luyện. Hàn Lập nhận ra bát đen trong chiến lợi phẩm chính là Tụ Hồn Bát, cảm thấy âm hàn tà dị mạnh và suy đoán đã có nhiều hồn phách tu sĩ táng thân trong đó, nên lập tức thu vào túi trữ vật.","nguon":["@c0330","@c0339"],"tabs":{"tienTrinh":[{"chuong":"@c0339","loai":"dùng","importance":"normal","giaiDoan":"Uy hiếp Khúc Hồn","text":"Hàn Lập lấy Tụ Hồn bát ra để dọa luyện hồn tu sĩ trong thân Khúc Hồn và dùng nó làm vật thề theo yêu cầu của đối phương.","anchor":"Tiếp theo bàn tay Hàn Lập lật một cái, Tụ Hồn bát lại xuất hiện"}]},"congNang":["Dùng để uy hiếp hồn phách và làm Hồn khí cho lời thề trong cuộc ép hỏi tu sĩ trong thân Khúc Hồn @c0339"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0339","denChuong":"","cachCoDuoc":"Đã có trong tay trước khi ép hỏi tu sĩ trong thân Khúc Hồn.","trangThai":"dang-co"}]},{"id":"tam-ban-do-khong-tron-ven","name":"Tấm bản đồ không trọn vẹn","aliases":[],"cn":"","category":"khac","categoryLabel":"Vật phẩm bản đồ","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập cất giữ","blurb":"Tấm bản đồ cũ hiện ra từ tro thi thể Việt hoàng. Nó không giống bản đồ Việt quốc và chỉ là một phần của bản đồ lớn hơn.","detail":"Vật này là một dải lụa trắng đã ố vàng, có huỳnh quang nhàn nhạt, được Hàn Lập phát hiện sau khi hỏa táng Việt hoàng. Vì bản đồ dường như từng được giấu trong cơ thể bằng bí pháp và không thuộc địa hình Việt quốc, Hàn Lập cho rằng không thể xem thường rồi cất vào hộp ngọc.","phanLoaiPhu":"Bản đồ","hinhDang":"Dải lụa trắng cũ đã ố vàng","dacDiem":"Có huỳnh quang nhàn nhạt, không trọn vẹn và không phải bản đồ Việt quốc.","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Việt hoàng","tuChuong":"@c0331","denChuong":"@c0331","cachCoDuoc":"Giấu trong cơ thể bằng bí pháp trước khi bị hỏa táng","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0331","denChuong":"","cachCoDuoc":"Phát hiện trong tro thi thể Việt hoàng và cất vào hộp ngọc","trangThai":"đang giữ"}],"congNang":["Ghi lại một phần địa hình hoặc bí mật chưa rõ, không thuộc Việt quốc @c0331"],"capNhatToi":"@c0331","tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ ra từ tro tàn","text":"Tấm bản đồ không trọn vẹn hiện ra từ tro thi thể Việt hoàng và được Hàn Lập cất giữ.","anchor":"Miếng vải này đã thoáng ố vàng, vừa nhìn đã thấy là một vật có niên đại rất xa xưa"}]},"nguon":["@c0331"]},{"id":"thu-lenh-trieu-tap-truc-co-ky","name":"Thủ lệnh triệu tập Trúc Cơ kỳ","aliases":[],"cn":"","category":"khac","categoryLabel":"Lệnh phù văn thư","phamCap":"Chưa rõ","soHuu":["Mã sư điệt","Hàn Lập"],"trangThai":"Đã truyền đạt","blurb":"Thủ lệnh do Mã sư điệt giao cho Hàn Lập tại Tần gia. Nội dung yêu cầu đệ tử Trúc Cơ kỳ đang làm nhiệm vụ bên ngoài đến đại doanh biên giới trong một tháng.","detail":"Thủ lệnh có linh huy tiêu ký xác thực, truyền đạt mệnh lệnh tập hợp nhân thủ Trúc Cơ kỳ trở lên của Thất phái. Lệnh này gắn với việc Ma đạo lục tông đã hạ chiến thư quyết chiến sau hai tháng.","phanLoaiPhu":"Thủ lệnh","dacDiem":"Có linh huy tiêu ký xác thực.","congNang":["Truyền quân lệnh yêu cầu tu sĩ Trúc Cơ kỳ bên ngoài nhiệm vụ đến đại doanh biên giới trong một tháng @c0331"],"chuSoHuu":[{"ten":"Mã sư điệt","tuChuong":"@c0331","denChuong":"@c0331","cachCoDuoc":"Mang lệnh của tông môn đến Tần gia","trangThai":"đã giao"},{"ten":"Hàn Lập","tuChuong":"@c0331","denChuong":"","cachCoDuoc":"Nhận từ Mã sư điệt","trangThai":"đã nhận lệnh"}],"capNhatToi":"@c0331","tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"xuất hiện","importance":"normal","giaiDoan":"Truyền lệnh ra biên giới","text":"Mã sư điệt giao thủ lệnh cho Hàn Lập, yêu cầu đệ tử Trúc Cơ kỳ bên ngoài nhiệm vụ đến đại doanh biên giới trong một tháng.","anchor":"Yêu cầu tất cả các đệ tử Trúc Cơ kỳ bên ngoài làm nhiệm vụ, trong một tháng từ khi nhận được lệnh"}]},"nguon":["@c0331"]},{"id":"ngoc-gian-cua-ly-hoa-nguyen","name":"Ngọc giản của Lý Hóa Nguyên","aliases":[],"cn":"","category":"khac","categoryLabel":"Ngọc giản tín giản","phamCap":"Chưa rõ","soHuu":["Mã sư điệt","Hàn Lập"],"trangThai":"Đã truyền tin","blurb":"Ngọc giản chứa hư ảnh truyền lệnh của Lý Hóa Nguyên. Nó thông báo nhiệm vụ bảo hộ Tần gia đã kết thúc và Hàn Lập có thể trở về biên giới.","detail":"Khi Hàn Lập xem ngọc giản, hư ảnh Lý Hóa Nguyên xuất hiện và nói ngắn gọn rằng Tần gia không cần tiếp tục được bảo hộ. Nguyên nhân là kế hoạch Ma đạo tiềm nhập thế tục Việt quốc đã bị hủy bỏ không rõ vì sao.","phanLoaiPhu":"Ngọc giản truyền tin","congNang":["Lưu hư ảnh của Lý Hóa Nguyên để truyền đạt mệnh lệnh hủy nhiệm vụ bảo hộ Tần gia @c0331"],"chuSoHuu":[{"ten":"Mã sư điệt","tuChuong":"@c0331","denChuong":"@c0331","cachCoDuoc":"Mang theo để giao lệnh","trangThai":"đã giao"},{"ten":"Hàn Lập","tuChuong":"@c0331","denChuong":"","cachCoDuoc":"Nhận từ Mã sư điệt","trangThai":"đã xem"}],"capNhatToi":"@c0331","tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"xuất hiện","importance":"normal","giaiDoan":"Hủy nhiệm vụ bảo hộ","text":"Ngọc giản hiện hư ảnh Lý Hóa Nguyên và truyền tin Tần gia không cần tiếp tục được bảo hộ.","anchor":"Kết quả, tại trong đó xuất hiện hư ảnh của Lý Hóa Nguyên"}]},"nguon":["@c0331"]},{"id":"dinh-nhan-dan","name":"Định nhan đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"khong-ro","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Định nhan đan là đan dược giúp dung mạo người dùng không thay đổi trong nhiều năm. Hàn Lập từng phục dụng nó nên Tôn Nhị Cẩu vẫn nhận ra hắn sau thời gian dài xa cách. (+) Đan dược có công hiệu trú nhan, duy trì dung nhan trẻ. Hàn Lập dùng mấy viên đổi lấy vật phẩm trân quý của các Kết Đan kỳ tu sĩ lân cận. [CAN-SOAT-GOP] (+) Đan dược cố định dung mạo vĩnh viễn tại thời điểm uống, không thay đổi theo tuổi tác. [CAN-SOAT-GOP]","detail":"Đan dược này được nhắc tới khi Tôn Nhị Cẩu gặp lại Hàn Lập và kinh ngạc vì dung mạo đối phương không đổi. Tác dụng đã thấy là giữ dung mạo ổn định qua nhiều năm.","phanLoaiPhu":"đan dược giữ dung mạo","congNang":["Giữ dung mạo người phục dụng không thay đổi qua nhiều năm @c0333"],"chuHienThoi":"Hàn Lập","capNhatToi":"@c0333","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0333","denChuong":"","cachCoDuoc":"Từng phục dụng trước thời điểm gặp lại Tôn Nhị Cẩu.","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0333","loai":"nhắc tới","importance":"normal","giaiDoan":"Dung mạo không đổi","text":"Định nhan đan được nhắc là nguyên nhân khiến dung mạo Hàn Lập nhiều năm không thay đổi, nhờ đó Tôn Nhị Cẩu vừa gặp đã nhận ra hắn.","anchor":"Bởi vì đã phục dụng “ Định nhan đan”, nhiều năm đã qua nhưng dung mạo của Hàn Lập không thay đổi chút nào."}]},"nguon":["@c0333","@c0399","@c0637"]},{"id":"giai-doc-dan-mau-lam","name":"Giải độc đan màu lam","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Tôn Nhị Cẩu"],"trangThai":"Được Hàn Lập giao cho Tôn Nhị Cẩu","blurb":"Đan dược màu lam Hàn Lập lấy ra để giúp Tôn Nhị Cẩu giải độc.","detail":"Sau khi xác nhận Tôn Nhị Cẩu trúng độc lâu ngày, Hàn Lập lấy ra một viên đan dược màu lam ném cho hắn, dặn chờ một lát rồi ăn vào. Hàn Lập nói nếu sau đó không tiếp tục bị hạ độc thì độc trong người Tôn Nhị Cẩu sẽ không đáng ngại.","phanLoaiPhu":"Giải độc","hinhDang":"Viên đan dược màu lam","uyLuc":"Có thể giải loại độc bí ẩn nhưng độc tính không mạnh trong người Tôn Nhị Cẩu nếu không tiếp tục bị hạ độc.","congNang":["Giải độc cho người đã trúng độc tích lũy nhiều tháng @c0334"],"chuSoHuu":[{"ten":"Tôn Nhị Cẩu","tuChuong":"@c0334","denChuong":"","cachCoDuoc":"Được Hàn Lập ném cho để giải độc","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0334","loai":"xuất hiện","importance":"normal","giaiDoan":"Cấp thuốc giải độc","text":"Hàn Lập lấy ra viên giải độc đan màu lam và đưa cho Tôn Nhị Cẩu dùng sau khi độc tố hiện rõ.","anchor":"Hàn Lập nhẹ nhàng lắc đầu, nhưng vẫn đem ra viên đan dược màu lam ném cho người này"}]},"capNhatToi":"@c0334","nguon":["@c0334"]},{"id":"khong-bach-phu","name":"Không Bạch phù","cn":"","aliases":[],"category":"khac","categoryLabel":"Phù tín vật","phamCap":"bình thường","soHuu":["Hàn Lập","Tôn Nhị Cẩu"],"trangThai":"bị xé đôi làm tín vật","blurb":"Không Bạch phù là lá phù bình thường được Hàn Lập xé làm hai nửa để làm tín vật. Một nửa do Tôn Nhị Cẩu giữ, dùng cho hậu nhân Tôn gia nhận ra Hàn Lập về sau.","detail":"Hàn Lập lấy một lá Không Bạch phù bình thường, xé làm hai nửa rồi giao một nửa cho Tôn Nhị Cẩu. Vật này được dùng như tín vật nhận diện giữa Hàn Lập và hậu nhân Tôn gia, gắn với lời hứa cho Tôn gia đời đời phú quý nếu trung thành.","phanLoaiPhu":"phù tín vật","hinhDang":"một lá phù bị xé làm hai nửa","congNang":["Làm tín vật để hậu nhân Tôn gia nhận ra Hàn Lập @c0335"],"chuHienThoi":"Hàn Lập và Tôn Nhị Cẩu mỗi bên giữ một nửa","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0335","denChuong":"","cachCoDuoc":"tự lấy ra một lá Không Bạch phù rồi giữ lại một nửa","trangThai":"đang giữ một nửa"},{"ten":"Tôn Nhị Cẩu","tuChuong":"@c0335","denChuong":"","cachCoDuoc":"được Hàn Lập giao một nửa làm tín vật","trangThai":"đang giữ một nửa"}],"tabs":{"tienTrinh":[{"chuong":"@c0335","loai":"xuất hiện","importance":"normal","giaiDoan":"Lập tín vật cho Tôn gia","text":"Hàn Lập xé Không Bạch phù làm hai nửa, giao một nửa cho Tôn Nhị Cẩu để làm tín vật đời sau.","anchor":"liền lấy ra một lá Không Bạch phù bình thường, Roạt một tiếng, xé ra làm hai nửa"}]},"capNhatToi":"@c0335","nguon":["@c0335"]},{"id":"dan-tri-ngoai-thuong","name":"Đan trị ngoại thương","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Tôn Nhị Cẩu"],"trangThai":"được Hàn Lập ban cho Tôn Nhị Cẩu","blurb":"Đan trị ngoại thương là bình đan dược Hàn Lập tặng Tôn Nhị Cẩu. Công dụng được nêu là trị các loại ngoại thương, chỉ cần còn thở thì không chết.","detail":"Trong lúc lung lạc Tôn Nhị Cẩu, Hàn Lập đưa cho hắn một bình đan chuyên trị ngoại thương. Đây là vật bảo mệnh dành cho Tôn Nhị Cẩu và phe Tứ Bình bang sau khi quy thuận Hàn Lập.","phanLoaiPhu":"đan trị thương","congNang":["Trị các loại ngoại thương, chỉ cần còn thở là sẽ không chết @c0335"],"chuHienThoi":"Tôn Nhị Cẩu","chuSoHuu":[{"ten":"Tôn Nhị Cẩu","tuChuong":"@c0335","denChuong":"","cachCoDuoc":"được Hàn Lập tặng sau khi quy thuận","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0335","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập ban đan","text":"Hàn Lập tặng Tôn Nhị Cẩu một bình đan chuyên trị ngoại thương để bảo mệnh.","anchor":"Một bình chuyên trị liệu các loại ngoại thương, chỉ cần còn thở là sẽ không chết"}]},"capNhatToi":"@c0335","nguon":["@c0335"]},{"id":"thong-linh-ngoc","name":"Thông Linh ngọc","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc bội","phamCap":"trân bảo thế gian","soHuu":["Anh Trữ"],"trangThai":"đang thuộc Anh Trữ","blurb":"Thông Linh ngọc là một mảnh ngọc bội màu trắng, thuộc hàng trân bảo thế gian khó tìm, được Hàn Lập thu được sau vài lần đại chiến. Hắn đã tặng ngọc cho Anh Trữ làm quà kỷ niệm.","detail":"Thông Linh ngọc là chiến lợi phẩm Hàn Lập thu được sau vài lần đại chiến, được xếp vào hàng trân bảo hiếm có ở thế gian. Ngọc có hình dạng ngọc bội màu trắng, được Hàn Lập cất giữ trong túi trữ vật. Sau khi ôm Anh Trữ, Hàn Lập lấy Thông Linh ngọc ra tặng cho đứa bé làm kỷ niệm @c0336.","phanLoaiPhu":"ngọc bội","hinhDang":"mảnh ngọc bội màu trắng","nguonGoc":"chiến lợi phẩm Hàn Lập thu được sau vài lần đại chiến","congNang":["Đông ấm hạ mát @c0336","Bách trùng bất xâm @c0336"],"chuHienThoi":"Anh Trữ","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0336","denChuong":"@c0336","cachCoDuoc":"lấy từ chiến lợi phẩm trong túi trữ vật","trangThai":"đã tặng cho Anh Trữ"},{"ten":"Anh Trữ","tuChuong":"@c0336","denChuong":"","cachCoDuoc":"được Hàn Lập tặng làm kỷ niệm","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0336","loai":"đổi chủ","importance":"major","giaiDoan":"Tặng cho Anh Trữ","text":"Hàn Lập lấy Thông Linh ngọc từ túi trữ vật và tặng cho Anh Trữ làm kỷ niệm.","anchor":"có thể đông ấm hạ mát, bách trùng bất xâm"}]},"dinhDanh":"goc","capNhatToi":"@c0336","nguon":["@c0336"]},{"id":"toan-tam-trung","name":"Toàn tâm trùng","cn":"","aliases":[],"category":"khac","categoryLabel":"Trùng độc","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã cấy vào Ngũ Sắc môn chủ","blurb":"Trùng độc cực nhỏ được Hàn Lập dùng làm ám thủ với Ngũ Sắc môn chủ.","detail":"Hàn Lập âm thầm ký sinh Toàn tâm trùng vào thân thể Ngũ Sắc môn chủ. Trùng theo huyết mạch tới tim, khiến nạn nhân về sau đau tim, mất ngủ và chết giống bệnh tim phát tác, khó bị tu sĩ cao cấp lần ra.","phanLoaiPhu":"trùng độc ám sát","congNang":["Ký sinh trong thân thể, theo huyết mạch tới tim và tạo cái chết chậm giống bệnh tim phát tác @c0337"],"chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0337","denChuong":"","cachCoDuoc":"Đem dùng như ám thủ trong lúc vỗ vai Ngũ Sắc môn chủ.","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0337","loai":"dùng","importance":"normal","giaiDoan":"Ám thủ với Ngũ Sắc môn chủ","text":"Hàn Lập âm thầm cấy Toàn tâm trùng vào thân thể Ngũ Sắc môn chủ để tạo hậu hoạn chết chậm.","anchor":"đem một con “ Toàn tâm trùng” âm thầm ký sinh vào thân thể hắn"}]},"capNhatToi":"@c0337","nguon":["@c0337"]},{"id":"ngoc-gian-gui-linh-thu-son","name":"Ngọc giản gửi Linh Thú sơn","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản chứng cứ","phamCap":"Chưa rõ","soHuu":["Tu sĩ Ngự Linh Tông","Linh Thú sơn"],"trangThai":"Được giấu trong túi trữ vật ở sơn động @c0340","blurb":"Ngọc giản do bổn tông của tu sĩ Ngự Linh Tông gửi cho Linh Thú sơn, được Khúc Hồn giấu lại làm chứng cứ. Khi bị Hàn Lập ép hỏi, Khúc Hồn thừa nhận sự tồn tại của ngọc giản này và cho biết nó được cất trong túi trữ vật tại một sơn động gần đó.","detail":"Ngọc giản này là vật liên lạc giữa bổn tông của tu sĩ Ngự Linh Tông và Linh Thú sơn, ghi chép nội dung cấu kết hoặc kế hoạch giữa hai bên. Khúc Hồn đã lén giữ lại ngọc giản thay vì tiêu hủy, xem nó như bằng chứng về mưu đồ của Ma đạo. Khi Hàn Lập truy vấn, Khúc Hồn buộc phải khai ra sự tồn tại của ngọc giản và tiết lộ nơi cất giấu — nằm trong túi trữ vật được để tại một sơn động lân cận.","phanLoaiPhu":"Ngọc giản lưu tin tức","chuHienThoi":"Tu sĩ Ngự Linh Tông","congNang":["Lưu chứng cứ liên lạc hoặc kế hoạch giữa bổn tông của tu sĩ Ngự Linh Tông và Linh Thú sơn @c0340"],"chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0340","denChuong":"","cachCoDuoc":"Mang tin tức của bổn tông đến Việt quốc rồi giấu ngọc giản.","trangThai":"đang liên quan"}],"nguon":["@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"xuất hiện","importance":"major","giaiDoan":"Chứng cứ cấu kết","text":"Khúc Hồn thừa nhận đã giấu ngọc giản do bổn tông gửi cho Linh Thú sơn, dùng làm chứng cứ cho lời khai với Hàn Lập.","anchor":"ta đã giấu đi ngọc giản mà bổn tông gửi cho Linh Thú sơn"}]},"capNhatToi":"@c0340","dinhDanh":"goc"},{"id":"quy-xac","name":"Quy Xác","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"Đang được Hàn Lập dùng phòng thân @c0340","blurb":"Pháp khí phòng ngự Hàn Lập thả cùng Bạch Lân thuẫn khi đi vào sơn động. Nó được dùng để che trước người trong lúc quái vật phục kích.","detail":"Quy Xác xuất hiện như lớp phòng hộ đi kèm Bạch Lân thuẫn. Khi Hàn Lập nhận ra nguy hiểm trong sơn động, pháp khí này vẫn nằm trong số đồ phòng thân được hắn sử dụng.","phanLoaiPhu":"Pháp khí phòng hộ","hinhDang":"Quy xác","chuHienThoi":"Hàn Lập","congNang":["Che chắn trước người cùng Bạch Lân thuẫn khi vào sơn động @c0340"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0340","denChuong":"","cachCoDuoc":"Hàn Lập mang theo và thả ra phòng thân.","trangThai":"đang có"}],"nguon":["@c0340"],"tabs":{"tienTrinh":[{"chuong":"@c0340","loai":"dùng","importance":"normal","giaiDoan":"Phòng thân trong động","text":"Hàn Lập thả Quy Xác cùng Bạch Lân thuẫn để che trước người khi tiến vào sơn động.","anchor":"liền thả ra Bạch Lân thuẫn, cùng pháp khí Quy Xác che ở trước người","phamCap":"Pháp khí"}]},"capNhatToi":"@c0340","dinhDanh":"goc"},{"id":"bo-kim-nhan","name":"Bộ kim nhận","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí công kích","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"nhiều món bị hủy","blurb":"Bộ kim nhận là nhóm pháp khí công kích Hàn Lập dùng để vây công bọ ngựa yêu thú. Nhiều thanh bị song đao của yêu thú chấn nát hoặc chém đứt.","detail":"Trong lúc đối đầu bọ ngựa yêu thú, Hàn Lập phóng kim nhận vây công để kiềm chế đối thủ. Yêu thú dùng hai chi trước tạo thế phòng hộ, khiến nhiều kim nhận bị chấn nát hoặc đứt đoạn, làm Hàn Lập đau lòng vì bộ pháp khí này đã theo hắn nhiều năm.","congNang":["Công kích bằng nhiều kim nhận vây đánh mục tiêu @c0341"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0341","denChuong":"","cachCoDuoc":"Đã sở hữu từ trước","trangThai":"nhiều món bị hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c0341","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị bọ ngựa yêu thú phá hủy","text":"Bộ kim nhận của Hàn Lập bị bọ ngựa yêu thú chấn nát và chém đứt nhiều thanh trong lúc giao chiến.","anchor":"lại thêm hai kiện kim nhận bị đứt ra vài khúc"}]},"dinhDanh":"goc","capNhatToi":"@c0341","nguon":["@c0341"]},{"id":"an-linh-sa","name":"Ẩn Linh sa","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Áo choàng/pháp khí ẩn nấp","phamCap":"Không rõ","soHuu":["Hàn Lập","Tuyên Nhạc"],"trangThai":"Hàn Lập đang giữ","blurb":"Ẩn Linh sa là áo choàng lụa mỏng có thể che giấu khí tức và linh khí dao động. Hàn Lập dùng nó để ẩn thân trong rừng khi bị bọ ngựa yêu thú truy đuổi.","detail":"Ẩn Linh sa là chiến lợi phẩm Hàn Lập đoạt từ Tuyên Nhạc. Trong lúc bị bọ ngựa yêu thú truy sát, Hàn Lập khoác vật này lên người để ngăn cách linh khí dao động cùng hơi thở, hy vọng yêu thú không phát hiện tung tích sau khi hắn trốn vào rừng.","hinhDang":"Áo choàng lụa mỏng","congNang":["Ngăn cách linh khí dao động và các loại khí tức trên người người dùng @c0341","Hỗ trợ ẩn nấp trong rừng khi tránh sự truy tìm của yêu thú @c0341"],"chuSoHuu":[{"ten":"Tuyên Nhạc","tuChuong":"@c0341","denChuong":"@c0341","cachCoDuoc":"Chủ cũ được nhắc lại","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0341","denChuong":"","cachCoDuoc":"Chiến lợi phẩm đoạt từ Tuyên Nhạc","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0341","loai":"dùng","importance":"normal","giaiDoan":"Ẩn thân trong rừng","text":"Hàn Lập khoác Ẩn Linh sa để che giấu linh khí dao động và hơi thở sau khi dùng pháp khí cùng khôi lỗi đánh lạc hướng bọ ngựa yêu thú.","anchor":"ngăn cách tất cả các loại khí tức trên người Hàn Lập"}]},"dinhDanh":"goc","capNhatToi":"@c0341","nguon":["@c0341"]},{"id":"huyet-linh-toan","name":"Huyết Linh Toản","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"Đang được Hàn Lập sử dụng","blurb":"Pháp khí công kích được Hàn Lập nắm chặt và rót linh lực khi yêu thú bọ ngựa áp sát nơi ẩn thân. (+) Ám khí trên thân Khúc Hồn, phóng tia huyết quang có thể xuyên thủng cơ thể đối phương. [CAN-SOAT-GOP]","detail":"Hàn Lập dự định chờ yêu thú bọ ngựa đến thật gần mới phóng Huyết Linh Toản ra, nhằm tăng khả năng đả thương hoặc giết chết đối phương trong tình thế nguy cấp.","nguon":["@c0342","@c0426"],"tabs":{}},{"id":"luc-hoang-kiem","name":"Lục Hoàng Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"pháp bảo","soHuu":["Hàn Lập","Tu sĩ Ngự Linh Tông"],"trangThai":"Hàn Lập thu giữ, chưa thể sử dụng do chưa đạt Kết Đan","blurb":"Lục Hoàng Kiếm là một thanh tiểu kiếm màu xanh dài chừng một tấc, trên thân khắc hai chữ cổ \"Lục hoàng\". Từng được nguyên thần tu sĩ Kết Đan kỳ trong thân Khúc Hồn dùng để chặn Ô Long đoạt; sau khi chủ nhân bị diệt, Hàn Lập thu được và xem đây là pháp bảo đầu tiên của mình.","detail":"Lục Hoàng Kiếm lộ diện trong trận chiến khi nguyên thần Kết Đan kỳ ẩn trong thân Khúc Hồn dùng nó để đỡ chiêu Ô Long đoạt. Thanh kiếm có hình dáng tiểu kiếm màu xanh, dài khoảng một tấc, trên thân kiếm khắc hai chữ cổ \"Lục hoàng\". Khi chủ nhân — nguyên thần Kết Đan kỳ — bị diệt, pháp bảo mất người thao túng và bị áp chế. Hàn Lập nhận ra rằng với tu vi chưa đạt Kết Đan kỳ thì không thể sử dụng pháp bảo vô chủ, nên cẩn thận cất vào túi trữ vật, coi đây là pháp bảo đầu tiên mà mình sở hữu.","phanLoaiPhu":"tiểu kiếm màu xanh","hinhDang":"tiểu kiếm màu xanh dài chừng một tấc, thân kiếm khắc hai chữ cổ “Lục hoàng”","chuHienThoi":"Hàn Lập","capNhatToi":"@c0343","congNang":["Chặn được Ô Long đoạt khi có nguyên thần Kết Đan kỳ điều khiển @c0343"],"chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0343","denChuong":"@c0343","cachCoDuoc":"Đã có trước khi bị Hàn Lập diệt nguyên thần","trangThai":"mất quyền sở hữu do nguyên thần bị diệt"},{"ten":"Hàn Lập","tuChuong":"@c0343","denChuong":"","cachCoDuoc":"Thu lấy sau khi diệt nguyên thần chủ nhân cũ","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0343","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập thu được pháp bảo đầu tiên","text":"Lục Hoàng Kiếm lộ diện khi chặn Ô Long đoạt, sau đó mất chủ nhân thao túng vì nguyên thần Kết Đan kỳ bị Hàn Lập tiêu diệt. Hàn Lập chưa thể sử dụng pháp bảo vô chủ do chưa đạt Kết Đan, nhưng vẫn cẩn thận thu nó vào túi trữ vật.","phamCap":"pháp bảo","anchor":"Hàn Lập vô cùng yêu thích bèn ngắm nghía trong chốc lát mới đem “Lục Hoàng Kiếm” cẩn thận thu vào túi trữ vật, đây chính là kiện pháp bảo đầu tiên hắn có được a."}]},"nguon":["@c0343"],"uyLuc":"Đủ sức chặn đỡ chiêu Ô Long đoạt khi được nguyên thần Kết Đan kỳ vận dụng @c0343","dacDiem":"Tiểu kiếm màu xanh dài chừng một tấc, trên thân kiếm khắc hai chữ cổ \"Lục hoàng\"; cần tu vi Kết Đan kỳ trở lên mới có thể sử dụng"},{"id":"vien-dan-mau-xanh-biec","name":"Viên đan màu xanh biếc","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan hoàn","phamCap":"không rõ, nghi liên quan kim đan Kết Đan kỳ","soHuu":["Tu sĩ Ngự Linh Tông","Hàn Lập"],"trangThai":"bị Huyết Linh Toản đánh nổ, mảnh vỡ do Hàn Lập thu giữ","blurb":"Viên đan màu xanh biếc được nguyên thần trong thân Khúc Hồn phun ra để phát lục quang hộ thân và vô hiệu Dẫn Hồn chung. Sau khi bị Huyết Linh Toản đánh nổ, các mảnh vỡ được Hàn Lập thu lại vì nghi có quan hệ với kim đan Kết Đan kỳ.","detail":"Viên đan này phát ra lục quang nhu hòa bao bọc toàn thân Khúc Hồn, khiến tiếng chuông của Dẫn Hồn chung không phát huy tác dụng. Khi Hàn Lập đổi mục tiêu, Huyết Linh Toản đánh nổ viên đan, làm nguyên thần đối thủ đau đớn dữ dội và khiến lục quang hộ thân biến mất. Hàn Lập nhặt các mảnh vỡ còn lại vì đoán chúng có liên hệ tới kim đan của tu sĩ Kết Đan kỳ.","phanLoaiPhu":"đan hoàn hộ thân","hinhDang":"viên đan màu xanh biếc phát lục quang nhu hòa","chuHienThoi":"Hàn Lập","capNhatToi":"@c0343","congNang":["Phát lục quang hộ thân và khiến Dẫn Hồn chung của Hàn Lập vô hiệu @c0343","Khi bị đánh nổ, gây đau đớn trực tiếp từ sâu trong nguyên thần của người điều khiển @c0343"],"chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0343","denChuong":"@c0343","cachCoDuoc":"Được phun ra từ thân Khúc Hồn khi đối chiến với Hàn Lập","trangThai":"bị phá hủy"},{"ten":"Hàn Lập","tuChuong":"@c0343","denChuong":"","cachCoDuoc":"Nhặt các mảnh vỡ sau trận chiến","trangThai":"giữ mảnh vỡ"}],"tabs":{"tienTrinh":[{"chuong":"@c0343","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Hộ thân rồi bị phá","text":"Viên đan màu xanh biếc phát lục quang bảo vệ thân Khúc Hồn, làm Dẫn Hồn chung mất tác dụng. Hàn Lập dùng Huyết Linh Toản đánh nổ viên đan, khiến phòng hộ tan vỡ và nguyên thần đối thủ chịu đau đớn dữ dội.","phamCap":"không rõ","anchor":"Thấy một màn này, Hàn Lập vẻ mặt trở nên ngưng trọng, rõ ràng là viên đan màu xanh kia phát ra quang mang bảo vệ đối phương, khiến cho Dẫn Hồn chung của mình vô hiệu ."}]},"nguon":["@c0343"]},{"id":"khoi-loi","name":"Khôi lỗi","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Khôi lỗi thú","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang được Hàn Lập sử dụng @c0344","blurb":"Pháp bảo của Thương Khôn Thượng Nhân, tự bạo để tạo vụ nổ/chấn động che mắt đối phương, giúp hắn chạy thoát khi bị vây công năm nghìn năm trước. (+) Nhóm khôi lỗi được Hàn Lập thả ngoài Điên đảo ngũ hành trận để công kích và quấy nhiễu yêu thú bọ ngựa. [CAN-SOAT-GOP]","detail":"Trong trận diệt yêu, Hàn Lập dùng nhiều khôi lỗi liên tục công kích từ ngoài đại trận, khiến yêu thú bọ ngựa không thể nghỉ ngơi và hao hết thể lực. Hắn phải thay linh thạch nhiều lần để duy trì chúng.","congNang":["Công kích quấy nhiễu và tiêu hao địch trong phạm vi phối hợp với trận pháp @c0344"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"đã có và đem ra sử dụng trong trận diệt yêu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"dùng","importance":"normal","giaiDoan":"Quấy nhiễu yêu thú trong trận","text":"Hàn Lập thả nhiều khôi lỗi bên ngoài Điên đảo ngũ hành trận để liên tục công kích và tiêu hao yêu thú bọ ngựa.","anchor":"Hàn Lập liền thả ra một đống Khôi lỗi ở phía ngoài đại trận bắt đầu công kích"}]},"nguon":["@c0344","@c0684"]},{"id":"phu-bao-tieu-dao-mau-vang","name":"Phù bảo tiểu đao màu vàng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"phù bảo","soHuu":["Hàn Lập"],"trangThai":"đang được Hàn Lập sử dụng @c0344","blurb":"Phù bảo dạng tiểu đao màu vàng được Hàn Lập dùng làm đòn kết liễu yêu thú bọ ngựa.","detail":"Sau khi yêu thú bọ ngựa bị huyễn cảnh và khôi lỗi tiêu hao trong Điên đảo ngũ hành trận, Hàn Lập phát động phù bảo tiểu đao màu vàng. Một kích của nó xuyên qua đầu yêu thú và giết chết mục tiêu ngay trong đại trận.","uyLuc":"Có thể xuyên đầu yêu thú bọ ngựa đã suy kiệt trong đại trận.","congNang":["Tạo đòn công kích sắc bén dạng tiểu đao màu vàng để xuyên phá mục tiêu @c0344"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"đã có và đem ra sử dụng làm đòn kết liễu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"dùng","importance":"normal","giaiDoan":"Kết liễu yêu thú","text":"Hàn Lập phát động phù bảo tiểu đao màu vàng dưới sự yểm hộ của khôi lỗi và xuyên đầu yêu thú bọ ngựa.","anchor":"Hàn Lập liền phát động phù bảo tiểu đao màu vàng"}]},"nguon":["@c0344"]},{"id":"trung-yeu-thu-bo-ngua","name":"Trứng yêu thú bọ ngựa","cn":"","aliases":["Trứng Kim bối yêu lang"],"category":"nguyen-lieu","categoryLabel":"Trứng yêu thú","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"trứng chết @c0344","blurb":"Hơn mười quả trứng được Hàn Lập lấy từ bụng yêu thú bọ ngựa sau khi giết nó.","detail":"Hàn Lập kiểm tra thấy các quả trứng đều không còn hơi thở sinh mệnh, xác định là trứng chết. Dù vậy, hắn vẫn thu vào hộp ngọc vì cho rằng trứng chết của loài yêu thú bất thường này có thể còn diệu dụng.","dacDiem":"Không còn sinh cơ nhưng vẫn được giữ lại vì có thể còn công dụng.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"lấy từ bụng yêu thú bọ ngựa sau trận diệt yêu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu được sau khi mổ yêu thú","text":"Hàn Lập phát hiện hơn mười quả trứng trong bụng yêu thú bọ ngựa, kiểm tra thấy đều là trứng chết nhưng vẫn cất giữ.","anchor":"bên trong đều không có một chút hơi thở sinh mệnh"}]},"nguon":["@c0344"]},{"id":"tui-tru-vat-cua-tu-si-ngu-linh-tong","name":"Túi trữ vật của tu sĩ Ngự Linh Tông","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Túi trữ vật","phamCap":"không rõ","soHuu":["Tu sĩ Ngự Linh Tông","Hàn Lập"],"trangThai":"được Hàn Lập thu giữ @c0344","blurb":"Túi trữ vật của một tu sĩ Ngự Linh Tông, được Hàn Lập thu được từ di hài áo xám trong sơn động. Bên trong chứa chủ yếu vật dụng phục vụ bồi dưỡng kỳ trùng và yêu thú, không có pháp khí hay phù bảo giá trị.","detail":"Túi trữ vật này được tìm thấy còn nguyên bên hông di hài một tu sĩ Ngự Linh Tông mặc áo xám trong sơn động. Hàn Lập thu lấy và kiểm tra, phát hiện bên trong chủ yếu là thức ăn dành cho côn trùng và yêu thú, nhiều bình chứa mẫu côn trùng cùng lục sắc ngọc giản. Không có phù lục cấp cao, pháp khí hay phù bảo như hắn kỳ vọng, phản ánh đặc thù của tu sĩ Ngự Linh Tông chuyên nuôi dưỡng linh trùng linh thú hơn là sưu tầm pháp khí.","dacDiem":"Chứa vật dụng phục vụ bồi dưỡng kỳ trùng và yêu thú.","chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0344","denChuong":"@c0344","cachCoDuoc":"vật để lại trên di hài cũ","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"lấy từ bên hông di hài áo xám trong sơn động","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập thu giữ","text":"Hàn Lập phát hiện túi trữ vật còn nguyên bên hông di hài tu sĩ Ngự Linh Tông và lấy được các vật liên quan đến kỳ trùng bên trong.","anchor":"bên hông còn nguyên vẹn một cái tũi trữ vật"}]},"nguon":["@c0344"]},{"id":"luc-dan","name":"Lục đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Lõi linh khí","phamCap":"không rõ","soHuu":["Tu sĩ Ngự Linh Tông"],"trangThai":"được nguyên thần tu sĩ Ngự Linh Tông mang đi @c0344","blurb":"Viên lục đan được tu sĩ Ngự Linh Tông ngưng tụ từ linh khí trong kim đan khi bỏ thân thể cũ.","detail":"Khi thân thể sắp tiêu vong, tu sĩ Ngự Linh Tông đem non nửa linh khí trong kim đan ngưng tụ thành lục đan rồi để nguyên thần mang theo cùng Lục Hoàng Kiếm rời đi.","nguonGoc":"Được ngưng tụ từ non nửa linh khí trong kim đan của tu sĩ Ngự Linh Tông.","chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"tự ngưng tụ trước khi nguyên thần thoát ra","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ khi thoát nguyên thần","text":"Tu sĩ Ngự Linh Tông ngưng tụ lục đan từ linh khí trong kim đan trước khi nguyên thần rời thân thể cũ.","anchor":"đem non nửa linh khí ở trong kim đan ngưng tụ thành viên lục đan"}]},"nguon":["@c0344"]},{"id":"luc-sac-ngoc-gian","name":"Lục sắc ngọc giản","cn":"","aliases":["Ngọc giản tâm đắc kỳ trùng"],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Tu sĩ Ngự Linh Tông","Hàn Lập"],"trangThai":"được Hàn Lập thu giữ @c0344","blurb":"Ngọc giản màu lục ghi tâm đắc bồi dưỡng kỳ trùng và bí pháp điều khiển của tu sĩ Ngự Linh Tông.","detail":"Hàn Lập tìm được lục sắc ngọc giản ở đáy túi trữ vật. Nội dung ghi tâm đắc bồi dưỡng kỳ trùng, hơn ngàn chủng loại côn trùng kỳ lạ, bí pháp bồi dưỡng và điều khiển, kèm bảng xếp hạng yêu trùng trong đó Kim bối yêu lang đứng thứ bảy mươi ba.","congNang":["Lưu giữ tâm đắc bồi dưỡng kỳ trùng, bí pháp điều khiển và bảng xếp hạng yêu trùng @c0344"],"chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0344","denChuong":"@c0344","cachCoDuoc":"vật trong túi trữ vật để lại","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"tìm thấy trong túi trữ vật của tu sĩ Ngự Linh Tông","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập đọc ngọc giản","text":"Hàn Lập thu được ngọc giản ghi tâm đắc bồi dưỡng kỳ trùng, bí pháp điều khiển và bảng xếp hạng yêu trùng.","anchor":"Hàn Lập cũng tìm được một cái lục sắc ngọc giản"}]},"nguon":["@c0344"]},{"id":"mau-con-trung-trong-tui-tru-vat","name":"Mẫu côn trùng trong túi trữ vật","cn":"","aliases":["Các bình mẫu côn trùng"],"category":"nguyen-lieu","categoryLabel":"Kỳ trùng","phamCap":"không rõ","soHuu":["Tu sĩ Ngự Linh Tông","Hàn Lập"],"trangThai":"nhiều mẫu còn sống @c0344","blurb":"Các bình mẫu côn trùng được Hàn Lập tìm thấy trong túi trữ vật của tu sĩ Ngự Linh Tông.","detail":"Dù nhiều năm không ai nuôi dưỡng, hơn phân nửa côn trùng trong các bình vẫn còn sống. Hàn Lập đối chiếu lục sắc ngọc giản thấy đa số xếp hạng không cao, nhưng chúng vẫn thuộc loại kỳ trùng hiếm có.","dacDiem":"Sinh mệnh lực ngoan cường, nhiều loại vẫn sống sau thời gian dài bị bỏ lại.","chuSoHuu":[{"ten":"Tu sĩ Ngự Linh Tông","tuChuong":"@c0344","denChuong":"@c0344","cachCoDuoc":"mẫu côn trùng cất trong túi trữ vật","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0344","denChuong":"","cachCoDuoc":"lấy từ túi trữ vật của tu sĩ Ngự Linh Tông","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0344","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện trong túi trữ vật","text":"Hàn Lập phát hiện nhiều bình mẫu côn trùng trong túi trữ vật, trong đó hơn phân nửa vẫn còn sống.","anchor":"hơn phân nửa côn trùng trong bình đều còn sống"}]},"nguon":["@c0344"]},{"id":"bach-tri-chu","name":"Bạch Tri chu","cn":"","aliases":["Huyết Ngọc tri chu"],"category":"khac","categoryLabel":"Linh trùng yêu thú","phamCap":"Yêu thú bậc một cấp thấp @c0345","soHuu":["Hàn Lập"],"trangThai":"đã nở","blurb":"Bạch Tri chu là hai linh trùng nở từ trứng trong mật thất Linh Nhãn chi tuyền của Hàn Lập. Chúng trong suốt, thân cận Hàn Lập và khi mới nở đã có tu vi Luyện Khí kỳ tầng ba, tầng bốn.","detail":"Hai Bạch Tri chu non được Hàn Lập nhận ra có liên hệ với kỳ trùng Huyết Ngọc tri chu. Dù thứ hạng không cao bằng Kim bối yêu lang, chúng vẫn là loại kỳ trùng hiếm thấy và có tiềm lực đáng chú ý.","dinhDanh":"goc","phanLoaiPhu":"Linh trùng, yêu thú","hinhDang":"Hai nhện non trong suốt","chuHienThoi":"Hàn Lập","uyLuc":"Khi mới nở đã đạt Luyện Khí kỳ tầng ba và tầng bốn, thuộc yêu thú bậc một cấp thấp.","dacDiem":"Thân cận Hàn Lập do Khống Thần cấm chế bằng tinh huyết phát huy tác dụng.","congNang":["Linh trùng có thể được Hàn Lập mang theo nuôi dạy và bồi dưỡng @c0345"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0345","denChuong":"","cachCoDuoc":"Trứng nở trong động phủ, chịu Khống Thần cấm chế bằng tinh huyết","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0345","loai":"xuất hiện","importance":"normal","giaiDoan":"Nở thành linh trùng","text":"Hai trứng Bạch Tri chu nở thành nhện non trong mật thất Linh Nhãn chi tuyền và thân cận Hàn Lập.","anchor":"hai quả trứng nhện đã ấp nở thành công","phamCap":"Yêu thú bậc một cấp thấp"}]},"capNhatToi":"@c0345","nguon":["@c0345"]},{"id":"kinh-long-chung","name":"Kinh Long chung","cn":"","aliases":["Ngân sắc cự chung"],"category":"khac","categoryLabel":"Chuông báo động tông môn","phamCap":"Không rõ","soHuu":["Hoàng Phong Cốc"],"trangThai":"đã vang báo động @c0345","blurb":"Kinh Long chung là chuông báo động của Hoàng Phong Cốc. Tám mươi mốt tiếng chuông vang lên từ hướng Nghị Sự điện, được xác nhận là dấu hiệu diệt môn, biểu thị nguy cơ tồn vong cấp tông môn. (+) Ngân sắc cự chung của Hàn Lập, một tiếng chuông khiến Trúc Cơ kỳ choáng váng, Luyện Khí kỳ bất tỉnh. [CAN-SOAT-GOP]","detail":"Kinh Long chung là pháp khí trấn phái dùng để cảnh báo đại nạn của Hoàng Phong Cốc. Chuông phát ra từ hướng Nghị Sự điện, khi vang đủ tám mươi mốt hồi thì biểu thị tình thế cực nguy — hoặc đại bại tiền phương, hoặc nguy cơ tồn vong của tông môn. Theo lời Mã sư huynh giải thích, số tiếng chuông tám mươi mốt chính là dấu hiệu diệt môn, mức cảnh báo cao nhất.","dinhDanh":"goc","chuHienThoi":"Hoàng Phong Cốc","uyLuc":"Tám mươi mốt tiếng chuông biểu thị dấu hiệu diệt môn.","dacDiem":"Dùng để báo đại nạn cấp tông môn từ hướng Nghị Sự điện.","congNang":["Báo hiệu nguy cơ diệt môn hoặc tình thế cực nguy của Hoàng Phong Cốc, bằng cách vang đủ tám mươi mốt tiếng chuông @c0345"],"chuSoHuu":[{"ten":"Hoàng Phong Cốc","tuChuong":"@c0345","denChuong":"","cachCoDuoc":"Chuông báo động đặt trong hệ thống cảnh báo tông môn","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0345","loai":"dùng","importance":"major","giaiDoan":"Tám mươi mốt tiếng","text":"Kinh Long chung vang tám mươi mốt tiếng từ hướng Nghị Sự điện, báo hiệu nguy cơ diệt môn của Hoàng Phong Cốc.","anchor":"tám mươi mốt tiếng chuông của Kinh Long chung","phamCap":"Không rõ"}]},"capNhatToi":"@c0345","nguon":["@c0345","@c0745"]},{"id":"tui-tru-phu-luc","name":"Túi trữ phù lục","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập thu hồi khi rời động phủ @c0347","blurb":"Túi trữ phù lục được Hàn Lập cất dưới giường trong phòng ngủ tại động phủ. Khi chuẩn bị triệt ly, hắn lấy túi này mang đi.","detail":"Trong quá trình thu dọn động phủ trước khi rời Hoàng Phong Cốc, Hàn Lập lấy ra túi trữ phù lục được giấu dưới giường. Vật này thuộc nhóm đồ mang theo khi hắn xóa dấu vết động phủ.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0347","denChuong":"","cachCoDuoc":"Thu từ nơi cất dưới giường trong động phủ của mình","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0347","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu dọn động phủ","text":"Hàn Lập lấy túi trữ phù lục dưới giường khi chuẩn bị rời động phủ.","anchor":"lấy ra túi trữ phù lục dưới giường"}]},"nguon":["@c0347"]},{"id":"phi-kiem-truyen-tin-kem-ngoc-gian","name":"Phi kiếm truyền tin kèm ngọc giản","cn":"","aliases":[],"category":"khac","categoryLabel":"Truyền tin pháp khí","phamCap":"Không rõ","soHuu":["Hoàng sư thúc"],"trangThai":"đã truyền tin truy kích của Ma đạo @c0347","blurb":"Phi kiếm truyền tin kèm ngọc giản là vật báo tin khẩn xuất hiện trong lúc đội triệt ly rời Thái nhạc sơn mạch. Nó mang tin Ma đạo đã chia quân vây Hoàng Phong Cốc và truy kích đoàn rút lui.","detail":"Một đạo bạch quang bay tới tay Hoàng sư thúc, hiện thành tiểu kiếm lấp lóe kèm ngọc giản. Tin trong ngọc giản khiến đội rút lui phải chia người ở lại đánh lạc hướng Ma đạo.","congNang":["Truyền tin khẩn bằng tiểu kiếm bạch quang kèm ngọc giản @c0347"],"chuSoHuu":[{"ten":"Hoàng sư thúc","tuChuong":"@c0347","denChuong":"","cachCoDuoc":"Nhận giữa đường khi dẫn đội triệt ly","trangThai":"đã nhận tin"}],"tabs":{"tienTrinh":[{"chuong":"@c0347","loai":"xuất hiện","importance":"normal","giaiDoan":"Tin truy kích","text":"Phi kiếm truyền tin bay tới tay Hoàng sư thúc, mang ngọc giản báo Ma đạo đang chia quân truy kích.","anchor":"đó là một thanh tiểu kiếm bạch quang lấp lóe"}]},"nguon":["@c0347"]},{"id":"ngoc-gian-ban-do-mau-xanh-biec","name":"Ngọc giản bản đồ màu xanh biếc","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản bản đồ","phamCap":"Không rõ","soHuu":["Hoàng sư thúc","Hàn Lập"],"trangThai":"phát cho nhóm Trúc Cơ ở lại đánh lạc hướng @c0347","blurb":"Ngọc giản bản đồ màu xanh biếc được Hoàng sư thúc phát cho nhóm hơn hai mươi tu sĩ Trúc Cơ ở lại cản Ma đạo. Người nhận phải ghi nhớ bản đồ rồi hủy đi để dùng khi thất lạc cần tụ tập.","detail":"Sau khi chọn nhóm ở lại đánh lạc hướng, Hoàng sư thúc phát hơn hai mươi khối ngọc giản bản đồ màu xanh biếc. Hàn Lập cũng nhận một khối nhưng chỉ xem qua vì đã có ý định nhân cơ hội này tách khỏi Hoàng Phong Cốc.","congNang":["Ghi bản đồ và điểm tụ tập cho nhóm ở lại sau khi thất lạc @c0347"],"chuSoHuu":[{"ten":"Hoàng sư thúc","tuChuong":"@c0347","denChuong":"@c0347","cachCoDuoc":"Mang theo để phát cho nhóm Trúc Cơ được chọn","trangThai":"đã phát"},{"ten":"Hàn Lập","tuChuong":"@c0347","denChuong":"","cachCoDuoc":"Nhận từ Hoàng sư thúc trong nhóm ở lại đánh lạc hướng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0347","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát bản đồ","text":"Hoàng sư thúc phát ngọc giản bản đồ cho nhóm Trúc Cơ ở lại, yêu cầu ghi nhớ rồi hủy đi.","anchor":"Ngọc giản này là bản đồ, nhớ kĩ rồi hủy đi"}]},"nguon":["@c0347"]},{"id":"phong-van-phien","name":"Phong Vân phiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"khong-ro","soHuu":["Hoàng sư thúc"],"trangThai":"bị hủy","blurb":"Phong Vân phiên là lá cờ nhỏ trắng như tuyết phát hoàng quang, do Hoàng sư thúc của Hoàng Phong Cốc sở hữu. Pháp bảo có khả năng tạo mây mù rộng lớn để che giấu hành tung cả đội tu sĩ, nhưng đã bị kích nổ trong trận giao chiến với Ma đạo và phóng sương trắng dày đặc che phủ toàn chiến trường.","detail":"Phong Vân phiên là pháp bảo hình lá cờ nhỏ màu trắng như tuyết, khi kích hoạt phát ra hoàng quang. Hoàng sư thúc sử dụng nó để tạo đám mây trắng rộng hơn mười trượng, bao phủ Hàn Lập cùng các tu sĩ Trúc Cơ kỳ Hoàng Phong Cốc rồi lẫn vào mây trời nhằm che giấu hành tung. Khi cục diện chuyển biến bất lợi, ông phất cờ làm sương mù tiêu tan để lộ đội hình. Tuy nhiên, Phong Vân phiên không đủ sức ngăn đội Hoàng Phong Cốc khỏi bị Ma đạo phản phục kích. Trong trận chiến tại chương 349, pháp bảo phát hoàng quang rồi nổ tung, phóng ra sương trắng dày đặc che phủ toàn bộ chiến trường, sau đó bị hư tổn.","phanLoaiPhu":"Lá cờ nhỏ","hinhDang":"Trắng như tuyết, phát hoàng quang","chuHienThoi":"Hoàng sư thúc","dacDiem":"Có thể tạo mây mù che giấu hành tung, nhưng không ngăn được việc đội Hoàng Phong Cốc bị Ma đạo phản phục kích.","congNang":["Tạo đám mây trắng rộng hơn mười trượng bao phủ nhiều người để che giấu hành tung, lẫn vào mây trời @c0348","Chủ nhân phất cờ có thể làm sương mù tiêu tan, giải trừ hiệu ứng che phủ @c0348","Khi bị kích nổ, phóng ra sương trắng dày đặc che phủ toàn bộ chiến trường @c0349"],"chuSoHuu":[{"ten":"Hoàng sư thúc","tuChuong":"@c0348","denChuong":"@c0349","cachCoDuoc":"Đang cầm trong tay khi giao chiến với Ma đạo","trangThai":"đã hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c0348","loai":"dùng","importance":"normal","giaiDoan":"Che giấu đội phục kích","text":"Hoàng sư thúc dùng Phong Vân phiên tạo mây trắng che giấu hành tung nhóm Trúc Cơ kỳ Hoàng Phong Cốc.","anchor":"Ta sẽ dùng Phong Vân phiên này che giấu hành tung của mấy vị sư điệt"},{"chuong":"@c0349","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Tự hủy mở đường","phamCap":"Không rõ","text":"Phong Vân phiên trong tay Hoàng sư thúc phát hoàng quang rồi nổ tung, phóng sương trắng che phủ chiến trường và giúp tu sĩ Hoàng Phong Cốc có cơ hội tháo chạy.","anchor":"Phong Vân phiên trong tay Hoàng sư thúc phát ra hoàng quang chói mắt rồi đột nhiên biến đổi, nổ tung"}]},"capNhatToi":"@c0348","nguon":["@c0348","@c0349"],"uyLuc":"Khi nổ tung phát hoàng quang, phóng sương trắng dày đặc đủ sức che phủ toàn bộ chiến trường @c0349"},{"id":"linh-thach-mau-lam","name":"Linh thạch màu lam","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Linh thạch","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Linh thạch màu lam được Hàn Lập lấy ra để bổ sung pháp lực sau khi thoát khỏi vòng vây Ma đạo. Nó giúp hắn khôi phục trong lúc Khúc Hồn đứng canh gác.","detail":"Sau khi dùng nhiều pháp lực để duy trì vòng bảo hộ và bỏ chạy, Hàn Lập hạ xuống một nơi bí mật dưới núi hoang. Hắn lấy linh thạch màu lam trong túi trữ vật ra để khôi phục pháp lực trước khi tiếp tục hành trình sang Nguyên Vũ Quốc.","phanLoaiPhu":"linh thạch","congNang":["Bổ sung pháp lực cho Hàn Lập sau khi phá vòng vây @c0349"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0349","denChuong":"@c0349","cachCoDuoc":"Lấy ra từ túi trữ vật","trangThai":"đã dùng"}],"capNhatToi":"@c0349","tabs":{"tienTrinh":[{"chuong":"@c0349","loai":"dùng","importance":"normal","giaiDoan":"Khôi phục pháp lực","phamCap":"Không rõ","text":"Hàn Lập lấy linh thạch màu lam trong túi trữ vật ra để bổ sung pháp lực sau khi thoát khỏi truy kích.","anchor":"Sau đó, hắn liền lấy bên trong túi trữ vật ra một viên linh thạch màu lam"}]},"nguon":["@c0349"]},{"id":"phap-bao-hinh-dong-tien","name":"Pháp bảo hình đồng tiền","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí phòng ngự","phamCap":"Không rõ","soHuu":["Lão giả Phó gia","Hàn Lập"],"trangThai":"Hàn Lập thu giữ @c0350","blurb":"Pháp bảo hình đồng tiền là một pháp khí phòng ngự do lão giả họ Phó sử dụng trong trận giao chiến với Hàn Lập. Sau khi lão giả bị giết, Hàn Lập thu lấy và đánh giá đây là pháp khí phòng ngự hiếm thấy.","detail":"Pháp bảo này vốn thuộc về một lão giả tu sĩ Phó gia. Trong lúc bị Hàn Lập tập kích, lão giả đã tung pháp bảo hình đồng tiền ra để chống đỡ, song cuối cùng vẫn tử trận. Hàn Lập sau đó lục soát hai túi trữ vật của lão, coi pháp bảo hình đồng tiền là chiến lợi phẩm nổi bật nhất, và nhận xét đây là loại pháp khí phòng ngự hiếm thấy.","phanLoaiPhu":"pháp khí phòng ngự","hinhDang":"hình đồng tiền, khi thúc động phình lớn như mặt bàn","uyLuc":"Có thể dùng để chống đỡ công kích diện rộng trong lúc giao chiến.","dacDiem":"Được Hàn Lập coi là pháp khí phòng ngự hiếm thấy.","chuHienThoi":"Hàn Lập","congNang":["Khi được kích hoạt, phình lớn như mặt bàn để chắn đỡ công kích trước mặt, đóng vai trò phòng ngự diện rộng trong chiến đấu @c0350"],"chuSoHuu":[{"ten":"Lão giả Phó gia","tuChuong":"@c0350","denChuong":"@c0350","cachCoDuoc":"đem ra sử dụng khi bị Hàn Lập tập kích","trangThai":"mất sau khi bị giết"},{"ten":"Hàn Lập","tuChuong":"@c0350","denChuong":"","cachCoDuoc":"thu lấy từ chiến lợi phẩm của lão giả Phó gia","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0350","loai":"đổi chủ","importance":"major","giaiDoan":"Chiến lợi phẩm Phó gia","text":"Lão giả Phó gia tung pháp bảo hình đồng tiền để phòng ngự khi bị Hàn Lập tập kích, nhưng sau khi lão chết thì Hàn Lập thu lấy vật này.","anchor":"một pháp bảo hình đồng tiền bay ra, đảo mắt phình to ra như mặt bàn","phamCap":"Không rõ"}]},"dinhDanh":"goc","capNhatToi":"@c0350","nguon":["@c0350"]},{"id":"hai-hop-ngoc-cua-tan-nhu-am","name":"Hai hộp ngọc của Tân Như Âm","cn":"","aliases":[],"category":"khac","categoryLabel":"Hộp chứa điển tịch","phamCap":"không rõ","soHuu":["Tân Như Âm","Hàn Lập"],"trangThai":"đã giao cho Hàn Lập","blurb":"Hai hộp ngọc do Tân Như Âm lấy ra để giao cho Hàn Lập.","detail":"Hai hộp ngọc chứa Vân Tiêu tâm đắc, các điển tịch luyện khí của Tề Vân Tiêu, cùng tâm huyết trận pháp và sách liên quan của Tân Như Âm.","congNang":["Lưu giữ và chuyển giao điển tịch luyện khí, trận pháp @c0351"],"chuSoHuu":[{"ten":"Tân Như Âm","tuChuong":"@c0351","denChuong":"@c0351","cachCoDuoc":"lấy từ túi trữ vật của mình","trangThai":"đã giao ra"},{"ten":"Hàn Lập","tuChuong":"@c0351","denChuong":"","cachCoDuoc":"được Tân Như Âm giao để đổi lời hứa báo thù","trangThai":"nhận giữ"}],"dinhDanh":"goc","capNhatToi":"@c0351","tabs":{"tienTrinh":[{"chuong":"@c0351","loai":"đổi chủ","importance":"normal","giaiDoan":"giao cho Hàn Lập","text":"Tân Như Âm lấy hai hộp ngọc từ túi trữ vật đặt lên bàn để giao cho Hàn Lập.","anchor":"lập tức lấy ra hai cái hộp ngọc từ trong túi trữ vật đặt lên trên bàn"}]},"nguon":["@c0351"]},{"id":"van-tieu-tam-dac","name":"Vân Tiêu tâm đắc","cn":"","aliases":[],"category":"khac","categoryLabel":"Điển tịch luyện khí","phamCap":"không rõ","soHuu":["Tề Vân Tiêu","Tân Như Âm","Hàn Lập"],"trangThai":"đã giao cho Hàn Lập","blurb":"Tâm đắc luyện khí của Tề Vân Tiêu cùng các điển tịch luyện khí hắn thu thập.","detail":"Vân Tiêu tâm đắc được đặt trong một hộp ngọc, đi kèm các điển tịch luyện khí do Tề Vân Tiêu thu thập, rồi được Tân Như Âm giao cho Hàn Lập.","dacDiem":"Tâm đắc luyện khí của Tề Vân Tiêu.","congNang":["Ghi lại tâm đắc luyện khí và điển tịch luyện khí do Tề Vân Tiêu thu thập @c0351"],"chuSoHuu":[{"ten":"Tề Vân Tiêu","tuChuong":"@c0351","denChuong":"@c0351","cachCoDuoc":"tâm đắc và điển tịch do hắn lưu lại","trangThai":"đã mất"},{"ten":"Tân Như Âm","tuChuong":"@c0351","denChuong":"@c0351","cachCoDuoc":"giữ lại sau khi Tề Vân Tiêu chết","trangThai":"đã giao ra"},{"ten":"Hàn Lập","tuChuong":"@c0351","denChuong":"","cachCoDuoc":"được Tân Như Âm giao","trangThai":"nhận giữ"}],"dinhDanh":"goc","capNhatToi":"@c0351","tabs":{"tienTrinh":[{"chuong":"@c0351","loai":"đổi chủ","importance":"normal","giaiDoan":"chuyển giao điển tịch","text":"Tân Như Âm giao Vân Tiêu tâm đắc và các điển tịch luyện khí của Tề Vân Tiêu cho Hàn Lập.","anchor":"trong một cái là quyển “Vân Tiêu tâm đắc” và các điển tịch luyện khí mà hắn thu thập"}]},"nguon":["@c0351"]},{"id":"tai-lieu-bach-tri-chu","name":"Tài liệu Bạch Tri chu","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"Tài liệu yêu thú cấp bốn","soHuu":["Hàn Lập"],"trangThai":"Đang được chuẩn bị luyện chế","blurb":"Tài liệu lấy từ Bạch Tri chu, gồm phần thi thể ngoài và chân nhện. Hàn Lập dự định giao cho Từ điếm chủ luyện thành một bộ pháp khí công kích.","detail":"Hàn Lập lấy tài liệu Bạch Tri chu ra cho Từ điếm chủ xem, nói rõ đây là tài liệu yêu thú cấp bốn. Phần chân nhện được hắn chỉ định dùng để luyện thành một bộ pháp khí công kích theo yêu cầu đặc thù.","phanLoaiPhu":"tài liệu luyện khí","chuHienThoi":"Hàn Lập","congNang":["Dùng để luyện pháp khí công kích @c0353"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0353","denChuong":"","cachCoDuoc":"Lấy từ Bạch Tri chu","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"xuất hiện","importance":"normal","giaiDoan":"Giao thợ luyện khí xem xét","text":"Hàn Lập đưa tài liệu Bạch Tri chu cho Từ điếm chủ xem và yêu cầu luyện chân nhện thành pháp khí công kích.","anchor":"đem mấy cái chân của con nhện luyện thành một bộ pháp khí công kích"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"tai-lieu-bo-ngua-yeu-thu-cap-bon-dinh-giai","name":"Tài liệu bọ ngựa yêu thú cấp bốn đỉnh giai","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài liệu luyện khí","phamCap":"Yêu thú cấp bốn đỉnh giai","soHuu":["Hàn Lập"],"trangThai":"Đang được chuẩn bị luyện chế","blurb":"Tài liệu lấy từ bọ ngựa yêu thú cấp bốn đỉnh giai, gồm chân trước và đôi cánh. Chất liệu cao cấp này khiến Từ điếm chủ cực kỳ hưng phấn.","detail":"Hàn Lập đưa ra tài liệu từ bọ ngựa lớn và nói rõ con yêu thú này đạt cấp bốn đỉnh giai. Từ điếm chủ đặc biệt cuồng nhiệt vì có cơ hội tự tay luyện chế loại tài liệu cao cấp hiếm gặp.","phanLoaiPhu":"tài liệu luyện khí","chuHienThoi":"Hàn Lập","congNang":["Dùng làm tài liệu luyện chế pháp khí theo yêu cầu riêng của Hàn Lập @c0353"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0353","denChuong":"","cachCoDuoc":"Lấy từ bọ ngựa yêu thú cấp bốn đỉnh giai","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"xuất hiện","importance":"normal","giaiDoan":"Đưa thợ luyện khí xem xét","text":"Hàn Lập giới thiệu tài liệu bọ ngựa là từ yêu thú cấp bốn đỉnh giai, khiến Từ điếm chủ đặc biệt muốn luyện chế.","anchor":"con sau là yêu thú cấp bốn đỉnh giai"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"phap-khi-dinh-giai-trong-phuong-thi-nguyen-vu-quoc","name":"Pháp khí đỉnh giai trong phường thị Nguyên Vũ quốc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh giai","soHuu":[],"trangThai":"Đang lưu thông trong phường thị","blurb":"Các pháp khí đỉnh giai xuất hiện nhiều trong phường thị Nguyên Vũ quốc sau khi tin chiến bại lan đến. Chúng phản ánh làn sóng tu sĩ đổi vật để tăng sức tự vệ.","detail":"Do giới tu tiên Nguyên Vũ quốc hoang mang trước tin thảm bại, nhiều tu sĩ mang pháp khí tốt ra giao dịch. Hàn Lập nhận thấy số pháp khí đỉnh giai xuất hiện lần này nhiều hơn trước.","phanLoaiPhu":"pháp khí giao dịch","dacDiem":"Xuất hiện nhiều hơn trong phường thị khi tình hình chiến sự lan rộng.","congNang":["Được tu sĩ mua bán để tăng thực lực tự bảo vệ @c0353"],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"nhắc tới","importance":"normal","giaiDoan":"Phường thị hưng vượng","text":"Nhiều pháp khí đỉnh giai xuất hiện trong các cửa hàng ở phường thị Nguyên Vũ quốc.","anchor":"xuất hiện không ít đỉnh giai pháp khí"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"duoc-tai-la-han-lap-thu-mua","name":"Dược tài lạ Hàn Lập thu mua","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Dược tài","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đã mua được","blurb":"Vài loại dược tài Hàn Lập chưa từng gặp trước đây, mua được khi dạo quanh phường thị Nguyên Vũ quốc. Chúng là thu hoạch phụ trước khi hắn đến Tinh Trần các.","detail":"Hàn Lập đi qua nhiều cửa hàng trong phường thị và thu được một số dược tài lạ. Chương chưa nêu tên hay công dụng cụ thể của các dược tài này.","phanLoaiPhu":"dược tài","chuHienThoi":"Hàn Lập","dacDiem":"Là những loại dược tài Hàn Lập trước đó chưa từng thấy.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0353","denChuong":"","cachCoDuoc":"Mua trong phường thị Nguyên Vũ quốc","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu mua trong phường thị","text":"Hàn Lập dạo quanh các cửa hàng và mua được vài loại dược tài trước đây chưa từng thấy.","anchor":"thu về được vài loại dược tài mà trước đó chưa từng thấy"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"tran-pham-tinh-tran-cac","name":"Trân phẩm Tinh Trần các","cn":"","aliases":[],"category":"khac","categoryLabel":"Trân phẩm","phamCap":"Chưa rõ","soHuu":["Tinh Trần các"],"trangThai":"Sắp được đưa ra cho khách xem","blurb":"Nhóm hàng cao cấp của Tinh Trần các mà Hàn Lập muốn mua, có thể là pháp khí hoặc phù lục. Phụ nhân tầng năm hứa sẽ lấy ra cho Hàn Lập và nam tử Trúc Cơ kỳ xem.","detail":"Hàn Lập nói rõ hắn muốn mua trân phẩm chân chính, bất kể là pháp khí hay phù lục. Phụ nhân trung niên tầng năm đáp rằng Tinh Trần các có thể làm vừa lòng khách nếu đủ sức mua.","phanLoaiPhu":"pháp khí hoặc phù lục cao cấp","chuHienThoi":"Tinh Trần các","congNang":["Là nhóm vật phẩm cao cấp được đưa ra cho tu sĩ cấp cao lựa chọn @c0353"],"tabs":{"tienTrinh":[{"chuong":"@c0353","loai":"xuất hiện","importance":"normal","giaiDoan":"Khách hỏi mua","text":"Hàn Lập yêu cầu mua trân phẩm thật sự của Tinh Trần các, bất kể pháp khí hay phù lục.","anchor":"mặc kệ là pháp khí hay phù lục"}]},"capNhatToi":"@c0353","nguon":["@c0353"]},{"id":"khan-to-mau-hong","name":"Khăn tơ màu hồng","cn":"","aliases":["Khăn tơ hồng"],"category":"khac","categoryLabel":"Vật phẩm che khay","phamCap":"Không rõ","soHuu":["Tinh Trần các"],"trangThai":"đang dùng","blurb":"Khăn tơ phủ lên khay trân phẩm của Tinh Trần các. Vật này có khả năng ngăn thần thức dò xét đồ vật bên trong khay.","detail":"Khăn tơ màu hồng nhìn bình thường nhưng khiến Hàn Lập bất ngờ khi dùng thần thức dò xét khay trân phẩm. Tu sĩ họ Phiền cũng có phản ứng kinh ngạc, cho thấy khăn có công năng che chắn thần thức trong giao dịch.","phanLoaiPhu":"vật phẩm che chắn","hinhDang":"khăn tơ màu hồng phủ trên khay","chuHienThoi":"Tinh Trần các","capNhatToi":"@c0354","congNang":["Ngăn thần thức dò xét vật phẩm trên khay trân phẩm @c0354"],"chuSoHuu":[{"ten":"Tinh Trần các","tuChuong":"@c0354","denChuong":"","cachCoDuoc":"Được dùng trong lúc bày trân phẩm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0354","loai":"xuất hiện","importance":"normal","giaiDoan":"Che khay trân phẩm","text":"Khăn tơ màu hồng phủ khay trân phẩm và cản thần thức của Hàn Lập khi hắn thử dò xét vật bên trong.","anchor":"không nghĩ rằng cái khăn tơ nhìn rất bình thường kia lại có điểm làm cho hắn ngoài ý muốn"}]},"nguon":["@c0354"]},{"id":"han-tinh-nhan","name":"Hàn Tinh nhận","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí đoản nhận","phamCap":"đỉnh giai","soHuu":["Tu sĩ họ Phiền"],"trangThai":"đã bán cho Tu sĩ họ Phiền","blurb":"Pháp khí đoản nhận do Lam phu nhân giới thiệu tại Tinh Trần các. Nó được luyện từ huyền tinh và băng ngọc, có công kích mạnh kèm âm hàn.","detail":"Hàn Tinh nhận là pháp khí đỉnh giai được đặt trong nhóm trân phẩm. Lam phu nhân nêu rõ đoản nhận này có uy lực công kích mạnh, kèm âm hàn khiến địch nhân đánh lâu sẽ bất tri bất giác suy giảm thực lực; tu sĩ họ Phiền mua với giá tám trăm linh thạch.","phanLoaiPhu":"đoản nhận","vatLieu":"huyền tinh và băng ngọc","uyLuc":"Công kích mạnh, âm hàn có thể làm suy giảm thực lực địch trong giao chiến kéo dài.","dacDiem":"Mang thuộc tính âm hàn rõ rệt khi được vũ động.","chuHienThoi":"Tu sĩ họ Phiền","capNhatToi":"@c0354","congNang":["Công kích kèm âm hàn @c0354","Khi chiến đấu kéo dài có thể làm thực lực địch nhân giảm dần @c0354"],"chuSoHuu":[{"ten":"Tinh Trần các","tuChuong":"@c0354","denChuong":"@c0354","cachCoDuoc":"Trưng bày trong khay trân phẩm","trangThai":"đã bán"},{"ten":"Tu sĩ họ Phiền","tuChuong":"@c0354","denChuong":"","cachCoDuoc":"Mua với giá tám trăm linh thạch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0354","loai":"đổi chủ","importance":"normal","giaiDoan":"Bán tại Tinh Trần các","text":"Hàn Tinh nhận được Lam phu nhân giới thiệu công năng âm hàn rồi bán cho tu sĩ họ Phiền với giá tám trăm linh thạch.","anchor":"Khi chiến đấu dài hơi thì làm cho thực lực của địch nhân bất tri bất giác giảm đi","phamCap":"đỉnh giai"}]},"nguon":["@c0354"]},{"id":"hai-phuong-thuoc-truc-co-ky","name":"Hai phương thuốc Trúc Cơ kỳ","cn":"","aliases":["Hai phương thuốc"],"category":"khac","categoryLabel":"Đan phương","phamCap":"Trúc Cơ kỳ","soHuu":["Tinh Trần các"],"trangThai":"đang có tại Tinh Trần các","blurb":"Hai đan phương phù hợp với tu sĩ Trúc Cơ kỳ mà Tinh Trần các mới thu được. Giá của chúng rất cao nên Lam phu nhân không thể tự quyết.","detail":"Khi Hàn Lập hỏi mua đan phương cho tu sĩ Trúc Cơ kỳ, Lam phu nhân cho biết Tinh Trần các gần đây thu được hai phương thuốc. Vì giá trị xa xỉ, việc thương lượng phải lên tầng trên chứ không xử lý ngay tại đại sảnh.","phanLoaiPhu":"đan phương","chuHienThoi":"Tinh Trần các","capNhatToi":"@c0354","congNang":["Cung cấp phương thuốc dùng cho tu sĩ Trúc Cơ kỳ @c0354"],"chuSoHuu":[{"ten":"Tinh Trần các","tuChuong":"@c0354","denChuong":"","cachCoDuoc":"Gần đây thu được","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0354","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàng giao dịch tầng cao","text":"Hai phương thuốc Trúc Cơ kỳ được Lam phu nhân nhắc là hàng Tinh Trần các mới thu được nhưng giá rất cao.","anchor":"gần đây bổn các thu được hai phương thuốc cùng một bộ pháp khí đỉnh giai"}]},"nguon":["@c0354"]},{"id":"bo-phap-khi-dinh-giai","name":"Bộ pháp khí đỉnh giai","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí thành bộ","phamCap":"đỉnh giai","soHuu":["Tinh Trần các"],"trangThai":"đang có tại Tinh Trần các","blurb":"Một bộ pháp khí đỉnh giai mà Tinh Trần các mới thu được. Món này thuộc nhóm hàng xa xỉ, cần lên tầng trên để thương lượng.","detail":"Sau khi Hàn Lập hỏi về pháp khí thành bộ với số lượng càng nhiều càng tốt, Lam phu nhân tiết lộ Tinh Trần các gần đây có một bộ pháp khí đỉnh giai. Giá trị của bộ pháp khí cao đến mức nàng không thể làm chủ tại đại sảnh.","phanLoaiPhu":"pháp khí thành bộ","chuHienThoi":"Tinh Trần các","capNhatToi":"@c0354","congNang":["Cung cấp lựa chọn pháp khí thành bộ cho giao dịch cấp cao @c0354"],"chuSoHuu":[{"ten":"Tinh Trần các","tuChuong":"@c0354","denChuong":"","cachCoDuoc":"Gần đây thu được","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0354","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàng giao dịch tầng cao","text":"Bộ pháp khí đỉnh giai được Lam phu nhân nhắc đến như món hàng xa xỉ cần lên tầng trên thương lượng.","anchor":"gần đây bổn các thu được hai phương thuốc cùng một bộ pháp khí đỉnh giai","phamCap":"đỉnh giai"}]},"nguon":["@c0354"]},{"id":"chan-nguyen-dan","name":"Chân Nguyên đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan phương / đan dược","phamCap":"Phù hợp Trúc Cơ kỳ sử dụng @c0355","soHuu":["Hàn Lập"],"trangThai":"được Hàn Lập chọn mua @c0355","blurb":"Chân Nguyên đan là phương thuốc phù hợp với tu sĩ Trúc Cơ kỳ, cần dược tài có chút lâu năm nhưng dễ phối dược. Hàn Lập nhận ra nó thích hợp với tình trạng hiện tại của mình.","detail":"Một trong hai ngọc giản phương thuốc ở tầng sáu ghi Chân Nguyên đan. Khác với Tụ Linh đan, phương thuốc này không phải cổ phương, giá riêng là một ngàn rưỡi linh thạch và được Hàn Lập chọn mua.","phanLoaiPhu":"đan phương","congNang":["Phù hợp cho Trúc Cơ kỳ sử dụng, cần dược tài lâu năm nhưng dễ phối dược @c0355"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0355","denChuong":"","cachCoDuoc":"Chọn mua tại tầng sáu của cửa hàng","trangThai":"đang giao dịch"}],"capNhatToi":"@c0355","tabs":{"tienTrinh":[{"chuong":"@c0355","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Hàn Lập chọn mua","text":"Chân Nguyên đan lộ diện trong ngọc giản phương thuốc ở tầng sáu và được Hàn Lập chọn vì phù hợp với hắn hiện tại.","anchor":"Cái còn lại thì không phải là phương thuốc cổ xưa, mà là một loại có tên “Chân Nguyên đan”"}]},"nguon":["@c0355"]},{"id":"hong-tuyen-don-quang-cham","name":"Hồng tuyến độn quang châm","cn":"","aliases":["Hồng tuyết độn quang châm"],"category":"phap-bao","categoryLabel":"Pháp khí phi châm thành bộ","phamCap":"pháp khí thành bộ @c0355","soHuu":["Hàn Lập"],"trangThai":"được Hàn Lập chọn mua @c0355","blurb":"Hồng tuyến độn quang châm là bộ pháp khí phi châm gồm mười ba cây màu đỏ lửa. Bộ châm không chia tử mẫu, muốn thi triển phải đồng thời điều khiển toàn bộ mười ba cây.","detail":"Bộ phi châm này nhỏ, nhanh và thích hợp đánh lén ám toán, nhưng yêu cầu thần thức mạnh vì phải điều khiển cả bộ cùng lúc. Lam phu nhân từng thích nhưng chỉ khống chế được tám đến chín cây nên bỏ qua, còn Hàn Lập thử dùng được toàn bộ khiến Tú nhi kinh ngạc.","phanLoaiPhu":"pháp khí phi châm thành bộ","hinhDang":"mười ba cây châm tinh xảo hồng quang lấp lóe","uyLuc":"Thích hợp đánh lén ám toán nhờ kích thước nhỏ và tốc độ nhanh.","dacDiem":"Không chia tử mẫu, phải đồng thời xuất ra cả mười ba cây mới sử dụng được.","congNang":["Dùng làm phi châm nhỏ và nhanh, thích hợp đánh lén hoặc ám toán @c0355","Có thể hóa thành hơn mười đạo hồng tuyến bay quanh thân khi được điều khiển đồng thời @c0355"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0355","denChuong":"","cachCoDuoc":"Chọn mua sau khi thử điều khiển đủ mười ba cây","trangThai":"đang giao dịch"}],"capNhatToi":"@c0355","tabs":{"tienTrinh":[{"chuong":"@c0355","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện và được thử dùng","text":"Hồng tuyến độn quang châm xuất hiện trong hộp ngọc lớn, được Tú nhi giải thích hạn chế điều khiển và được Hàn Lập thử dùng trọn bộ.","anchor":"Nếu muốn điều động thì phải đồng loạt đem tất cả mười ba cái xuất ra"}]},"nguon":["@c0355"]},{"id":"ngoc-gian-phuong-thuoc-tu-tinh-tran-cac","name":"Ngọc giản phương thuốc từ Tinh Trần các","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản phương thuốc","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Ngọc giản phương thuốc Hàn Lập nhận được trong giao dịch với Tinh Trần các. Nó được đổi cùng Hồng tuyến độn quang châm bằng Định Nhan đan và linh thạch.","detail":"Vật này nằm trong túi trữ vật của Hàn Lập sau khi giao dịch hoàn tất tại Tinh Trần các, đi kèm bộ Hồng tuyến độn quang châm mà hắn nhắm tới.","dinhDanh":"goc","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0356","denChuong":"","cachCoDuoc":"Đổi từ Tinh Trần các bằng Định Nhan đan và linh thạch","trangThai":"đang giữ"}],"congNang":["Chứa phương thuốc mà Hàn Lập đổi được từ Tinh Trần các @c0356"],"capNhatToi":"@c0356","tabs":{"tienTrinh":[{"chuong":"@c0356","loai":"đổi chủ","importance":"normal","giaiDoan":"Vào tay Hàn Lập","text":"Ngọc giản phương thuốc được Hàn Lập đổi từ Tinh Trần các cùng Hồng tuyến độn quang châm.","anchor":"để đổi lấy phương thuốc và pháp khí"}]},"nguon":["@c0356"]},{"id":"phi-dao-trang-tinh-tu-chan-bach-tri-chu","name":"Phi đao trắng tinh từ chân Bạch Tri chu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Bộ pháp khí gồm năm thanh phi đao trắng tinh luyện từ chân Bạch Tri chu. Đây là thành quả duy nhất đáng kể sau lần luyện khí thất bại nặng ở chỗ Từ điếm chủ.","detail":"Sau hơn nửa tháng luyện khí, phần lớn tài liệu quý của Hàn Lập bị hủy, nhưng năm chân Bạch Tri chu luyện thành một bộ năm thanh phi đao trắng tinh bay quanh thân hắn. Bộ pháp khí này khiến tâm tình Hàn Lập đỡ hơn một chút dù các phần tài liệu khác không thành.","dinhDanh":"goc","phanLoaiPhu":"bộ phi đao","hinhDang":"năm thanh phi đao trắng tinh","vatLieu":"năm chân Bạch Tri chu","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0356","denChuong":"","cachCoDuoc":"Nhờ Từ điếm chủ luyện từ chân Bạch Tri chu","trangThai":"đang giữ"}],"congNang":["Bay quanh thân Hàn Lập như một bộ phi đao pháp khí @c0356"],"dacDiem":"Gồm năm thanh phi đao luyện từ năm chân Bạch Tri chu.","capNhatToi":"@c0356","tabs":{"tienTrinh":[{"chuong":"@c0356","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện thành bộ phi đao","text":"Từ điếm chủ luyện thành năm thanh phi đao trắng tinh từ chân Bạch Tri chu cho Hàn Lập sau khi phần lớn tài liệu khác bị hủy.","anchor":"năm thanh phi đao trắng tinh bay ra, xoay quanh thân Hàn Lập không ngừng"}]},"nguon":["@c0356"]},{"id":"tran-ky-va-tran-ban-cua-tan-nhu-am-te-van-tieu","name":"Trận kỳ và trận bàn của Tân Như Âm - Tề Vân Tiêu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Trận cụ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Bộ trận kỳ và trận bàn do Tân Như Âm cùng Tề Vân Tiêu chung sức luyện chế, được Tân Như Âm trao tặng cho Hàn Lập khi biết mình không còn sống được bao lâu. Đây là tâm huyết của hai người và được kỳ vọng sẽ giúp ích cho Hàn Lập trong quá trình tu luyện.","detail":"Tân Như Âm đem túi trữ vật chứa bộ trận kỳ và trận bàn giao cho Hàn Lập, nói rõ đây là tâm sức mà nàng cùng Tề Vân Tiêu đã bỏ ra để luyện chế. Nàng trao lại bộ trận cụ này trong bối cảnh tự biết bản thân chỉ còn sống được một hai năm, đồng thời gắn liền với lời nhờ Hàn Lập báo thù Phó gia. Theo lời Tân Như Âm, bộ trận cụ có thể giúp ích cho Hàn Lập trong quá trình tu luyện.","dinhDanh":"goc","phanLoaiPhu":"trận kỳ và trận bàn","nguonGoc":"Do Tân Như Âm và Tề Vân Tiêu chung sức luyện chế","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Tân Như Âm","tuChuong":"@c0356","denChuong":"@c0356","cachCoDuoc":"Cùng Tề Vân Tiêu luyện chế","trangThai":"đã trao cho Hàn Lập"},{"ten":"Hàn Lập","tuChuong":"@c0356","denChuong":"","cachCoDuoc":"Được Tân Như Âm tặng","trangThai":"đang giữ"}],"congNang":["Có thể giúp ích cho Hàn Lập trong quá trình tu luyện, theo lời Tân Như Âm @c0356"],"capNhatToi":"@c0356","tabs":{"tienTrinh":[{"chuong":"@c0356","loai":"đổi chủ","importance":"major","giaiDoan":"Tân Như Âm trao tặng","text":"Tân Như Âm trao cho Hàn Lập bộ trận kỳ và trận bàn do nàng cùng Tề Vân Tiêu chung sức luyện chế.","anchor":"mấy cái này là trận kỳ và trận bàn mà ta cùng Tề đại ca chung sức luyện chế"}]},"nguon":["@c0356"]},{"id":"tai-lieu-tu-bo-truyen-tong-tran","name":"Tài liệu tu bổ Truyền Tống trận","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu trận pháp","phamCap":"phổ thông đến chuyên dụng","soHuu":["Hàn Lập"],"trangThai":"đã dùng hết","blurb":"Nhóm vật liệu Hàn Lập mua để sửa Truyền Tống trận cổ sau khi rời Bạch Trì sơn.","detail":"Hàn Lập mua vật liệu theo nhu cầu tu bổ Truyền Tống trận, nhưng vì tay nghề sửa trận còn kém nên làm hỏng quá nhiều. Sau bảy ngày, vật liệu đã cạn khi trận mới sửa được non nửa.","congNang":["Dùng để tu bổ Truyền Tống trận cổ @c0359"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0359","denChuong":"@c0359","cachCoDuoc":"mua ở phường thị Thiên Tinh tông","trangThai":"đã dùng hết"}],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"dùng","importance":"normal","giaiDoan":"Tu bổ trận cổ","text":"Hàn Lập dùng hết số tài liệu mua được khi mới sửa xong non nửa Truyền Tống trận cổ.","anchor":"tài liệu lúc trước mua đã dùng hết không còn một mảnh"}]},"capNhatToi":"@c0359"},{"id":"thiet-mau","name":"Thiết mẫu","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu","phamCap":"phổ thông","soHuu":[],"trangThai":"đang tìm mua","blurb":"Một loại vật liệu Hàn Lập dự định mua thêm để tiếp tục sửa Truyền Tống trận cổ.","detail":"Khi thiếu vật liệu sửa trận, Hàn Lập tính tới tiểu phường thị phía đông mỏ linh thạch để mua những vật liệu như thiết mẫu và tinh ngọc.","congNang":["Vật liệu dùng cho phần tu bổ Truyền Tống trận cổ @c0359"],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"nhắc tới","importance":"normal","giaiDoan":"Tìm vật liệu sửa trận","text":"Hàn Lập dự định tìm mua thiết mẫu tại tiểu phường thị phía đông mỏ linh thạch.","anchor":"mấy loại tài liệu như thiết mẫu hay tinh ngọc"}]},"capNhatToi":"@c0359"},{"id":"tinh-ngoc","name":"Tinh ngọc","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu","phamCap":"phổ thông","soHuu":[],"trangThai":"đang tìm mua","blurb":"Một loại vật liệu Hàn Lập hy vọng mua được để hoàn tất việc tu bổ Truyền Tống trận cổ.","detail":"Tinh ngọc được nhắc cùng thiết mẫu như vật liệu tương đối thường gặp mà Hàn Lập muốn mua tại tiểu phường thị của gia tộc tu tiên phía đông mỏ linh thạch.","congNang":["Vật liệu dùng cho phần tu bổ Truyền Tống trận cổ @c0359"],"nguon":["@c0359"],"tabs":{"tienTrinh":[{"chuong":"@c0359","loai":"nhắc tới","importance":"normal","giaiDoan":"Tìm vật liệu sửa trận","text":"Hàn Lập dự định tìm mua tinh ngọc tại tiểu phường thị phía đông mỏ linh thạch.","anchor":"mấy loại tài liệu như thiết mẫu hay tinh ngọc"}]},"capNhatToi":"@c0359"},{"id":"sao-ngoc-cua-dien-cong-tu","name":"Sáo ngọc của Điền công tử","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Điền công tử"],"trangThai":"đang sử dụng","blurb":"Pháp khí dạng sáo ngọc của Điền công tử, dùng để phát động công kích trong lúc truy sát Hàn Lập.","detail":"Điền công tử lấy sáo ngọc ra, huy động để phát ra âm thanh trong trẻo và hào quang, phối hợp hóa thành khổng tước phấn hồng lao tới Hàn Lập.","hinhDang":"Sáo ngọc","chuHienThoi":"Điền công tử","congNang":["Phát âm thanh và hào quang để hóa thành khổng tước phấn hồng công kích @c0360"],"chuSoHuu":[{"ten":"Điền công tử","tuChuong":"@c0360","denChuong":"","cachCoDuoc":"Đã mang theo khi truy sát Nam Cung Uyển","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0360","loai":"dùng","importance":"normal","giaiDoan":"Truy kích Hàn Lập","text":"Điền công tử dùng sáo ngọc tạo âm thanh và hào quang, hóa thành khổng tước phấn hồng công kích Hàn Lập.","anchor":"trong tay đột nhiên xuất hiện cây sáo ngọc, sau khi huy động thì âm thanh trong trẻo truyền ra"}]},"capNhatToi":"@c0360","nguon":["@c0360"]},{"id":"hoa-phuong-can","name":"Hỏa Phượng Cân","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Đổng Huyên Nhi"],"trangThai":"đang dùng","blurb":"Khăn màu hồng phấn của Đổng Huyên Nhi, dùng để hộ thân trong lúc đối phó Hàn Lập.","detail":"Đổng Huyên Nhi giơ Hỏa Phượng Cân ra rồi dung hợp với Ma Công tạo thành vòng bảo hộ cường đại trước thế công của Hàn Lập.","dinhDanh":"goc","phanLoaiPhu":"khăn màu hồng phấn","hinhDang":"khăn màu hồng phấn","congNang":["Tạo vòng bảo hộ khi phối hợp Ma Công @c0361"],"chuHienThoi":"Đổng Huyên Nhi","chuSoHuu":[{"ten":"Đổng Huyên Nhi","tuChuong":"@c0361","denChuong":"","cachCoDuoc":"đã có và sử dụng hộ thân","trangThai":"đang giữ"}],"capNhatToi":"@c0361","tabs":{"tienTrinh":[{"chuong":"@c0361","loai":"dùng","importance":"normal","giaiDoan":"Dựng hộ tráo","text":"Đổng Huyên Nhi tung Hỏa Phượng Cân rồi phối hợp Ma Công tạo vòng bảo hộ trước thế công của Hàn Lập.","anchor":"tay khẽ giơ lên, một chiếc khăn màu hồng phấn bay ra ngoài"}]},"nguon":["@c0361"]},{"id":"tui-tru-vat-mau-do","name":"Túi trữ vật màu đỏ","cn":"","aliases":[],"category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Nam Cung Bình","Hàn Lập"],"trangThai":"đã trao cho Hàn Lập","blurb":"Túi trữ vật màu đỏ là vật Nam Cung Bình ném cho Hàn Lập để bồi thường. Bên trong chứa hơn mười khối linh thạch bậc trung và nhiều loại tài liệu.","detail":"Nam Cung Bình dùng túi trữ vật màu đỏ làm phần bồi thường theo lựa chọn nhận linh thạch của Hàn Lập. Hàn Lập kiểm tra thấy trong túi có hơn mười khối linh thạch bậc trung cùng bảy tám loại nguyên vật liệu thường dùng.","phanLoaiPhu":"Túi trữ vật","hinhDang":"Túi màu đỏ","chuHienThoi":"Hàn Lập","congNang":["Chứa linh thạch bậc trung và tài liệu bồi thường @c0362"],"chuSoHuu":[{"ten":"Nam Cung Bình","tuChuong":"@c0362","denChuong":"@c0362","cachCoDuoc":"Vốn giữ túi trước khi bồi thường","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0362","denChuong":"","cachCoDuoc":"Nhận từ Nam Cung Bình sau khi chọn phương án lấy linh thạch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0362","loai":"đổi chủ","importance":"normal","giaiDoan":"Bồi thường cho Hàn Lập","text":"Nam Cung Bình ném túi trữ vật màu đỏ cho Hàn Lập, trong đó có linh thạch bậc trung và nhiều loại tài liệu.","anchor":"một túi trữ vật màu đỏ bay về phía hắn"}]},"capNhatToi":"@c0362","dinhDanh":"goc","nguon":["@c0362"]},{"id":"nguyen-ngoc","name":"Nguyên Ngọc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Nam Cung Bình","Hàn Lập"],"trangThai":"Hàn Lập đã nhận vài khối","blurb":"Nguyên Ngọc là vật liệu Hàn Lập xin thêm từ Nam Cung Bình. Vài khối ngọc thạch trắng này giúp hắn đủ vật liệu chữa trị truyền tống trận cổ xưa.","detail":"Sau khi nhận túi trữ vật, Hàn Lập chủ động hỏi Nam Cung Bình còn Nguyên Ngọc hay không. Nam Cung Bình ném cho hắn vài khối ngọc thạch trắng, khiến hắn mừng vì không cần quay về bổn môn để tìm vật liệu sửa truyền tống trận.","phanLoaiPhu":"Vật liệu trận pháp","hinhDang":"Ngọc thạch trắng","chuHienThoi":"Hàn Lập","congNang":["Dùng làm vật liệu chữa trị truyền tống trận cổ xưa @c0362"],"chuSoHuu":[{"ten":"Nam Cung Bình","tuChuong":"@c0362","denChuong":"@c0362","cachCoDuoc":"Có sẵn vài khối trước khi Hàn Lập hỏi xin","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0362","denChuong":"","cachCoDuoc":"Xin thêm từ Nam Cung Bình để sửa truyền tống trận","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0362","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập nhận vật liệu","text":"Hàn Lập hỏi xin Nguyên Ngọc và nhận được vài khối, nhờ đó đủ vật liệu chữa trị truyền tống trận.","anchor":"Không biết tiền bối còn có “Nguyên Ngọc” hay không"}]},"capNhatToi":"@c0362","dinhDanh":"goc","nguon":["@c0362"]},{"id":"linh-thach-bac-trung","name":"Linh thạch bậc trung","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh thạch","phamCap":"Bậc trung","soHuu":["Nam Cung Bình","Hàn Lập"],"trangThai":"Hàn Lập đã nhận hơn mười khối","blurb":"Linh thạch bậc trung là phần bồi thường Nam Cung Bình giao cho Hàn Lập trong túi trữ vật màu đỏ. Số lượng hơn mười khối khiến Hàn Lập kinh hãi dù đã chuẩn bị tâm lý.","detail":"Trong túi trữ vật màu đỏ Nam Cung Bình ném cho Hàn Lập có hơn mười khối linh thạch bậc trung. Đây là phần chính của phương án bồi thường bằng linh thạch mà Hàn Lập đã chọn thay vì theo nàng về Yểm Nguyệt Tông.","phanLoaiPhu":"Linh thạch","chuHienThoi":"Hàn Lập","congNang":["Dùng làm tài nguyên bồi thường cho tổn thất tu vi của Hàn Lập @c0362"],"chuSoHuu":[{"ten":"Nam Cung Bình","tuChuong":"@c0362","denChuong":"@c0362","cachCoDuoc":"Có trong túi trữ vật màu đỏ trước khi bồi thường","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0362","denChuong":"","cachCoDuoc":"Nhận trong túi trữ vật màu đỏ do Nam Cung Bình ném tới","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0362","loai":"đổi chủ","importance":"normal","giaiDoan":"Bồi thường bằng linh thạch","text":"Hơn mười khối linh thạch bậc trung được phát hiện trong túi trữ vật màu đỏ mà Nam Cung Bình đưa cho Hàn Lập.","anchor":"bên trong có hơn mười khối linh thạch bậc trung"}]},"capNhatToi":"@c0362","dinhDanh":"goc","nguon":["@c0362"]},{"id":"o-quang-cua-lao-gia-ly-thi","name":"Ô quang của lão giả Lý thị","cn":"","category":"phap-bao","categoryLabel":"Pháp khí công kích","phamCap":"Không rõ","soHuu":["Lão giả trong Lý thị huynh đệ"],"trangThai":"đang sử dụng @c0363","blurb":"Đạo ô quang màu đen do lão giả Lý thị phóng ra để đánh Hàn Lập. Đòn này bị ngũ sắc quang hoa của Điên đảo ngũ hành trận chặn lại.","detail":"Khi thấy Hàn Lập trong động quật, lão giả Lý thị hé miệng phóng ra một đạo ô quang màu đen bắn thẳng tới Hàn Lập. Công kích bị cấm chế của Điên đảo ngũ hành trận ngăn lại.","dinhDanh":"goc","congNang":["Công kích trực diện mục tiêu @c0363"],"chuSoHuu":[{"ten":"Lão giả trong Lý thị huynh đệ","tuChuong":"@c0363","denChuong":"","cachCoDuoc":"Vật hoặc thuật do lão giả Lý thị thi triển","trangThai":"đang dùng"}],"capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"dùng","importance":"normal","giaiDoan":"Công kích Hàn Lập","text":"Lão giả Lý thị phóng ô quang màu đen đánh Hàn Lập nhưng bị Điên đảo ngũ hành trận chặn lại.","anchor":"liền hé miệng ra, một đạo ô quang màu đen bắn thẳng đến Hàn Lập"}]},"nguon":["@c0363"]},{"id":"quang-ti-mau-den-cua-lao-gia-ly-thi","name":"Quang ti màu đen của lão giả Lý thị","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hoặc thần thông công kích","phamCap":"Không rõ","soHuu":["Lão giả trong Lý thị huynh đệ"],"trangThai":"đang sử dụng @c0363","blurb":"Luồng quang ti màu đen rất lớn do lão giả Lý thị đánh ra sau khi nhận ra Đại Na Di lệnh. Nó tạo áp lực mạnh khiến ngũ sắc quang mạc của Điên đảo ngũ hành trận vỡ ra.","detail":"Sau khi nhận ra Hàn Lập cầm Đại Na Di lệnh, lão giả Lý thị đánh ra quang ti màu đen lớn từ tay. Đòn này tạo áp lực lên Điên đảo ngũ hành trận và góp phần phá vỡ ngũ sắc quang mạc.","dinhDanh":"goc","congNang":["Tạo áp lực công phá quang mạc phòng hộ @c0363"],"uyLuc":"Góp phần làm ngũ sắc quang mạc của Điên đảo ngũ hành trận bạo liệt.","chuSoHuu":[{"ten":"Lão giả trong Lý thị huynh đệ","tuChuong":"@c0363","denChuong":"","cachCoDuoc":"Do lão giả Lý thị thi triển khi phá trận","trangThai":"đang dùng"}],"capNhatToi":"@c0363","tabs":{"tienTrinh":[{"chuong":"@c0363","loai":"dùng","importance":"normal","giaiDoan":"Phá quang mạc","text":"Lão giả Lý thị đánh ra quang ti màu đen lớn, gây áp lực khiến ngũ sắc quang mạc bị phá vỡ.","anchor":"xuất hiện một quang ti màu đen thật lớn từ trong tay mạnh mẽ vọt ra"}]},"nguon":["@c0363"]}]};